#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than k
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long operations = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Don't copy to itself
            }
            // For each other pile a[i], we can add min_val to it
            // as long as a[i] + min_val <= k.
            // The number of times we can add min_val to a[i] is
            // floor((k - a[i]) / min_val)
            if (min_val > 0) { // Should always be true based on constraints (a_i >= 1)
                operations += (k - a[i]) / min_val;
            }
        }
        std::cout << operations << std::endl;
    }
    return 0;
}

