#include <iostream>
#include <vector>
#include <numeric>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::map<int, int> counts;
    for (int i = 0; i < n; ++i) {
        int s_val;
        std::cin >> s_val;
        if (s_val <= 2048) {
            counts[s_val]++;
        }
    }

    int current_sum = 0;
    for (auto const& [val, count] : counts) {
        // Add the total value contributed by 'val' to current_sum
        // This is equivalent to repeatedly merging 'val's until no more pairs exist,
        // and then adding the resulting larger powers of two to the sum.
        // For example, if we have three 4s:
        // 4, 4, 4 -> merge two 4s to get 8. Multiset becomes {8, 4}.
        // The 'value' contributed to the sum is 8 + 4 = 12.
        // Or, more simply, if we have 'count' copies of 'val',
        // they effectively contribute 'count * val' to the total sum of numbers
        // that are less than or equal to 2048.
        // We only care about the sum of numbers that can be combined to form 2048.
        // Numbers larger than 2048 are ignored.
        // So, we sum up all numbers that are <= 2048.
        current_sum += val * count;
    }

    if (current_sum >= 2048) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

