#include <numeric>

void solve() {
    int n;
    std::cin >> n;

    if (n == 1) {
        std::cout << -1 << "\n";
    } else {
        // For n >= 2, we can construct a number.
        // The strategy is to use '2' as the first digit,
        // and '3' for all subsequent digits.
        // This number will be 233...3 (n-1 times '3').
        //
        // Let's check the conditions:
        // 1. s > 0: Yes, it's a positive number.
        // 2. s consists of n digits: Yes, '2' followed by n-1 '3's.
        // 3. No digit in s equals 0: Yes, only '2' and '3' are used.
        // 4. s is not divisible by any of its digits:
        //    The digits are '2' and '3'.
        //    Is s divisible by 2?
        //    The number ends in '3', which is odd. So, s is not divisible by 2.
        //    Is s divisible by 3?
        //    The sum of digits is 2 + (n-1)*3.
        //    If n=2, sum = 2 + 3 = 5. Not divisible by 3.
        //    If n=3, sum = 2 + 3 + 3 = 8. Not divisible by 3.
        //    If n=4, sum = 2 + 3 + 3 + 3 = 11. Not divisible by 3.
        //    In general, 2 + (n-1)*3 = 2 + 3n - 3 = 3n - 1.
        //    Since 3n is divisible by 3, 3n - 1 is never divisible by 3.
        //    Therefore, s is not divisible by 3.
        //
        // This construction satisfies all conditions for n >= 2.

        std::cout << '2';
        for (int i = 0; i < n - 1; ++i) {
            std::cout << '3';
        }
        std::cout << "\n";
    }
}

