#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point (cell 0)

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current 'R' is at index i, which corresponds to cell i+1.
                // The previous 'R' (or start) was at last_r_pos.
                // The gap is (current cell index) - (previous cell index).
                // Cell indices are 0-based for string, 1-based for problem.
                // If last_r_pos is -1 (start), previous cell is 0.
                // If last_r_pos is k (an 'R' at s[k]), previous cell is k+1.
                // So, the distance is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // Or, more simply, the number of 'L's between last_r_pos and i.
                // The distance from the previous 'R' (or 0) to the current 'R' is (i - last_r_pos).
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }

        // After iterating through the string, consider the gap from the last 'R' to n+1.
        // The last 'R' was at index last_r_pos (cell last_r_pos + 1).
        // The target is cell n+1.
        // The distance is (n+1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, n - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

