    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' is limited by three factors:
        // 1. The number of coders: k <= c
        // 2. The number of mathematicians: k <= m
        // 3. The total number of students: 3 * k <= c + m + x
        // From (1) and (2), k <= min(c, m).
        // From (3), k <= (c + m + x) / 3.
        // So, k must be less than or equal to the minimum of these three upper bounds.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    // The total area of the carrot is A_total = (1/2) * base * height = (1/2) * 1 * h = h/2.
    // Each of the n pieces must have an area of A_piece = A_total / n = (h/2) / n = h / (2n).

    // Consider a cut made at a distance x from the apex.
    // This cut forms a smaller isosceles triangle with height x.
    // By similar triangles, if the original base is 1 and height is h,
    // then for a smaller triangle with height x, its base b_x will be x/h.
    // The area of this smaller triangle is A_x = (1/2) * b_x * x = (1/2) * (x/h) * x = x^2 / (2h).

    // We want the area from the apex down to the i-th cut (at x_i) to be i * A_piece.
    // So, x_i^2 / (2h) = i * (h / (2n)).
    // x_i^2 = i * (h^2 / n).
    // x_i = sqrt(i * h^2 / n) = h * sqrt(i / n).

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

