                current_balance++;
            }
        } else { // c == ')'
            if (close_needed > 0 && current_balance > 0) {
                result += ')';
                close_needed--;
                current_balance--;
            }
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a 1-stair nice staircase
        long long sum_of_costs = 0;

        while (true) {
            // Calculate the cost for the next nice staircase
            // A nice staircase with k stairs has cost (2^k - 1) * (2^k) / 2
            // The sequence of costs for nice staircases is:
            // n=1: 1
            // n=3: 6
            // n=7: 28
            // n=15: 120
            // ...
            // The number of stairs is 2^k - 1.
            // The cost is (2^k - 1) * (2^k) / 2.
            // Let m = 2^k. Then cost is (m-1)*m/2.
            // The sequence of m values is 2, 4, 8, 16, ...
            // So, current_cost = (m-1)*m/2.
            // The next m value is 2 * m_prev.
            // The next current_cost will be (2*m_prev - 1) * (2*m_prev) / 2.
            // This is equivalent to:
            // current_cost = (2*current_m - 1) * current_m / 2
            // next_m = 2 * current_m
            // next_cost = (next_m - 1) * next_m / 2

            // The sequence of costs is 1, 6, 28, 120, 496, ...
            // The pattern for the cost of the k-th nice staircase (where k=1 for 1-stair, k=2 for 3-stair, etc.)
            // is (2^k - 1) * 2^(k-1).
            // Let's use the formula for the number of cells for a nice staircase with (2^k - 1) stairs.
            // The number of cells is (2^k - 1) * (2^k) / 2.
            // Let's denote m_k = 2^k. The cost is (m_k - 1) * m_k / 2.
            // For k=1, m_1=2, cost = (2-1)*2/2 = 1.
            // For k=2, m_2=4, cost = (4-1)*4/2 = 6.
            // For k=3, m_3=8, cost = (8-1)*8/2 = 28.
            // The current_cost variable holds the cost for the k-th nice staircase.
            // To get the next cost, we need to find the next m.
            // The current_cost is (m-1)*m/2.
            // The next cost will be (2m-1)*2m/2 = (2m-1)*m.
            // So, if current_cost is (m-1)*m/2, then the next cost is (2m-1)*m.
            // This is not quite right. Let's re-derive.
            // The number of stairs for the k-th nice staircase is N_k = 2^k - 1.
            // The cost for N_k stairs is C_k = N_k * (N_k + 1) / 2 = (2^k - 1) * (2^k) / 2.
            // Let's use a variable `m` which represents `2^k`.
            // Initially, for k=1, m=2. Cost = (2-1)*2/2 = 1.
            // In each iteration, we double `m`.
            // So, `m` starts at 2.
            // `cost_for_this_staircase = (m - 1) * m / 2`.
            // If `sum_of_costs + cost_for_this_staircase <= x`, we take it.
            // Then `m = m * 2`.

            long long cost_for_this_staircase = (current_cost * 2 + 1); // This is the (2m-1) part
            cost_for_this_staircase = cost_for_this_staircase * (current_cost + 1); // This is the m part
            cost_for_this_staircase = cost_for_this_staircase / 2; // This is the /2 part

            // Let's use a simpler approach:
            // The costs are 1, 6, 28, 120, 496, ...
            // Let's generate these costs iteratively.
            // The first cost is 1.
            // The next cost is derived from the previous one.
            // If the previous staircase had `n` stairs, its cost was `n*(n+1)/2`.
            // The next nice staircase has `2n+1` stairs. Its cost is `(2n+1)*(2n+2)/2 = (2n+1)*(n+1)`.
            // This is not correct. The number of stairs is 2^k - 1.
            // Let `num_stairs` be the number of stairs for the current nice staircase.
            // Initially, `num_stairs = 1`.
            // Cost = `num_stairs * (num_stairs + 1) / 2 = 1 * 2 / 2 = 1`.
            // Next `num_stairs = 2 * num_stairs + 1 = 2*1 + 1 = 3`.
            // Cost = `3 * 4 / 2 = 6`.
            // Next `num_stairs = 2 * 3 + 1 = 7`.
            // Cost = `7 * 8 / 2 = 28`.
            // This is the correct sequence of costs for nice staircases.

            long long current_num_stairs = 1;
            long long current_staircase_cost = 1; // Cost for 1-stair staircase

            while (sum_of_costs + current_staircase_cost <= x) {
                sum_of_costs += current_staircase_cost;
                count++;

                // Calculate the next number of stairs and its cost
                current_num_stairs = current_num_stairs * 2 + 1;
                current_staircase_cost = current_num_stairs * (current_num_stairs + 1) / 2;
            }
            // The loop condition `sum_of_costs + current_staircase_cost <= x`
            // already handles the case where `current_staircase_cost` might overflow
            // if `current_num_stairs` becomes very large, because `sum_of_costs`
            // would also be large, making the sum exceed `x` before overflow.
            // `x` is up to 10^18.
            // Max `current_staircase_cost` can be around 10^18.
            // `current_num_stairs` can be up to sqrt(2 * 10^18) approx 1.4 * 10^9.
            // `current_num_stairs * 2 + 1` will fit in long long.
            // `current_num_stairs * (current_num_stairs + 1)` can be up to (1.4*10^9)^2 = 2*10^18, which fits in long long.
            // So, no overflow issues with `long long`.
            break; // The loop should only run once for the calculation.
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
