int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k = n / m; // Number of multiples of m up to n

        // Calculate the sum of last digits for the first 10 multiples of m
        // This sum will repeat for every block of 10 multiples.
        long long sum_first_10_digits = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_first_10_digits += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full blocks of 10 multiples
        long long num_blocks = k / 10;

        // Sum from full blocks
        long long total_sum = num_blocks * sum_first_10_digits;

        // Add the sum for the remaining multiples (less than 10)
        long long remaining_multiples = k % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // current_min_idx and current_max_idx are already initialized to pos[1].
        // The length is 1.
        // min_val is 1, max_val is 1.
        // So m=1 is always beautiful.

        // For m > 1, we consider the number 'm'.
        // We need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm' (if it's not already included).
        // The new segment must contain all numbers from 1 to m.
        // This means the new segment must span from min(pos[1], ..., pos[m])
        // to max(pos[1], ..., pos[m]).

        // Update the overall min and max indices seen so far for numbers 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Check if the current segment [current_min_idx, current_max_idx]
        // is a permutation of 1 to m.
        // This requires two conditions:
        // 1. The segment must contain all numbers from 1 to m. (Guaranteed by how current_min_idx/max_idx are updated)
        // 2. The segment must not contain any numbers greater than m.
        //    This is implicitly checked by verifying the length of the segment.
        //    If the segment [current_min_idx, current_max_idx] has length 'm',
        //    and it contains all numbers from 1 to m, then it must be a permutation of 1 to m.
        //    (Because it has 'm' distinct elements, and they are all <= m, so they must be exactly 1 to m).

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <cmath>
#include <iomanip>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y " << std::fixed << std::setprecision(9) << 0.0 << " " << 0.0 << "\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For a = (d + sqrt(d^2 - 4d)) / 2
            // For b = (d - sqrt(d^2 - 4d)) / 2
            // Or vice versa, since a and b are interchangeable.
            // We need a, b >= 0.
            // Since d >= 4, d^2 - 4d >= 0, so sqrt(d^2 - 4d) is real.
            // Also, d >= 0.
            // For a: (d + sqrt(d^2 - 4d)) / 2 is clearly >= 0.
            // For b: (d - sqrt(d^2 - 4d)) / 2.
            // We need d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Since both sides are non-negative, we can square both:
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // Since d is given as non-negative, and we already established d >= 4 for real solutions,
            // both a and b will be non-negative.

            double discriminant = d * d - 4 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

