bool can_be_box1(long long A, long long B, long long C, long long D) {
    // Total number of toys
    long long total_toys = A + B + C + D;
    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // If only one toy initially
    if (total_toys == 1) {
        return A == 1;
    }

    // Parity of negative toys
    long long neg_count = A + B;

    // Case 1: Final toy is negative
    // This requires an odd number of negative toys to be multiplied.
    // The final product will be negative if the initial number of negative toys (A+B) is odd.
