    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& a, const Element& b) {
        return a.value > b.value;
    });

    std::vector<long long> result_a(m);

    // The optimal strategy is to pair the smallest A_i with the largest B_j,
    // the second smallest A_i with the second largest B_j, and so on.
    // This means a_elements[i] (which is the i-th smallest A value)
    // should be paired with b_elements[i] (which is the i-th largest B value).
    // The value a_elements[i].value should be placed at the original index
    // of b_elements[i].
    for (int i = 0; i < m; ++i) {
        result_a[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
