    std::vector<bool> seen_suffix(n + 1, false);
    current_max = 0;
    current_is_perm = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        if (a[i] < 1 || a[i] > n || seen_suffix[a[i]]) {
            current_is_perm = false;
        }
        seen_suffix[a[i]] = true;
        if (a[i] > current_max) {
            current_max = a[i];
        }
        suffix_max[i] = current_max;
        if (current_is_perm && current_max == len) {
            suffix_is_perm[len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

