        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The reverse of a permutation has the same fingerprint.
        // Since n >= 2, a permutation p is different from its reverse p_rev
        // unless p is a palindrome (e.g., [1,2,1] which is not a permutation,
        // or [1,2,3,2,1] which is not a permutation, or [1,2] and [2,1] are different).
        // For n=2, p=[1,2], p_rev=[2,1]. They are different.
        // For n > 2, p=[p_1, ..., p_n]. If p = p_rev, then p_1=p_n, p_2=p_{n-1}, etc.
        // This is only possible if p_i = p_{n-i+1} for all i.
        // However, a permutation consists of distinct integers from 1 to n.
        // So, if p_1 = p_n, and p_1 is distinct from p_n, this implies p_1 != p_n.
        // The only case where p == p_rev is if n=1, but n >= 2.
        // For n=2, p=[1,2], p_rev=[2,1]. They are different.
        // For n > 2, p_1 must be different from p_n for p to be a permutation (unless n=1).
        // So p is always different from p_rev.

        for (int i = n - 1; i >= 0; --i) {
            std::cout << p[i] << (i == 0 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

