// Function to check if two strings can be made equal
bool can_be_equal(const std::string& s, const std::string& t) {
    // Create frequency arrays for characters 'a' through 'z'
    // A boolean array is sufficient to track presence, as we only care if a character exists.
    bool s_chars[26] = {false};
    bool t_chars[26] = {false};

    // Populate s_chars array
    for (char c : s) {
        s_chars[c - 'a'] = true;
    }

    // Populate t_chars array
    for (char c : t) {
        t_chars[c - 'a'] = true;
    }

    // Check for common characters
    for (int i = 0; i < 26; ++i) {
        if (s_chars[i] && t_chars[i]) {
            // If there is at least one common character,
            // both strings can be transformed into a string consisting solely of that character.
            // For example, if 'a' is in both, s can become "aaa..." and t can become "aaa...".
            // Thus, they can be made equal.
            return true;
        }
    }

    // If no common character is found, they cannot be made equal.
    return false;
}

