    long long b_count = 0;
    long long mod = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            b_count = (b_count + 1) % mod;
        } else { // s[i] == 'a'
            // This 'a' needs to move past all 'b's to its right.
            // Each 'b' to its right will cause 'b_count' operations.
            // After these operations, this 'a' will be to the right of all these 'b's.
            // The number of 'b's to its right will double for the next 'a' to its left.
            total_steps = (total_steps + b_count) % mod;
            b_count = (b_count * 2) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

