// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    if (n == 0) {
        return "0";
    }
    std::string pattern = "";
    while (n > 0) {
        if ((n % 10) % 2 == 0) {
            pattern += '0';
        } else {
            pattern += '1';
        }
        n /= 10;
    }
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // And "Similarly, if the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we need to pad the number's pattern to a fixed length (e.g., 18) with '0's from the left.
    // However, the map key should be the canonical form of the pattern.
    // The matching rule is "i-th from the right digit".
    // So, if a number is 92 (pattern "10") and pattern is "010",
    // 92 -> "10"
    // 010 -> "010"
    // Padded 92 -> "00...010"
    // Padded 010 -> "00...010"
    // The comparison is effectively on the right-aligned patterns.
    // So, we can just store the pattern as is, and when querying, pad the query pattern.
    // Or, we can normalize all patterns to a fixed length (e.g., 18) by padding with '0's from the left.
    // Let's normalize to 18 digits.
    while (pattern.length() < 18) {
        pattern += '0';
    }
    return pattern;
}

