        //   We need to find x such that exp_2(x) < exp_2(q) = 1.
        //   This means exp_2(x) must be 0.
        //   To achieve this, we divide p by 2^(exp_2(p) - exp_2(q) + 1) = 2^(2 - 1 + 1) = 2^2 = 4.
        //   p / 4 = 3. (3 % 6 != 0)
        // For factor 3:
        //   Exponent of 3 in p is 1. Exponent of 3 in q is 1.
        //   We need to find x such that exp_3(x) < exp_3(q) = 1.
        //   This means exp_3(x) must be 0.
        //   To achieve this, we divide p by 3^(exp_3(p) - exp_3(q) + 1) = 3^(1 - 1 + 1) = 3^1 = 3.
        //   p / 3 = 4. (4 % 6 != 0)
        // The maximum of {3, 4} is 4.

        long long ans = 0;
        std::vector<long long> prime_factors_of_q = get_prime_factors(q);

        for (long long factor : prime_factors_of_q) {
            long long current_p = p;
            // Count how many times 'factor' divides q
            long long count_factor_in_q = 0;
            long long temp_q = q;
            while (temp_q > 0 && temp_q % factor == 0) {
                count_factor_in_q++;
                temp_q /= factor;
            }

            // Count how many times 'factor' divides p
            long long count_factor_in_p = 0;
            long long temp_p = p;
            while (temp_p > 0 && temp_p % factor == 0) {
                count_factor_in_p++;
                temp_p /= factor;
            }

            // We need to reduce the exponent of 'factor' in p such that it's less than count_factor_in_q.
            // The smallest exponent we can aim for is count_factor_in_q - 1.
            // To achieve this, we must divide p by factor raised to the power of
            // (count_factor_in_p - (count_factor_in_q - 1)).
            // This is equivalent to dividing p by factor raised to the power of (count_factor_in_p - count_factor_in_q + 1).

            long long divisor_power = count_factor_in_p - count_factor_in_q + 1;
            long long divisor_val = 1;
            for(int i = 0; i < divisor_power; ++i) {
                divisor_val *= factor;
            }

            ans = std::max(ans, p / divisor_val);
        }
        std::cout << ans << "\n";
    }
    return 0;
}

