    std::vector<int> count_x(n + 1, 0);
    std::vector<int> count_y(n + 1, 0);
    std::vector<int> count_z(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        count_x[i + 1] = count_x[i];
        count_y[i + 1] = count_y[i];
        count_z[i + 1] = count_z[i];
        if (s[i] == 'x') {
            count_x[i + 1]++;
        } else if (s[i] == 'y') {
            count_y[i + 1]++;
        } else { // s[i] == 'z'
            count_z[i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int num_x = count_x[r] - count_x[l - 1];
        int num_y = count_y[r] - count_y[l - 1];
        int num_z = count_z[r] - count_z[l - 1];

        // The algorithm terminates if and only if it's possible to reach a state
        // where all 3-character substrings are one of "zyx", "xzy", "yxz".
        // This implies that the counts of 'x', 'y', 'z' must be "balanced"
        // such that their difference is at most 1.
        // If the counts are not balanced, say num_x, num_y, num_z,
        // and max(num_x, num_y, num_z) - min(num_x, num_y, num_z) > 1,
        // then it's always possible to find a 3-character substring that is not
        // a permutation of "xyz" (e.g., "xxx", "xxy", etc.) or
        // a 3-character substring that is a permutation of "xyz" but not one of the forbidden ones.
        // The problem states "rearrange randomly". If there's *any* 3-char substring
        // that is not "zyx", "xzy", "yxz", the algorithm can pick it.
        // If the counts are unbalanced, say (5, 3, 3), then there must be at least one 'x'
        // that is not part of an 'xyz' permutation.
        // For example, if we have "xxxxxyyzz", we can pick "xxx".
        // If the counts are (5, 3, 3), we can't form 3 'xyz' permutations.
        // We can form 3 'xyz' permutations and have 2 'x's left.
        // The only way to guarantee termination is if the counts of 'x', 'y', 'z'
        // are such that they can *only* form permutations of "xyz" and specifically
        // only the "zyx", "xzy", "yxz" ones. This is impossible.
        // The condition for termination is that *all* 3-character substrings
        // are one of "zyx", "xzy", "yxz".
        // This means the counts of 'x', 'y', 'z' must be very close.
        // Specifically, if the counts are c_x, c_y, c_z, then
        // max(c_x, c_y, c_z) - min(c_x, c_y, c_z) <= 1.
        // If this condition holds, it's possible to arrange the characters
        // such that all 3-character substrings are permutations of 'xyz'.
        // For example, if counts are (3,3,3), we can have "xyzxyzxyz".
        // If counts are (4,3,3), we can have "xxyzxyzxyz".
        // In such cases, it's possible to rearrange to "xzyxzyxzy" or "zyxzyxzyx".
        // If the counts are balanced, it's possible to arrange the string
        // such that all 3-character substrings are "zyx", "xzy", or "yxz".
        // For example, if we have "xyzxyzxyz", the substrings are "xyz", "yzx", "zxy".
        // None of these are "zyx", "xzy", "yxz".
        // However, the problem states "rearrange the letters of the found subsequence randomly".
        // If we have "xyz", we can rearrange it to "zyx".
        // The algorithm terminates if there is a non-zero probability that it terminates.
        // This means there must be a state reachable where all 3-char substrings are "zyx", "xzy", "yxz".
        // This is only possible if the counts of 'x', 'y', 'z' are "balanced".
        // If the counts are not balanced, e.g., (5, 3, 3), then no matter how we arrange them,
        // there will always be at least one character that cannot be part of an 'xyz' triplet.
        // For example, if we have 5 'x's, 3 'y's, 3 'z's, we can form 3 'xyz' triplets,
        // leaving 2 'x's. These 2 'x's must be adjacent or separated by other characters.
        // If they are adjacent, "xx", then "xxx" or "xxy" or "xxz" will appear.
        // If they are separated, e.g., "x...x", then some 3-char substring will not be 'xyz' permutation.
        // For example, "x y z x y z x y z x x"
        // The only way to avoid having a substring that is not a permutation of 'xyz'
        // is if the counts of 'x', 'y', 'z' differ by at most 1.
        // If max(num_x, num_y, num_z) - min(num_x, num_y, num_z) > 1,
        // then there will always be a 3-character substring that is not a permutation of 'xyz'.
        // For example, if counts are (5,3,3), then len=11.
        // The average count is 11/3 = 3.66.
        // The counts are 5, 3, 3. Max diff is 5-3=2.
        // In this case, it's impossible to arrange the string such that all 3-char substrings
        // are permutations of 'xyz'. There will always be a substring like "xxx", "xxy", etc.
        // If such a substring exists, say "xxx", the algorithm can pick it and rearrange it to "xxx".
        // This means the algorithm can get stuck in an infinite loop.
        // So, if max(num_x, num_y, num_z) - min(num_x, num_y, num_z) > 1,
        // the algorithm works incorrectly. Output "NO".
        // Otherwise, if max(num_x, num_y, num_z) - min(num_x, num_y, num_z) <= 1,
        // it is possible to arrange the characters such that all 3-char substrings are permutations of 'xyz'.
        // For example, if counts are (4,3,3), we can have "xzyxzyxzyx".
        // The substrings are "xzy", "zyx", "yxz", "xzy", "zyx", "yxz", "xzy", "zyx", "yxz".
        // All of these are among "zyx", "xzy", "yxz".
        // So, if the counts are balanced, it's possible to reach a state where all 3-char substrings
        // are "zyx", "xzy", "yxz". In this state, the algorithm terminates.
        // Since it's possible to rearrange randomly, there's a non-zero probability to reach this state.
        // So, if max(num_x, num_y, num_z) - min(num_x, num_y, num_z) <= 1,
        // the algorithm works correctly. Output "YES".

        int min_count = std::min({num_x, num_y, num_z});
        int max_count = std::max({num_x, num_y, num_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

