bool check(const std::string& s, const std::string& coloring) {
    std::string s1_str;
    std::string s2_str;

    for (size_t i = 0; i < s.length(); ++i) {
        if (coloring[i] == '1') {
            s1_str += s[i];
        } else {
            s2_str += s[i];
        }
    }

    // Check if s1_str is non-decreasing
    for (size_t i = 0; i + 1 < s1_str.length(); ++i) {
        if (s1_str[i] > s1_str[i+1]) {
            return false;
        }
    }

    // Check if s2_str is non-decreasing
    for (size_t i = 0; i + 1 < s2_str.length(); ++i) {
        if (s2_str[i] > s2_str[i+1]) {
            return false;
        }
    }

    // Check if last of s1_str <= first of s2_str
    if (!s1_str.empty() && !s2_str.empty()) {
        if (s1_str.back() > s2_str.front()) {
            return false;
        }
    }

    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    for (int p = 0; p <= 9; ++p) {
        std::string coloring(n, ' ');
        char last_s1_digit = '0' - 1; // Smaller than any digit
        char last_s2_digit = '0' - 1; // Smaller than any digit
        bool possible_for_p = true;

        for (int i = 0; i < n; ++i) {
            char current_digit = s[i];
            if (current_digit < (p + '0')) {
                // Must be color 1
                if (current_digit < last_s1_digit) {
                    possible_for_p = false;
                    break;
                }
                coloring[i] = '1';
                last_s1_digit = current_digit;
            } else if (current_digit > (p + '0')) {
                // Must be color 2
                if (current_digit < last_s2_digit) {
                    possible_for_p = false;
                    break;
                }
                coloring[i] = '2';
                last_s2_digit = current_digit;
            } else { // current_digit == (p + '0')
                // Can be color 1 or color 2
                if (current_digit >= last_s2_digit) {
                    // Try to put it in color 2 if possible
                    coloring[i] = '2';
                    last_s2_digit = current_digit;
                } else if (current_digit >= last_s1_digit) {
                    // Otherwise, try to put it in color 1
                    coloring[i] = '1';
                    last_s1_digit = current_digit;
                } else {
                    // Cannot be placed in either
                    possible_for_p = false;
                    break;
                }
            }
        }

        if (possible_for_p) {
            // Final check: last_s1_digit must be <= first digit of S2
            // This is implicitly handled by the logic:
            // if a digit 'p' is put into S1, it must be >= last_s1_digit.
            // if a digit 'p' is put into S2, it must be >= last_s2_digit.
            // The choice for 'p' digits prioritizes S2 if possible,
            // which means if it goes to S1, it must be because it couldn't go to S2
            // (i.e., current_digit < last_s2_digit).
            // But this is only for digits equal to 'p'.
            // Digits < 'p' go to S1. Digits > 'p' go to S2.
            // The critical condition is that the last digit of S1 must be <= the first digit of S2.
            // Our construction ensures that all digits in S1 are <= p, and all digits in S2 are >= p.
            // So, if S1 is non-decreasing and S2 is non-decreasing, and the split point is 'p',
            // then the combined sequence will be non-decreasing.
            // The only edge case is if S1 contains 'p' and S2 contains 'p'.
            // Our greedy choice for 'p' digits: if current_digit >= last_s2_digit, put in S2.
            // This means all 'p's that come *after* a digit > 'p' will go to S2.
            // All 'p's that come *before* a digit > 'p' might go to S1.
            // This strategy ensures that the "split point" for 'p's is as late as possible.
            // Example: 1 2 3 2 4. Pivot 2.
            // 1 -> S1 (1)
            // 2 -> S1 (1,2) (last_s1=2, last_s2=-1)
            // 3 -> S2 (3) (last_s1=2, last_s2=3)
            // 2 -> S1 (1,2,2) (last_s1=2, last_s2=3) (because 2 < last_s2=3, so must go to S1)
            // 4 -> S2 (3,4) (last_s1=2, last_s2=4)
            // Result: S1 = 122, S2 = 34. Combined: 12234. Valid.

            // The check function is more robust for verifying the final result.
            // However, the construction logic itself should guarantee validity if possible_for_p is true.
            // Let's double check the logic for 'p' digits.
            // If current_digit == p:
            //   If current_digit >= last_s2_digit: put in S2. This is always valid for S2.
            //   Else (current_digit < last_s2_digit): must put in S1.
            //     If current_digit < last_s1_digit: impossible.
            //     Else: put in S1. This is valid for S1.
            // This logic ensures that all digits in S1 are <= p, and all digits in S2 are >= p.
            // And within S1 and S2, they are non-decreasing.
            // The only remaining condition is last(S1) <= first(S2).
            // If S1 is empty, it's fine. If S2 is empty, it's fine.
            // If both are non-empty:
            //   last(S1) will be either a digit < p or a digit == p.
            //   first(S2) will be either a digit > p or a digit == p.
            //   In all cases, last(S1) <= p <= first(S2).
            //   So, last(S1) <= first(S2) is guaranteed by this construction.
            // Therefore, if possible_for_p is true, the coloring is valid.

            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_part
    long long sum_r_part;
    if (b == 1) { // If b=1, then b-1=0, sum_r_part is 0.
                  // Also, mod(x,1) is always 0, so no nice integers.
                  // The problem statement says mod(x,b) != 0.
                  // So if b=1, sum should be 0.
        sum_r_part = 0;
    } else {
        sum_r_part = (b - 1);
        sum_r_part = (sum_r_part * b) / 2;
        sum_r_part %= MOD;
    }

    // Sum of (k * b + 1) for k from 1 to a
    // This is sum_k_part
    // sum_{k=1 to a} (k * b + 1) = sum_{k=1 to a} (k * b) + sum_{k=1 to a} 1
    // = b * sum_{k=1 to a} k + a
    // = b * (a * (a + 1) / 2) + a
    long long sum_k_part;
    long long sum_k_val = (a * (a + 1)) / 2;
    sum_k_val %= MOD;

    sum_k_part = (b % MOD * sum_k_val) % MOD;
    sum_k_part = (sum_k_part + a) % MOD;

    long long total_sum = (sum_r_part * sum_k_part) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int char_code = 0; char_code < 26; ++char_code) {
        if (char_indices[char_code].empty()) {
            continue; // This character does not appear in s
        }

        // These are the possible values of k for which t[0] == char_code
        const std::vector<int>& possible_k_for_t0 = char_indices[char_code];
        int num_possible_k_for_t0 = possible_k_for_t0.size();

        if (num_possible_k_for_t0 <= 1) {
            // If there's only one or zero k values that result in this t[0],
            // Vasya already knows k uniquely (or it's impossible).
            // If it's 1, he wins. If it's 0, this branch is not taken.
            total_win_prob += (double)num_possible_k_for_t0;
            continue;
        }

        double max_win_prob_for_t0 = 0.0;

        // Vasya chooses p to maximize win probability for this t[0]
        // p ranges from 1 to L-1
        for (int p = 1; p < L; ++p) {
            int current_p_wins = 0;

            // Group (t[0], t[p]) pairs
            // map: char_at_p -> count_of_k_producing_this_pair
            std::map<char, int> counts_for_p;

            for (int k_val : possible_k_for_t0) {
                char char_at_p = s[(k_val + p) % L];
                counts_for_p[char_at_p]++;
            }

            for (const auto& pair : counts_for_p) {
                if (pair.second == 1) {
                    current_p_wins++;
                }
            }
            max_win_prob_for_t0 = std::max(max_win_prob_for_t0, (double)current_p_wins);
        }
        total_win_prob += max_win_prob_for_t0;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <set>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    for (char c = 'a'; c <= 'z'; ++c) {
        adj[c] = {};
    }

    bool possible = true;
    for (size_t i = 0; i < s.length() - 1; ++i) {
        char c1 = s[i];
        char c2 = s[i+1];

        adj[c1].insert(c2);
        adj[c2].insert(c1);

        if (adj[c1].size() > 2 || adj[c2].size() > 2) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::string layout = "";
    std::set<char> visited;

    // Find a starting point for a path (a character with only one neighbor)
    char start_char = '\0';
    for (char c = 'a'; c <= 'z'; ++c) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    // If no char has 1 neighbor, it means all connected components are cycles or isolated nodes.
    // For a valid layout, we need a path. If all chars in password form a cycle, it's impossible.
    // If there are isolated nodes or multiple components, we can still form a path.
    // The only case where start_char is not found is if all involved characters have 2 neighbors (a cycle)
    // or all involved characters are isolated (not possible with s.length() > 0).
    // Or if s.length() == 1, then start_char will be '\0'.
    if (start_char == '\0' && s.length() > 0) {
        // This means all characters involved in the password have exactly 2 neighbors.
        // This forms a cycle. A cycle cannot be laid out on a linear keyboard.
        // Example: abca -> a-b-c-a. 'a' needs to be adjacent to 'b' and 'c'.
        // If 'a' is at one end, it only has one neighbor. If 'a' is in middle, it has two.
        // But if it's a cycle, it means all characters have two neighbors.
        // A linear layout must have two endpoints with one neighbor each.
        // So, if all characters in the password have 2 neighbors, it's impossible.
        // We need to check if there's at least one character from 's' that has 2 neighbors.
        bool has_two_neighbor_char_from_s = false;
        for(char sc : s) {
            if (adj[sc].size() == 2) {
                has_two_neighbor_char_from_s = true;
                break;
            }
        }
        if (has_two_neighbor_char_from_s) { // If there's a cycle involving password chars
            std::cout << "NO\n";
            return;
        }
        // If s.length() == 1, start_char will be '\0'. We can pick s[0] as start.
        // If s.length() > 1 and no char has 1 neighbor, it means all chars in s have 2 neighbors.
        // This implies a cycle.
    }

    if (s.length() == 0) { // Empty password, any layout is fine
        std::cout << "YES\n";
        std::cout << "abcdefghijklmnopqrstuvwxyz\n";
        return;
    }

    if (start_char == '\0') { // This happens if s.length() == 1, or if all chars in s form a cycle.
        // If s.length() == 1, s[0] is the only char. It has 0 neighbors.
        // We can start with s[0].
        start_char = s[0];
    }

    // Build the layout starting from `start_char`
    char current = start_char;
    while (current != '\0' && !visited.count(current)) {
        layout += current;
        visited.insert(current);

        char next_char = '\0';
        for (char neighbor : adj[current]) {
            if (!visited.count(neighbor)) {
                next_char = neighbor;
                break;
            }
        }
        current = next_char;
    }

    // Add any remaining unvisited characters (those not part of the password path)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (!visited.count(c)) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

