#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit (0-9)
    // For each bit position `b`:
    // `bit_0_val[b]` stores the result if the input bit `b` is 0.
    // `bit_1_val[b]` stores the result if the input bit `b` is 1.
    // Initially, if input bit is 0, output is 0. If input bit is 1, output is 1.
    std::vector<int> bit_0_val(10); // Result for input bit 0
    std::vector<int> bit_1_val(10); // Result for input bit 1

    for (int b = 0; b < 10; ++b) {
        bit_0_val[b] = 0;
        bit_1_val[b] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int b = 0; b < 10; ++b) {
            int x_bit = (x >> b) & 1;
            if (op_char == '&') {
                bit_0_val[b] &= x_bit;
                bit_1_val[b] &= x_bit;
            } else if (op_char == '|') {
                bit_0_val[b] |= x_bit;
                bit_1_val[b] |= x_bit;
            } else if (op_char == '^') {
                bit_0_val[b] ^= x_bit;
                bit_1_val[b] ^= x_bit;
            }
        }
    }

    // Now, for each bit `b`, we know how it transforms:
    // (0 -> bit_0_val[b]) and (1 -> bit_1_val[b])
    // We need to find a minimal set of operations to achieve this.
    // The possible transformations for a single bit are:
    // 1. 0 -> 0, 1 -> 1 (identity)
    // 2. 0 -> 1, 1 -> 0 (NOT)
    // 3. 0 -> 0, 1 -> 0 (always 0)
    // 4. 0 -> 1, 1 -> 1 (always 1)

    // Let's find the constants for the combined operations.
    // We want to find A, B, C such that for any input `val`:
    // (((val & A) | B) ^ C) == final_result(val)

    // Consider the input `0`. The final result for `0` is `(((0 & A) | B) ^ C) = (0 | B) ^ C = B ^ C`.
    // Consider the input `1023` (all 1s). The final result for `1023` is `(((1023 & A) | B) ^ C) = (A | B) ^ C`.

    // Let's determine the constants for the three operations.
    // We can determine the constants bit by bit.
    int final_and_const = 1023; // All 1s initially for AND
    int final_or_const = 0;     // All 0s initially for OR
    int final_xor_const = 0;    // All 0s initially for XOR

    for (int b = 0; b < 10; ++b) {
        // Case 1: 0 -> 0, 1 -> 1 (identity)
        // This means the bit is unchanged.
        // To achieve this with `&A | B ^ C`:
        // If input bit is 0: (0 & A_b | B_b) ^ C_b = B_b ^ C_b = 0
        // If input bit is 1: (1 & A_b | B_b) ^ C_b = (A_b | B_b) ^ C_b = 1
        // From B_b ^ C_b = 0, we get B_b = C_b.
        // Then (A_b | B_b) ^ B_b = 1.
        // If B_b = 0, then (A_b | 0) ^ 0 = A_b = 1. So A_b=1, B_b=0, C_b=0.
        // If B_b = 1, then (A_b | 1) ^ 1 = 1 ^ 1 = 0. This doesn't work.
        // So for identity: A_b=1, B_b=0, C_b=0.
        if (bit_0_val[b] == 0 && bit_1_val[b] == 1) {
            // This bit should be identity.
            // final_and_const_b = 1
            // final_or_const_b = 0
            // final_xor_const_b = 0
            // No change to final_and_const, final_or_const, final_xor_const for this bit.
        }
        // Case 2: 0 -> 1, 1 -> 0 (NOT)
        // This means the bit is flipped.
        // If input bit is 0: B_b ^ C_b = 1
        // If input bit is 1: (A_b | B_b) ^ C_b = 0
        // From B_b ^ C_b = 1, we get B_b != C_b.
        // If B_b = 0, C_b = 1. Then (A_b | 0) ^ 1 = A_b ^ 1 = 0 => A_b = 1.
        // So for NOT: A_b=1, B_b=0, C_b=1.
        // If B_b = 1, C_b = 0. Then (A_b | 1) ^ 0 = 1 ^ 0 = 1. This doesn't work.
        // So for NOT: A_b=1, B_b=0, C_b=1.
        else if (bit_0_val[b] == 1 && bit_1_val[b] == 0) {
            // This bit should be NOT.
            // final_and_const_b = 1
            // final_or_const_b = 0
            // final_xor_const_b = 1
            final_xor_const |= (1 << b);
        }
        // Case 3: 0 -> 0, 1 -> 0 (always 0)
        // If input bit is 0: B_b ^ C_b = 0
        // If input bit is 1: (A_b | B_b) ^ C_b = 0
        // From B_b ^ C_b = 0, we get B_b = C_b.
        // Then (A_b | B_b) ^ B_b = 0.
        // If B_b = 0, then (A_b | 0) ^ 0 = A_b = 0. So A_b=0, B_b=0, C_b=0.
        // If B_b = 1, then (A_b | 1) ^ 1 = 1 ^ 1 = 0. This works for any A_b.
        // To minimize operations, we prefer A_b=0, B_b=0, C_b=0.
        // So for always 0: A_b=0, B_b=0, C_b=0.
        else if (bit_0_val[b] == 0 && bit_1_val[b] == 0) {
            // This bit should be always 0.
            // final_and_const_b = 0
            // final_or_const_b = 0
            // final_xor_const_b = 0
            final_and_const &= ~(1 << b); // Set A_b to 0
        }
        // Case 4: 0 -> 1, 1 -> 1 (always 1)
        // If input bit is 0: B_b ^ C_b = 1
        // If input bit is 1: (A_b | B_b) ^ C_b = 1
        // From B_b ^ C_b = 1, we get B_b != C_b.
        // If B_b = 0, C_b = 1. Then (A_b | 0) ^ 1 = A_b ^ 1 = 1 => A_b = 0.
        // So for always 1: A_b=0, B_b=0, C_b=1.
        // If B_b = 1, C_b = 0. Then (A_b | 1) ^ 0 = 1 ^ 0 = 1. This works for any A_b.
        // To minimize operations, we prefer A_b=0, B_b=1, C_b=0.
        // So for always 1: A_b=0, B_b=1, C_b=0.
        else if (bit_0_val[b] == 1 && bit_1_val[b] == 1) {
            // This bit should be always 1.
            // final_and_const_b = 0
            // final_or_const_b = 1
            // final_xor_const_b = 0
            final_and_const &= ~(1 << b); // Set A_b to 0
            final_or_const |= (1 << b);   // Set B_b to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If any bit of A is 0
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If any bit of B is 1
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If any bit of C is 1
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate the maximum possible length of the strictly increasing prefix
    // if we can decrease elements.
    // For a_i to be part of an increasing sequence starting from 0,
    // it must be possible to make a_i >= i.
    // Since we can decrease a_i, we can make it exactly i if a_i >= i.
    // If a_i < i, we cannot make it i.
    // So, the longest possible prefix is up to the first index i where a_i < i.
    int prefix_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            prefix_len = i + 1;
        } else {
            break;
        }
    }

    // Calculate the maximum possible length of the strictly decreasing suffix
    // if we can decrease elements.
    // For a_i to be part of a decreasing sequence ending at 0,
    // it must be possible to make a_i >= (n - 1 - i).
    // Since we can decrease a_i, we can make it exactly (n - 1 - i) if a_i >= (n - 1 - i).
    // If a_i < (n - 1 - i), we cannot make it (n - 1 - i).
    // So, the longest possible suffix is up to the first index i (from right)
    // where a_i < (n - 1 - i).
    int suffix_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            suffix_len = (n - 1 - i) + 1;
        } else {
            break;
        }
    }

    // A sharpened array requires a peak k.
    // The elements a_1, ..., a_k must be strictly increasing.
    // The elements a_k, ..., a_n must be strictly decreasing.
    // This means the peak k must be covered by both the potential increasing prefix
    // and the potential decreasing suffix.
    // The length of the increasing prefix is `prefix_len`.
    // The length of the decreasing suffix is `suffix_len`.
    // If `prefix_len + suffix_len > n`, it means there is at least one index
    // that can serve as a peak `k`.
    // For example, if n=3, prefix_len=2, suffix_len=2.
    // Prefix covers indices 0, 1. Suffix covers indices 1, 2.
    // Index 1 is covered by both, so it can be a peak.
    // If prefix_len = 1, suffix_len = 1, n = 3.
    // Prefix covers index 0. Suffix covers index 2. No common peak.
    // The condition `prefix_len + suffix_len > n` ensures there's an overlap.
    // An overlap means there's at least one index `k` such that `0 <= k < prefix_len`
    // AND `n - suffix_len <= k < n`.
    // This is equivalent to `k` being in `[0, prefix_len-1]` and `k` being in `[n-suffix_len, n-1]`.
    // For such a `k` to exist, we need `prefix_len-1 >= n-suffix_len`.
    // Which simplifies to `prefix_len + suffix_len - 1 >= n`.
    // Or `prefix_len + suffix_len > n`.

    if (prefix_len + suffix_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

