    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::min, std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        // Ensure n >= m for simpler logic, as the problem is symmetric
        if (n < m) {
            std::swap(n, m);
        }

        // Calculate the minimum number of moves to reach (n, m)
        // This is max(n, m) if only diagonal and axial moves are used efficiently.
        // However, we need to reach it in exactly k moves.

        // Parity check:
        // Each move changes the parity of x by 0 or 1.
        // Each move changes the parity of y by 0 or 1.
        // The parity of (x+y) changes by 0 or 2 for a diagonal move.
        // The parity of (x+y) changes by 1 for an axial move.
        // So, (x_final + y_final) % 2 must be equal to (k % 2) if we only consider
        // the parity of the sum of coordinates.
        // (0+0) % 2 = 0. So (n+m) % 2 must be equal to (k % 2).
        // If (n+m) % 2 != k % 2, it's impossible.
        // This is equivalent to checking if (n % 2) == (k % 2) and (m % 2) == (k % 2)
        // for the case where n and m are both even or both odd.
        // More simply, (n % 2) == (k % 2) is the condition for reaching (n,m) in k moves
        // if we consider only one coordinate at a time.
        // For 2D, the parity of (n+m) must match the parity of k.
        // (n+m) % 2 == k % 2
        // This is because each move changes the parity of x by 0 or 1, and y by 0 or 1.
        // A diagonal move changes both x and y parity, so (x_new % 2) == (x_old % 2) and (y_new % 2) == (y_old % 2).
        // An axial move changes one parity, so (x_new % 2) != (x_old % 2) and (y_new % 2) == (y_old % 2) (or vice versa).
        // This means that after an even number of moves, the parity of x and y must be the same as initial.
        // After an odd number of moves, the parity of x and y must be different from initial.
        // So, (n % 2) == (k % 2) and (m % 2) == (k % 2) is the condition.
        // This is equivalent to (n % 2 == m % 2) and (n % 2 == k % 2).
        // Or, (n % 2 != m % 2) and (n % 2 != k % 2) and (m % 2 != k % 2).
        // This simplifies to: (n % 2 == k % 2) AND (m % 2 == k % 2).
        // If n and m have different parities, and k has the same parity as one of them, it's impossible.
        // Example: (2,1) in 3 moves. n=2, m=1, k=3. n%2=0, m%2=1, k%2=1.
        // (n%2 != k%2) is false. (m%2 != k%2) is true. So it's impossible.
        // Example: (2,2) in 3 moves. n=2, m=2, k=3. n%2=0, m%2=0, k%2=1.
        // (n%2 != k%2) is true. So it's impossible.
        // The condition is (n % 2 == k % 2) && (m % 2 == k % 2).
        // This is equivalent to (n % 2 == m % 2) && (n % 2 == k % 2).
        // Or, (n % 2 != m % 2) && (n % 2 != k % 2) && (m % 2 != k % 2)
        // This is equivalent to (n % 2 == k % 2) && (m % 2 == k % 2).
        // Let's re-evaluate the parity condition.
        // Each move changes the parity of x by 0 or 1.
        // Each move changes the parity of y by 0 or 1.
        // After k moves, the parity of x_final must be (x_initial + sum_of_dx_parities) % 2.
        // x_final % 2 = (sum_of_dx_parities) % 2.
        // y_final % 2 = (sum_of_dy_parities) % 2.
        // The total number of moves is k.
        // Let d_x be the number of moves that change x's parity.
        // Let d_y be the number of moves that change y's parity.
        // d_x + d_y is not necessarily k.
        // A diagonal move changes both x and y parity.
        // An axial move changes one parity.
        // Let D be diagonal moves, A_x be axial moves along x, A_y be axial moves along y.
        // D + A_x + A_y = k.
        // n % 2 = (D + A_x) % 2
        // m % 2 = (D + A_y) % 2
        // This implies (n % 2) == (m % 2) if and only if (A_x % 2) == (A_y % 2).
        // Also, (n % 2) == (k % 2) if and only if (D + A_x) % 2 == (D + A_x + A_y) % 2, which means A_y % 2 == 0.
        // This is not correct.
        // The correct parity condition is:
        // The parity of the final x-coordinate must be the same as the parity of the number of moves that change the x-coordinate.
        // The parity of the final y-coordinate must be the same as the parity of the number of moves that change the y-coordinate.
        // Let $k_x$ be the number of moves that change the x-coordinate (i.e., $dx \ne 0$).
        // Let $k_y$ be the number of moves that change the y-coordinate (i.e., $dy \ne 0$).
        // $n \equiv k_x \pmod 2$ and $m \equiv k_y \pmod 2$.
        // Also, $k_x \le k$ and $k_y \le k$.
        // A diagonal move contributes to both $k_x$ and $k_y$.
        // An axial move along x contributes to $k_x$.
        // An axial move along y contributes to $k_y$.
        // The total number of moves is $k$.
        // The minimum number of moves to reach (n,m) is $n$ (if $n=m$) or $n$ (if $n>m$).
        // If $k < n$, it's impossible.
        if (k < n) {
            std::cout << -1 << "\n";
            continue;
        }

        // If n and m have different parities, and k has the same parity as n,
        // then (n-m) is odd.
        // (k-n) is even.
        // (k-m) is odd.
        // This means we need to make an odd number of moves that change y-parity
        // relative to x-parity.
        // If n and m have different parities, then (n-m) is odd.
        // If k has the same parity as n, then (k-n) is even.
        // This means (k-m) is odd.
        // The number of moves that change x-parity is $k_x$.
        // The number of moves that change y-parity is $k_y$.
        // We need $n \equiv k_x \pmod 2$ and $m \equiv k_y \pmod 2$.
        // The total number of moves is $k$.
        // Each move changes the parity of x or y or both.
        // If $n \pmod 2 \ne m \pmod 2$:
        //   This means one coordinate is even and the other is odd.
        //   To reach this state, we must have an odd number of moves that change x-parity
        //   and an even number of moves that change y-parity (or vice versa).
        //   This implies that the number of diagonal moves plus axial x moves must have
        //   different parity than diagonal moves plus axial y moves.
        //   $(D+A_x) \pmod 2 \ne (D+A_y) \pmod 2 \implies A_x \pmod 2 \ne A_y \pmod 2$.
        //   Also, $k = D + A_x + A_y$.
        //   If $A_x$ and $A_y$ have different parities, then $A_x+A_y$ is odd.
        //   So $k \pmod 2 = (D + \text{odd}) \pmod 2$.
        //   If $n \pmod 2 \ne m \pmod 2$, then $k$ must be odd.
        //   If $k$ is even, it's impossible.
        //   Example: (2,1) in 3 moves. n=2, m=1, k=3. n%2=0, m%2=1, k%2=1.
        //   n%2 != m%2. k%2 is 1 (odd). This is possible.
        //   Example: (2,1) in 2 moves. n=2, m=1, k=2. n%2=0, m%2=1, k%2=0.
        //   n%2 != m%2. k%2 is 0 (even). This is impossible.
        //   So if (n % 2 != m % 2) and (k % 2 == 0), then impossible.
        if ((n % 2 != m % 2) && (k % 2 == 0)) {
            std::cout << -1 << "\n";
            continue;
        }

        // If n and m have the same parity, and k has a different parity:
        //   This means $n \pmod 2 = m \pmod 2$.
        //   So $A_x \pmod 2 = A_y \pmod 2$.
        //   If $A_x$ and $A_y$ are both even, then $A_x+A_y$ is even.
        //   If $A_x$ and $A_y$ are both odd, then $A_x+A_y$ is even.
        //   So $A_x+A_y$ is always even.
        //   Then $k \pmod 2 = (D + \text{even}) \pmod 2 = D \pmod 2$.
        //   If $n \pmod 2 = m \pmod 2$, and $k \pmod 2 \ne n \pmod 2$:
        //   This means $D \pmod 2 \ne n \pmod 2$.
        //   But $n \pmod 2 = (D+A_x) \pmod 2$.
        //   If $A_x$ is even, then $n \pmod 2 = D \pmod 2$.
        //   If $A_x$ is odd, then $n \pmod 2 \ne D \pmod 2$.
        //   This is getting complicated. Let's use a simpler parity argument.
        //   Each move changes the sum of coordinates (x+y) by an even amount if it's diagonal (e.g., (0,0)->(1,1), sum changes by 2)
        //   or by an odd amount if it's axial (e.g., (0,0)->(1,0), sum changes by 1).
        //   Let D be diagonal moves, A be axial moves.
        //   Total moves k = D + A.
        //   The final sum of coordinates (n+m) must have the same parity as A.
        //   So (n+m) % 2 == A % 2.
        //   Also, A = k - D.
        //   So (n+m) % 2 == (k - D) % 2.
        //   This means (n+m) % 2 == (k % 2 - D % 2 + 2) % 2.
        //   If (n+m) % 2 != k % 2, then D must be odd.
        //   If (n+m) % 2 == k % 2, then D must be even.
        //   This condition is always satisfiable if k >= n.
        //   The problem is that we can "waste" moves by going back and forth.
        //   For example, (0,0) -> (1,0) -> (0,0) -> (1,0) ...
        //   Each pair of such moves (e.g., (x,y) -> (x+1,y) -> (x,y)) uses 2 moves and results in no net change in position.
        //   These "wasted" moves can be used to adjust the parity of k.
        //   If we are at (n,m) and have $k'$ moves remaining, and $k' > 0$, we can always make $k'$ even by doing (n,m)->(n+1,m)->(n,m) if $k'$ is odd.
        //   Or we can make $k'$ odd by doing (n,m)->(n+1,m) if $k'$ is even and $k'>0$.
        //   The only constraint is that we must reach (n,m) in exactly k moves.
        //   The minimum number of moves to reach (n,m) is max(n,m).
        //   Let $k_{min} = \max(n,m)$.
        //   If $k < k_{min}$, it's impossible. (Already checked $k < n$).
        //   If $k \ge k_{min}$:
        //     We can reach (n,m) in $k_{min}$ moves.
        //     The remaining $k - k_{min}$ moves must be "wasted".
        //     Each "wasted" move must be paired with another move that cancels its effect on the final position.
        //     For example, (x,y) -> (x+1,y) -> (x,y) uses 2 moves.
        //     (x,y) -> (x+1,y+1) -> (x,y) uses 2 moves.
        //     So, we can always use up an even number of extra moves.
        //     If $k - k_{min}$ is even, we can reach (n,m) in $k$ moves.
        //     If $k - k_{min}$ is odd:
        //       We need to make one extra move that changes the parity of the final coordinates.
        //       For example, if we are at (n,m) and have 1 move left, we can't stay at (n,m).
