#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_balance = 0; // count(1) - count(2)
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // Map to store the minimum number of jars removed from the left
    // to achieve a certain balance.
    // key: balance, value: number of jars removed from left
    std::map<int, int> left_balances;
    left_balances[0] = 0; // 0 jars removed from left, balance is 0

    int current_left_balance = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            current_left_balance++;
        } else {
            current_left_balance--;
        }
        // Store the minimum number of jars removed (i+1) to get current_left_balance
        // If current_left_balance is already in map, it means we found it with fewer jars,
        // so we don't update. If it's not, or if (i+1) is smaller, we update.
        // Since we iterate from left to right, (i+1) is always increasing,
        // so the first time we see a balance, it's with the minimum jars.
        if (left_balances.find(current_left_balance) == left_balances.end()) {
            left_balances[current_left_balance] = i + 1;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removals

    // Case 1: No jars removed from the right side.
    // We need the remaining balance to be 0.
    // The remaining balance is initial_balance - current_left_balance.
    // So, we need initial_balance - current_left_balance = 0,
    // which means current_left_balance = initial_balance.
    // If initial_balance is achievable by removing some jars from left,
    // then the number of removed jars is left_balances[initial_balance].
    if (left_balances.count(initial_balance)) {
        min_removed = std::min(min_removed, left_balances[initial_balance]);
    }

    // Case 2: Remove jars from the right side.
    int current_right_balance = 0; // balance of jars removed from right
    for (int i = 0; i < n; ++i) {
        int jar_idx = 2 * n - 1 - i; // Jars from right: 2n-1, 2n-2, ..., n
        if (a[jar_idx] == 1) {
            current_right_balance++;
        } else {
            current_right_balance--;
        }

        // After removing (i+1) jars from the right,
        // the total balance of remaining jars is initial_balance - current_right_balance.
        // We need this remaining balance to be 0.
        // So, initial_balance - current_right_balance - current_left_balance_removed = 0
        // current_left_balance_removed = initial_balance - current_right_balance
        int target_left_balance = initial_balance - current_right_balance;

        if (left_balances.count(target_left_balance)) {
            int removed_from_left = left_balances[target_left_balance];
            int removed_from_right = i + 1;
            min_removed = std::min(min_removed, removed_from_left + removed_from_right);
        }
    }

    std::cout << min_removed << std::endl;
}

