#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> p(n);

    // Case 1: All elements in one subsequence (e.g., all 1s)
    // min_f = a_0 + a_1
    // max_f = a_{n-2} + a_{n-1}
    // goodness = (a_{n-2} + a_{n-1}) - (a_0 + a_1)
    long long min_goodness = (elements[n - 2].value + elements[n - 1].value) - (elements[0].value + elements[1].value);
    std::vector<int> best_p(n, 1);

    // Case 2: At least one element in each subsequence
    // The minimum possible f value is a_0 + a_1.
    // The maximum possible f value is a_{n-2} + a_{n-1} + h.
    // The minimum f value can also be a_0 + a_1 + h if a_0 and a_1 are in different groups.
    // The maximum f value can also be a_{n-2} + a_{n-1} if a_{n-2} and a_{n-1} are in the same group.

    // Consider the partition where elements[0] is in S1 and all others are in S2.
    // Or elements[0] and elements[1] are in S1, and others in S2.
    // Or elements[0] is in S1, elements[1] is in S2, and others are in S2.

    // Let's analyze the critical values:
    // min_same = a_0 + a_1
    // max_same = a_{n-2} + a_{n-1}
    // min_diff = a_0 + a_1 + h
    // max_diff = a_{n-1} + a_{n-2} + h (if n >= 2)

    // The overall minimum f value will be min(a_i + a_j) or min(a_i + a_j + h).
    // The overall maximum f value will be max(a_i + a_j) or max(a_i + a_j + h).

    // If we put elements[0] in S1 and all other elements in S2:
    // min_f = min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // max_f = max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h)
    // This is not quite right. The min/max values depend on which pairs exist.

    // Let's consider the two main strategies:
    // Strategy A: Try to make all f values close to each other.
    // This usually means putting a_0 and a_1 in different groups, or a_{n-1} and a_{n-2} in different groups.
    // Or, if h is very large, put all elements in one group.

    // The minimum possible sum of two elements is elements[0].value + elements[1].value.
    // The maximum possible sum of two elements is elements[n-2].value + elements[n-1].value.

    // Consider a partition where elements[0] is in S1, and elements[1], ..., elements[n-1] are in S2.
    // Pairs within S1: None (if n=1, but n>=2)
    // Pairs within S2: (elements[1], elements[2]), ..., (elements[n-2], elements[n-1])
    // Pairs across S1 and S2: (elements[0], elements[1]), ..., (elements[0], elements[n-1])

    // For this partition:
    // min_f_same = elements[1].value + elements[2].value (if n >= 3)
    // max_f_same = elements[n-2].value + elements[n-1].value (if n >= 3)
    // min_f_diff = elements[0].value + elements[1].value + h
    // max_f_diff = elements[0].value + elements[n-1].value + h

    // If n=2: elements[0] in S1, elements[1] in S2.
    // Only one pair: (elements[0], elements[1]). It's in different groups.
    // f = elements[0].value + elements[1].value + h. Goodness = 0.
    // This is covered by the general logic below.

    // If n >= 3:
    // min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    // max_f = std::max(elements[n-2].value + elements[n-1].value, elements[0].value + elements[n-1].value + h);
    // current_goodness = max_f - min_f;

    // This is the key insight:
    // The minimum possible sum of two elements is `elements[0].value + elements[1].value`.
    // The maximum possible sum of two elements is `elements[n-2].value + elements[n-1].value`.

    // If we put `elements[0]` in group 1 and all other `n-1` elements in group 2:
    // The values `a_i + a_j` are:
    //   - `elements[0].value + elements[k].value + h` for `k = 1, ..., n-1`
    //   - `elements[k].value + elements[l].value` for `k, l = 1, ..., n-1` (k != l)
    //
    // The minimum value of `f` will be `min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)`.
    // The maximum value of `f` will be `max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)`.
    //
    // Let `min_val_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);`
    // Let `max_val_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);`
    //
    // The goodness for this partition is `max_val_f - min_val_f`.
    // This partition is: `elements[0]` gets 1, `elements[1...n-1]` get 2.

    if (n >= 3) { // This partition strategy only makes sense if there are at least 3 elements
                  // to have both same-group and different-group pairs.
        long long current_min_f = std::min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value);
        long long current_max_f = std::max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value);
        long long current_goodness = current_max_f - current_min_f;

        if (current_goodness < min_goodness) {
            min_goodness = current_goodness;
            for (int i = 0; i < n; ++i) {
                if (i == 0) {
                    best_p[elements[i].original_index] = 1;
                } else {
                    best_p[elements[i].original_index] = 2;
                }
            }
        }
    } else { // n == 2
        // If n=2, elements[0] and elements[1].
        // Case 1: Both in same group (e.g., 1 1). f = a_0 + a_1. Goodness = 0.
        // Case 2: In different groups (e.g., 1 2). f = a_0 + a_1 + h. Goodness = 0.
        // In both cases, goodness is 0. The initial min_goodness is (a_0+a_1)-(a_0+a_1)=0.
        // So the initial best_p (all 1s) is correct.
    }

    std::cout << min_goodness << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << best_p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

