bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    for (int i = 0; i < n; ++i) { // Iterate through each head
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long head_pos = h[i];
        long long current_p = p[p_idx];

        // If the current head cannot reach the current target track p[p_idx]
        // even by moving left for T seconds, then this head cannot cover it.
        // We need to move to the next head.
        if (head_pos + T < current_p) {
            continue;
        }

        // This head can potentially cover p[p_idx].
        // Calculate the leftmost track this head can reach.
        long long left_reach = head_pos - T;

        // Calculate the rightmost track this head can reach.
        // This is the maximum of its initial position and the current target track,
        // plus the remaining time.
        long long right_reach = head_pos + T;

        // Now, advance p_idx as long as tracks are within this head's reach.
        while (p_idx < m && p[p_idx] <= right_reach) {
            // If p[p_idx] is to the left of head_pos, it must be reachable within T steps.
            // The actual rightmost point this head can cover is limited by T steps from p[p_idx].
            // If p[p_idx] is to the right of head_pos, it must be reachable within T steps.
            // The actual rightmost point this head can cover is limited by T steps from head_pos.
            // The effective rightmost point this head can cover, given it covers p[p_idx], is:
            // max(head_pos + T, p[p_idx] + (T - abs(head_pos - p[p_idx])))
            // This simplifies to:
            // If p[p_idx] <= head_pos: right_reach = head_pos + T
            // If p[p_idx] > head_pos: right_reach = p[p_idx] + (T - (p[p_idx] - head_pos)) = p[p_idx] + T - p[p_idx] + head_pos = head_pos + T
            // So, the right_reach calculated initially is correct.

            // The crucial part is that if a head covers p[p_idx], it can also cover
            // any track to its right, up to its maximum right_reach, provided the time
            // taken to reach p[p_idx] allows for further movement.
            // The total span covered by a head is [head_pos - T, head_pos + T].
            // If p[p_idx] is within this span, then this head can cover p[p_idx].
            // We want to maximize the rightmost track covered by this head, given it covers p[p_idx].
            // The rightmost track it can cover is `head_pos + T`.
            // So, we just advance p_idx as long as p[p_idx] is within `head_pos + T`.
            p_idx++;
        }
    }
    return p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible difference between p_m and h_1, or h_n and p_1.
                                    // 10^10 (max coord) - 1 (min coord) approx 10^10.
                                    // So 2 * 10^10 is a safe upper bound.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

