    // The minimum l for this pattern is x_0 + 1.
    // The minimum r for this pattern is x_0 + 2k + 1.

    for (int x_0 = 0; x_0 < n; ++x_0) {
        // k can be at most (n - 1 - x_0) / 2 to ensure x_0 + 2k < n
        // The problem states k >= 1.
