                // We want to find the minimum r for each l.
                // So, for l_pattern, the minimum r is r_pattern.
                // For l_pattern - 1, the minimum r is also r_pattern (or less if another pattern dictates it).
                // This means min_r_for_l[l_pattern] = min(min_r_for_l[l_pattern], r_pattern).
                // And for any l_prime <= l_pattern, min_r_for_l[l_prime] should be at most r_pattern.
                // This is handled by iterating l from l_pattern down to 1.
                min_r_for_l[l_pattern] = std::min(min_r_for_l[l_pattern], r_pattern);
            }
            // Optimization: If k becomes too large, the pattern length 2k+1 might exceed a reasonable bound.
            // The maximum k for a pattern to be relevant is when 2k+1 is small.
            // If k is large, say k > 20, then 2k+1 > 41.
            // The number of possible l,r pairs is N^2.
            // If N=300000, N^2 is too large.
            // The constraint on k is actually quite small.
