// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of a
    int parity_a = calculate_parity(a);

    // Calculate initial parity of b
    int parity_b = calculate_parity(b);

    // If parity_a is 0, it means an even number of '1's.
    // We can append '0's indefinitely without changing parity.
    // We can append '1's only if we first make parity_a 1.
    // If parity_a is 1, it means an odd number of '1's.
    // We can append '1's, which flips parity to 0.
    // We can append '0's, which keeps parity 1.

    // The maximum possible number of '1's we can achieve in string 'a'
    // is its current count of '1's plus its length.
    // This is because we can append '1's repeatedly.
    // Each time we append '1', the parity flips.
    // If current parity is 1, we append '1', new parity is 0.
    // If current parity is 0, we append '0', new parity is 0.
    // To get a '1' appended when parity is 0, we need to first make parity 1.
    // This is always possible by appending '1' if current parity is 1.
    // If current parity is 0, we can only append '0'.
    // So, if we want to increase the count of '1's, we must be able to append '1'.
    // This means the string must have an odd number of '1's (parity 1) at that moment.
    // If it has an even number of '1's (parity 0), we can only append '0'.
    //
    // However, the problem states "Write parity(a) to the end of a".
    // If parity(a) is 0, we append '0'. The count of '1's remains the same.
    // If parity(a) is 1, we append '1'. The count of '1's increases by 1.
    //
    // So, the count of '1's in 'a' can only increase if parity(a) is 1.
    // If parity(a) is 0, we append '0', and the count of '1's remains the same.
    //
    // Let's re-evaluate the maximum number of '1's.
    // If parity_a is 0, we can only append '0'. The count of '1's will never increase.
    // If parity_a is 1, we append '1'. The count of '1's increases by 1.
    // After appending '1', the new parity becomes 0.
    // So, we can increase the count of '1's by at most 1.
    //
    // This interpretation is wrong. The parity of the *new* string is what matters.
    // If `a` has parity `P`, we append `P`.
    // If `P` is '0', `a` becomes `a + '0'`. `count_ones(a + '0') = count_ones(a)`. `parity(a + '0') = P`.
    // If `P` is '1', `a` becomes `a + '1'`. `count_ones(a + '1') = count_ones(a) + 1`. `parity(a + '1') = 1 - P = 0`.
    //
