    //
    // Let `max_ones_a` be this maximum possible count of '1's.
    // If `count_ones(b)` is greater than `max_ones_a`, then it's impossible.

    int ones_in_a = calculate_parity(a); // This is actually count_ones(a) % 2
    int actual_ones_in_a = 0;
    for(char c : a) if(c == '1') actual_ones_in_a++;

