            }
            // For each other pile a[i], we want to add min_val to it as many times as possible
            // without exceeding k.
            // Current pile value is a[i]. We want a[i] + x * min_val <= k.
            // x * min_val <= k - a[i]
            // x <= (k - a[i]) / min_val
            // Since x must be an integer, x = floor((k - a[i]) / min_val)
            if (min_val > 0) { // min_val is guaranteed to be >= 1
                total_spells += (k - a[i]) / min_val;
            }
        }
        std::cout << total_spells << "\n";
