int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }

        // The problem statement guarantees that a solution exists.
        // Reversing the permutation always produces a permutation with the same fingerprint.
        // If p is [p_1, p_2, ..., p_n], its adjacent sums are [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
        // If p' is [p_n, p_{n-1}, ..., p_1], its adjacent sums are [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
        // These two sets of sums are identical, just in reverse order.
        // Therefore, their sorted versions (fingerprints) will be identical.
        // The only case where p' might be equal to p is if p is a palindrome (p_i = p_{n-1-i}).
        // However, for n >= 2, a permutation [1, 2, ..., n] is never a palindrome unless n=1 (not allowed)
        // or n=2 and p=[1,2] (p'=[2,1], different).
        // For n=2, p=[1,2], p'=[2,1]. They are different.
        // For n > 2, a permutation cannot be a palindrome because it would imply p_1 = p_n, p_2 = p_{n-1}, etc.
        // But all elements must be distinct. For example, if p_1 = p_n, then 1=n, which is only possible if n=1.
        // So, for n >= 2, reversing a permutation always yields a different permutation.

        std::reverse(p.begin(), p.end());
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long d;
    std::cin >> n >> d;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    long long current_a1 = a[0];

    for (int i = 1; i < n; ++i) {
        long long pile_idx = i; // 0-indexed pile_idx, corresponds to (i+1)-th pile
        long long distance = pile_idx; // distance from pile 0 (pile 1)

        if (a[pile_idx] == 0) {
            continue; // No haybales to move from this pile
        }

        // Calculate how many haybales can be moved from this pile
        // Each haybale costs 'distance' days.
        // We have 'd' days remaining.
        long long haybales_can_move = d / distance;

        long long haybales_to_move = std::min(a[pile_idx], haybales_can_move);

        current_a1 += haybales_to_move;
        d -= haybales_to_move * distance;

        if (d <= 0) {
            break; // No more days left
        }
    }

    std::cout << current_a1 << std::endl;
}

