#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n); // 0 for white (c), 1 for black (d)

    int current_color_for_half_T = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] < T / 2.0) { // Use floating point comparison to handle T/2 exactly
            p[i] = 0; // Assign to white (c)
        } else if (a[i] > T / 2.0) {
            p[i] = 1; // Assign to black (d)
        } else { // a[i] == T / 2.0
            // If T is odd, T/2.0 will have .5, so a[i] can't be T/2.0
            // This branch is only reached if T is even and a[i] == T/2
            p[i] = current_color_for_half_T;
            current_color_for_half_T = 1 - current_color_for_half_T; // Alternate color for next T/2 element
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

