#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_R_pos is -1, it means the frog is at cell 0.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed for string characters)
                // The actual cell index is i+1.
                // The distance from the last 'R' (or 0) to the current 'R' is (i+1) - (last_R_pos + 1)
                // which simplifies to i - last_R_pos.
                max_gap = std::max(max_gap, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1.
        // The last 'R' was at index last_R_pos. The cell it represents is last_R_pos + 1.
        // The target is n+1.
        // The distance is (n + 1) - (last_R_pos + 1) = n - last_R_pos.
        max_gap = std::max(max_gap, n - last_R_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        p[i] = max_val_in_row;
    }

    // Check if any p[i] is 0. If so, it means all a[i][j] for j!=i were 0.
    // This implies p[i] must be 1 (the smallest possible value in a permutation).
    // This happens if p[i] is 1 and all other p[j] are > 1.
    // Or if p[i] is 1 and some p[j] is also 1, which is not possible in a permutation.
    // The only case where max_val_in_row is 0 is if p[i] is 1 and all other p[j] are > 1.
    // In this case, min(p[i], p[j]) = min(1, p[j]) = 1 for all j where p[j] > 1.
    // This means max_val_in_row should be 1, not 0.
    // The only way max_val_in_row is 0 is if p[i] is 1 and there are no other elements,
    // or if p[i] is 1 and all other p[j] are also 1, which is not a permutation.
    // The problem states p is a permutation of 1 to n.
    // If max_val_in_row is 0, it means all a[i][j] for j!=i are 0.
    // This implies p[i] must be 1, and all other p[j] must be 0, which is not possible.
    // The only way max_val_in_row can be 0 is if n=1, but n >= 2.
    // So, max_val_in_row will always be at least 1.
    //
    // The logic for p[i] = max_val_in_row works for all p[i] except for the largest value, n.
    // If p[i] = n, then for any j != i, min(p[i], p[j]) = min(n, p[j]) = p[j].
    // So, max_{j != i} (a[i][j]) = max_{j != i} (p[j]).
    // This value is n-1, because the largest value among p[j] (j!=i) is n-1.
    // So, if p[i] = n, our current calculation would set p[i] = n-1.
    // We need to find if any p[i] was incorrectly set to n-1 when it should be n.
    //
    // We can count the occurrences of each value in the constructed p.
    // If n is present, then all values are correct.
    // If n is not present, it means one of the values that should be n was set to n-1.
    // In this case, we find the first element in p that is n-1 and increment it to n.
    // This is guaranteed to be correct because there will be exactly one value n-1 that should be n,
    // and all other values n-1 are correct.
    //
    // Example: n=2, p={1,2}.
    // a[0][1]=min(p[0],p[1])=min(1,2)=1.
    // a[1][0]=min(p[1],p[0])=min(2,1)=1.
    //
    // For i=0: max_val_in_row = a[0][1] = 1. So p[0]=1.
    // For i=1: max_val_in_row = a[1][0] = 1. So p[1]=1.
    // Resulting p = {1,1}.
    // The value n=2 is missing. One of the 1s should be 2.
    // We find the first 1 and change it to 2. Result {2,1} or {1,2}.
    //
    // Example: n=5, p={2,5,4,1,3}.
    // p[0]=2, p[1]=5, p[2]=4, p[3]=1, p[4]=3.
    //
    // i=0 (p[0]=2): max(a[0][j]) = max(min(2,5), min(2,4), min(2,1), min(2,3)) = max(2,2,1,2) = 2. So p[0]=2. Correct.
    // i=1 (p[1]=5): max(a[1][j]) = max(min(5,2), min(5,4), min(5,1), min(5,3)) = max(2,4,1,3) = 4. So p[1]=4. Incorrect, should be 5.
    // i=2 (p[2]=4): max(a[2][j]) = max(min(4,2), min(4,5), min(4,1), min(4,3)) = max(2,4,1,3) = 4. So p[2]=4. Correct.
    // i=3 (p[3]=1): max(a[3][j]) = max(min(1,2), min(1,5), min(1,4), min(1,3)) = max(1,1,1,1) = 1. So p[3]=1. Correct.
    // i=4 (p[4]=3): max(a[4][j]) = max(min(3,2), min(3,5), min(3,4), min(3,1)) = max(2,3,3,1) = 3. So p[4]=3. Correct.
    //
    // Resulting p = {2,4,4,1,3}.
    // The value n=5 is missing. The value 4 appears twice.
    // One of the 4s should be 5.
    // We find the first 4 and change it to 5. Result {2,5,4,1,3}.

    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // If n is not found, it means the element that should be n was calculated as n-1.
        // There must be exactly one such element.
        // We find the first occurrence of n-1 and change it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

