        // The maximum number of teams is limited by three factors:
        // 1. The total number of students available: (c + m + x) / 3
        // 2. The number of coders available: c
        // 3. The number of mathematicians available: m
        // The minimum of these three values gives an upper bound on the number of teams.
        // This upper bound is also achievable because any remaining students (coders or mathematicians
        // beyond the 'k' required for their specific roles) can fill the 'any specialization' slot.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
