#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for n=1 staircase
        long long sum_of_costs = 0;

        // The costs of nice staircases are 1, 7, 30, 104, 341, ...
        // These are of the form (2^k - 1) * (2^k) / 2 + (2^k - 1) * (2^k - 1) / 2
        // which simplifies to (2^k - 1) * (2^k + 2^k - 1) / 2
        // which simplifies to (2^k - 1) * (2^(k+1) - 1) / 2
        // No, this is not correct.
        // The costs are 1, 7, 30, 104, 341, ...
        // These are costs for n = 1, 3, 7, 15, 31, ... (i.e., n = 2^k - 1)
        // The cost for n = 2^k - 1 is (2^k - 1) * (2^k) / 2 + (2^k - 1) * (2^k - 1) / 2
        // This is the sum of cells for a staircase of size (2^k - 1)
        // which is (2^k - 1) * (2^k - 1 + 1) / 2 = (2^k - 1) * 2^k / 2 = (2^k - 1) * 2^(k-1)
        // Let's re-evaluate the cost for n = 2^k - 1.
        // The total cells for a staircase of size N is N * (N + 1) / 2.
        // For N = 2^k - 1, the cost is (2^k - 1) * (2^k - 1 + 1) / 2 = (2^k - 1) * 2^k / 2 = (2^k - 1) * 2^(k-1).
        // Let's check:
        // k=1, N=2^1-1=1. Cost = (2^1-1)*2^0 = 1*1 = 1. Correct.
        // k=2, N=2^2-1=3. Cost = (2^2-1)*2^1 = 3*2 = 6.
        // The example says cost for n=3 is 6.
        // The problem statement says "a nice covered staircase with 7 stairs looks like: [Image]".
        // The image shows a staircase with 7 stairs.
        // The total cells for n=7 is 7*(7+1)/2 = 7*8/2 = 28.
        // The example says for x=8, we can build n=1 (cost 1) and n=3 (cost 6). Total cost 7. Answer 2.
        // So the costs are 1, 6, 28, 120, 496, ...
        // These are (2^k - 1) * 2^(k-1) for k=1, 2, 3, ...
        // Let's use this formula.

        long long k_val = 1;
        while (true) {
            long long n_val = (1LL << k_val) - 1; // n = 2^k - 1
            long long cost = n_val * (1LL << (k_val - 1)); // cost = n * 2^(k-1)

            if (sum_of_costs + cost <= x) {
                sum_of_costs += cost;
                count++;
            } else {
                break;
            }

            // Check for overflow before calculating next k_val
            // (1LL << (k_val + 1)) - 1 could overflow if k_val + 1 >= 63
            // (1LL << k_val) could overflow if k_val >= 63
            // Max x is 10^18.
            // Max cost is around 10^18.
            // If k_val = 60, n_val = 2^60 - 1. cost = (2^60 - 1) * 2^59. This is too large.
            // 2^60 approx 10^18.
            // 2^59 approx 0.5 * 10^18.
            // (2^60 - 1) * 2^59 is approx 0.5 * 10^36. This will overflow long long.
            // The largest k_val for which cost fits in long long:
            // (2^k - 1) * 2^(k-1) <= 10^18
            // Approx 2^k * 2^(k-1) = 2^(2k-1) <= 10^18
            // 2k-1 <= log2(10^18) approx 18 * log2(10) approx 18 * 3.32 approx 59.79
            // 2k-1 <= 59
            // 2k <= 60
            // k <= 30.
            // So k_val will not exceed 30.
            // (1LL << (k_val + 1)) will not overflow if k_val + 1 <= 62.
            // If k_val = 30, then k_val + 1 = 31. (1LL << 31) is fine.
            // So no overflow issues for k_val.
            k_val++;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number we will use for the "zigzag" part

    // The first k+1 numbers will generate k distinct differences:
    // |1 - (k+1)| = k
    // |(k+1) - 2| = k-1
    // |2 - k| = k-2
    // ...
    // This sequence is 1, k+1, 2, k, 3, k-1, ...
    // It generates differences k, k-1, k-2, ..., 1.
    // This covers exactly k distinct differences.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, print from left (ascending)
            std::cout << left++;
        } else { // Odd index, print from right (descending)
            std::cout << right--;
        }
        std::cout << " ";
    }

    // The remaining numbers (from k+2 to n) can be printed in increasing order.
    // This will only generate a difference of 1 with the previous number,
    // which is already covered by the initial k differences (specifically, the difference of 1).
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // We can only add a closing bracket if we have an unmatched opening bracket
            // in our result string. However, a simpler approach is to just add it
            // if we still need closing brackets. Since the problem guarantees a solution
            // and the input 's' is a regular bracket sequence, and we are picking
            // k/2 open and k/2 close, this greedy choice will work.
            // The key is that we prioritize picking open brackets first, then close.
            // The balance property will be maintained because we pick k/2 of each.
            // The problem guarantees a solution, so we don't need to worry about
            // balance going negative if we just pick k/2 open and k/2 close.
            // The order of picking from 's' ensures subsequence property.
            result += ')';
            close_needed--;
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        if (m > n) {
            std::cout << 0 << "\n";
            continue;
        }

        long long k_max = n / m;

        // Calculate the sum of last digits for one full cycle (k=1 to k=10)
        // The last digits are (1*m)%10, (2*m)%10, ..., (10*m)%10
        long long sum_cycle = 0;
        for (int i = 1; i <= 10; ++i) {
            sum_cycle += (static_cast<long long>(i) * m) % 10;
        }

        // Number of full cycles of 10 multiples
        long long num_full_cycles = k_max / 10;
        long long total_sum = num_full_cycles * sum_cycle;

        // Remaining multiples after full cycles
        long long remaining_k = k_max % 10;
        for (long long i = 1; i <= remaining_k; ++i) {
            total_sum += (i * m) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result(n, '0');

    // For m=1, the subarray is [1]. This is always possible by taking l=r=pos[1].
    // min=1, max=1, length=1. So 1 is always beautiful.
    result[0] = '1';

    // min_idx and max_idx will track the minimum and maximum indices
    // encountered so far for numbers 1 to current_m.
    // Initialize for m=1.
    int min_idx = pos[1];
    int max_idx = pos[1];

    // Iterate for m from 2 to n
    for (int m = 2; m <= n; ++m) {
        // Update min_idx and max_idx to include the position of 'm'
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // Check if the current range [min_idx, max_idx] satisfies the conditions for 'm'
        // 1. The length of the subarray (max_idx - min_idx + 1) must be equal to 'm'.
        // 2. The minimum value in p[min_idx...max_idx] is 1 (guaranteed by construction).
        // 3. The maximum value in p[min_idx...max_idx] is m (guaranteed by construction).
        if (max_idx - min_idx + 1 == m) {
            result[m - 1] = '1';
        }
    }

    std::cout << result << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
