void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // If such a `p` exists, then a[p-1] > a[p].
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // After this loop, a[p...n-1] is non-decreasing.
    // If p=0, the whole array is non-decreasing.
    // If p>0, then a[p-1] < a[p] is NOT guaranteed.
    // It's a[p-1] < a[p] if the loop terminated because of the condition.
    // If the loop terminated because p=0, then a[0...n-1] is non-decreasing.

    // Now, find the rightmost index `q` such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // If such a `q` exists, then a[q-1] < a[q].
    int q = p; // Start from p, as a[p...n-1] is non-decreasing.
               // We are looking for the non-increasing part to the left of p.
    while (q > 0 && a[q-1] <= a[q]) { // This condition is for non-increasing: a[q-1] >= a[q]
        q--;
    }
    // After this loop, a[q...p-1] is non-increasing.
    // If q=0, then a[0...p-1] is non-increasing.
    // If q>0, then a[q-1] > a[q] is NOT guaranteed.
    // It's a[q-1] > a[q] if the loop terminated because of the condition.
    // If the loop terminated because q=0, then a[0...p-1] is non-increasing.

    // The length of the prefix to remove is `q`.
    std::cout << q << std::endl;
}

