int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: d^2 - 4d
            // For a real solution, d^2 - 4d >= 0
            // Since d >= 0, this means d >= 4 or d = 0.
            // We've handled d=0, so for d >= 4, there are real solutions.

            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            // Solutions for 'a' using quadratic formula: (d +/- sqrt(d^2 - 4d)) / 2
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = d - a1; // b = d - a

            // The problem asks for non-negative a and b.
            // Since d >= 4, d is positive.
            // sqrt(d^2 - 4d) is real and non-negative.
            // d + sqrt(d^2 - 4d) is positive, so a1 is positive.
            // For b1 = d - a1 = d - (d + sqrt(d^2 - 4d)) / 2 = (2d - d - sqrt(d^2 - 4d)) / 2 = (d - sqrt(d^2 - 4d)) / 2
            // We need to ensure b1 >= 0.
            // This means d - sqrt(d^2 - 4d) >= 0
            // d >= sqrt(d^2 - 4d)
            // d^2 >= d^2 - 4d (since both sides are non-negative, we can square)
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So, both a1 and b1 will be non-negative.

            // The other solution for 'a' would be a2 = (d - sqrt_discriminant) / 2.0
            // and b2 = d - a2.
            // (a1, b1) and (a2, b2) are just permutations of each other.
            // For example, if a1 is the larger root, then b1 will be the smaller root.
            // The problem doesn't specify order, so (a1, b1) is a valid pair.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long s;
    std::cin >> n >> s;

    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2; // For 0-indexed array of odd length n, median is at n/2

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of median_idx must be <= s
    // If a[i] > s, we must decrease it to s. Cost is a[i] - s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of median_idx must be >= s
    // If a[i] < s, we must increase it to s. Cost is s - a[i].
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

