#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long A, B, C, D;
    std::cin >> A >> B >> C >> D;

    long long total_toys = A + B + C + D;

    bool can_be_box1 = false;
    bool can_be_box2 = false;
    bool can_be_box3 = false;
    bool can_be_box4 = false;

    if (total_toys == 1) {
        if (A == 1) can_be_box1 = true;
        if (B == 1) can_be_box2 = true;
        if (C == 1) can_be_box3 = true;
        if (D == 1) can_be_box4 = true;
    } else {
        // Case 1: Final product is negative (Box 1 or Box 2)
        // This requires an odd number of negative factors.
        // The number of negative factors is A + B.
        // If A+B is odd, it's possible to end up with a negative product.
        if ((A + B) % 2 == 1) {
            // Can it be Box 1 (value <= -1)?
            // To get <= -1, we need to be able to make a product with magnitude >= 1.
            // This is possible if:
            // 1. There's at least one toy in Box 1 or Box 4 (magnitude >= 1).
            // 2. Or, if we can combine enough toys from Box 2 and Box 3 to get magnitude >= 1.
            //    This requires at least two toys from B2/B3 to be combined to form a product >= 1.
            //    E.g., -0.5 * -0.5 = 0.25 (still < 1)
            //    E.g., -0.5 * 0.5 = -0.25 (still < 1)
            //    It's impossible to get magnitude >= 1 by multiplying only values with magnitude < 1.
            //    So, we need at least one toy from Box 1 or Box 4 to ensure magnitude >= 1.
            //    If A+D > 0, then we can potentially get magnitude >= 1.
            //    If A+D == 0, all initial toys have magnitude < 1. Any product will also have magnitude < 1.
            //    So, if A+D > 0, Box 1 is possible.
            if (A + D > 0) {
                can_be_box1 = true;
            }
            // Can it be Box 2 (-1 < value < 0)?
            // This is always possible if A+B is odd.
            // We can always pick values close to 0 (e.g., -0.1, 0.1) for B and C,
            // and values close to -1 (e.g., -0.9) for A, and values close to 1 (e.g., 1.1) for D.
            // If A+D == 0, all initial toys have magnitude < 1. The final product will also have magnitude < 1.
            // So, if A+D == 0, and A+B is odd, it must be Box 2.
            // If A+D > 0, we can choose values such that the final product is between -1 and 0.
            // For example, if we have a toy in B1 or B4, say -3. We can multiply it by a very small positive number (e.g., 0.1)
            // to get -0.3. This requires having enough positive numbers to "dilute" the magnitude.
            // The only way to *not* be able to make a product in B2 is if all products must have magnitude >= 1.
            // This happens if we only have toys in B1 and B4, and we always multiply them.
            // But we can always introduce B2/B3 toys to reduce magnitude.
            // So, if A+B is odd, Box 2 is always possible.
            can_be_box2 = true;
        }

        // Case 2: Final product is positive (Box 3 or Box 4)
        // This requires an even number of negative factors.
        // If A+B is even, it's possible to end up with a positive product.
        if ((A + B) % 2 == 0) {
            // Can it be Box 3 (0 < value < 1)?
            // This is always possible if A+B is even.
            // We can always pick values close to 0 (e.g., 0.1) for B and C,
            // and values close to -1 (e.g., -0.9) for A, and values close to 1 (e.g., 1.1) for D.
            // If A+D == 0, all initial toys have magnitude < 1. The final product will also have magnitude < 1.
            // So, if A+D == 0, and A+B is even, it must be Box 3.
            // If A+D > 0, we can choose values such that the final product is between 0 and 1.
            // For example, if we have a toy in B1 or B4, say 3. We can multiply it by a very small positive number (e.g., 0.1)
            // to get 0.3. This requires having enough positive numbers to "dilute" the magnitude.
            // So, if A+B is even, Box 3 is always possible.
            can_be_box3 = true;

            // Can it be Box 4 (value >= 1)?
            // To get >= 1, we need to be able to make a product with magnitude >= 1.
            // This is possible if A+D > 0.
            // If A+D == 0, all initial toys have magnitude < 1. Any product will also have magnitude < 1.
            // So, if A+D > 0, Box 4 is possible.
            if (A + D > 0) {
                can_be_box4 = true;
            }
        }
    }

    std::cout << (can_be_box1 ? "Ya" : "Tidak") << " "
              << (can_be_box2 ? "Ya" : "Tidak") << " "
              << (can_be_box3 ? "Ya" : "Tidak") << " "
              << (can_be_box4 ? "Ya" : "Tidak") << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in ascending order
    std::sort(b_elements.begin(), b_elements.end(), compareElements);

    // The optimal strategy is to pair the i-th smallest A value with the (m-1-i)-th smallest B value.
    // This means a_elements[i].value should be paired with b_elements[m-1-i].value.
    // We need to store the result in an array indexed by the original positions of B.
    std::vector<long long> result(m);
    for (int i = 0; i < m; ++i) {
        // a_elements[i] is the i-th smallest value from A.
        // b_elements[m - 1 - i] is the (m-1-i)-th smallest value from B, which is the i-th largest value from B.
        // We want to assign a_elements[i].value to the original position of b_elements[m - 1 - i].
        result[b_elements[m - 1 - i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a prefix of length `len` is a permutation
bool is_permutation_prefix(int len, const std::vector<int>& a, const std::vector<int>& prefix_max_val, const std::vector<bool>& prefix_distinct_check) {
    if (len == 0) return false; // Permutations must have non-zero length
    return prefix_max_val[len - 1] == len && prefix_distinct_check[len - 1];
}

// Function to check if a suffix of length `len` is a permutation
bool is_permutation_suffix(int len, int n, const std::vector<int>& a, const std::vector<int>& suffix_max_val, const std::vector<bool>& suffix_distinct_check) {
    if (len == 0) return false; // Permutations must have non-zero length
    return suffix_max_val[n - len] == len && suffix_distinct_check[n - len];
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute for prefixes
    std::vector<int> prefix_max_val(n);
    std::vector<bool> prefix_distinct_check(n);
    std::vector<bool> seen_prefix(n + 1, false); // Max value can be n, but elements are <= n-1
    int current_max_prefix = 0;
    bool current_distinct_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // a[i] > n is technically not possible given constraints a[i] <= n-1
            current_distinct_prefix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_prefix = std::max(current_max_prefix, a[i]);
        prefix_max_val[i] = current_max_prefix;
        prefix_distinct_check[i] = current_distinct_prefix;
    }

    // Precompute for suffixes
    std::vector<int> suffix_max_val(n);
    std::vector<bool> suffix_distinct_check(n);
    std::fill(seen_prefix.begin(), seen_prefix.end(), false); // Reuse seen_prefix for suffix
    int current_max_suffix = 0;
    bool current_distinct_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] > n || a[i] <= 0 || seen_prefix[a[i]]) { // a[i] > n is technically not possible given constraints a[i] <= n-1
            current_distinct_suffix = false;
        }
        seen_prefix[a[i]] = true;
        current_max_suffix = std::max(current_max_suffix, a[i]);
        suffix_max_val[i] = current_max_suffix;
        suffix_distinct_check[i] = current_distinct_suffix;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 can range from 1 to n-1.
    // If l1 = n, then l2 = 0, which is not allowed.
    // If l1 = 0, then l2 = n, which is not allowed.
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if the first l1 elements form a permutation of length l1
        bool p1_is_perm = is_permutation_prefix(l1, a, prefix_max_val, prefix_distinct_check);

        // Check if the last l2 elements form a permutation of length l2
        bool p2_is_perm = is_permutation_suffix(l2, n, a, suffix_max_val, suffix_distinct_check);

        if (p1_is_perm && p2_is_perm) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <functional>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor ^= a;
    }

    // Condition for a good array: sum = 2 * xor
    // If current_sum = 2 * current_xor, the array is already good.
    // We can output 0 elements.
    if (current_sum == 2 * current_xor) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // If not good, we need to append elements.
    // We can always make it good by appending at most 3 elements.
    // Let's try to append two elements.
    // Let the two appended elements be X and Y.
    // New sum: S' = current_sum + X + Y
    // New xor: X' = current_xor ^ X ^ Y
    // We want S' = 2 * X'
    // current_sum + X + Y = 2 * (current_xor ^ X ^ Y)

    // A common strategy is to append elements that simplify the XOR sum.
    // Let's append current_xor as the first element.
    // New sum: S_1 = current_sum + current_xor
    // New xor: X_1 = current_xor ^ current_xor = 0

    // Now we need to append a second element, say Z, such that:
    // (S_1 + Z) = 2 * (X_1 ^ Z)
    // (current_sum + current_xor + Z) = 2 * (0 ^ Z)
    // current_sum + current_xor + Z = 2 * Z
    // current_sum + current_xor = Z

    // So, if we append current_xor and (current_sum + current_xor), the array becomes good.
    // Let b1 = current_xor
    // Let b2 = current_sum + current_xor
    // The appended elements are b1 and b2.
    // The number of appended elements is 2.
    // The new sum will be current_sum + b1 + b2
    // The new xor will be current_xor ^ b1 ^ b2
    //
    // New sum = current_sum + current_xor + (current_sum + current_xor)
    //         = 2 * current_sum + 2 * current_xor
    //
    // New xor = current_xor ^ current_xor ^ (current_sum + current_xor)
    //         = 0 ^ (current_sum + current_xor)
    //         = current_sum + current_xor
    //
    // Check condition: New sum = 2 * New xor
    // 2 * current_sum + 2 * current_xor = 2 * (current_sum + current_xor)
    // This is true.

    // Output 2 elements: current_xor and (current_sum + current_xor)
    std::cout << 2 << std::endl;
    std::cout << current_xor << " " << (current_sum + current_xor) << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can potentially be part of an 'ab' pair
            // with any 'a's to its left that haven't been processed yet.
            // These 'a's are represented by 'count_a'.
            // Each such 'a' will eventually move past this 'b'.
            // The number of steps for this 'b' to move past all 'count_a' 'a's
            // is 'count_a'.
            // When an 'a' moves past a 'b' (ab -> bba), the 'a' effectively
            // jumps over the 'b', and a new 'b' is created to its left.
            // This new 'b' will then interact with 'a's further to its left.
            // The key insight is that each 'a' effectively doubles the number
            // of 'b's it needs to jump over.
            // So, when we see a 'b', it means all 'a's to its left (represented by count_a)
            // will eventually interact with it.
            // Each 'a' will cause one 'ab' -> 'bba' operation involving this 'b'.
            // The total steps for this 'b' to be moved past by all 'count_a' 'a's
            // is 'count_a'.
            total_steps = (total_steps + count_a) % mod;

            // After this 'b' has been moved past by all 'count_a' 'a's,
            // it effectively becomes two 'b's for the 'a's further to the left.
            // This is because 'ab' -> 'bba'. The original 'b' is still there,
            // and a new 'b' is inserted.
            // So, the number of 'a's that will interact with future 'b's (to their left)
            // effectively doubles for each 'b' they encounter.
            // This is not quite right. The 'count_a' represents the number of 'a's
            // that are currently "active" and need to move past 'b's.
            // When an 'a' moves past a 'b', it consumes one 'b' from the 'b's it needs to pass.
            // But the 'b' itself effectively duplicates for the 'a's to its left.
            // Let's re-evaluate:
            // When we see a 'b', it means all 'a's to its left (count_a) will eventually
            // move past it. Each such 'a' will perform one operation with this 'b'.
            // So, 'count_a' operations are added.
            // After these operations, this 'b' effectively becomes two 'b's for any 'a's
            // further to the left. This means the 'count_a' value should be doubled
            // for the next 'b' encountered.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now available
            // to form 'ab' pairs with any 'b's to its right.
            // So, we increment the count of available 'a's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::map<int, long long> x_counts;
    std::map<int, long long> y_counts;
    std::map<std::pair<int, int>, long long> xy_counts;

    for (int i = 0; i < n; ++i) {
        int x, y;
        std::cin >> x >> y;
        x_counts[x]++;
        y_counts[y]++;
        xy_counts[{x, y}]++;
    }

    long long total_pairs = 0;

    // Pairs with same x-coordinate
    for (auto const& [x_coord, count] : x_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Pairs with same y-coordinate
    for (auto const& [y_coord, count] : y_counts) {
        if (count >= 2) {
            total_pairs += count * (count - 1) / 2;
        }
    }

    // Subtract pairs that were counted twice (same x AND same y)
    for (auto const& [coords, count] : xy_counts) {
        if (count >= 2) {
            total_pairs -= count * (count - 1) / 2;
        }
    }

    std::cout << total_pairs << std::endl;

    return 0;
}

