// Function to convert a number to its parity pattern string
std::string get_parity_pattern(long long n) {
    std::string s = "";
    if (n == 0) {
        s = "0";
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                s += '0';
            } else {
                s += '1';
            }
            n /= 10;
        }
    }
    // Pad with '0's from the left to a fixed length (e.g., 18 for 10^18-1)
    // The problem states "If the pattern is shorter than this integer, it's supplemented with 0-s from the left."
    // and "If the integer is shorter than the pattern its decimal notation is supplemented with the 0-s from the left."
    // This implies we should normalize both to a fixed length, say 18, by padding with '0's.
    // Since we build the string from right to left, padding from the left means appending '0's to our string.
    while (s.length() < 18) { // Max 18 digits for 10^18-1
        s += '0';
    }
    return s;
}

