// Function to find prime factors of a number
std::vector<long long> get_prime_factors(long long n) {
    std::vector<long long> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            factors.push_back(i);
            while (n % i == 0) {
                n /= i;
            }
        }
    }
    if (n > 1) {
        factors.push_back(n);
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find a divisor x of p such that x is not divisible by q.
        // We want the largest such x.
        // This means we need to remove some prime factors from p such that the resulting number
        // is no longer divisible by q, but we remove as few as possible (or rather, reduce p as little as possible).

        // Get prime factors of q
        std::vector<long long> q_prime_factors = get_prime_factors(q);

        long long max_x = 1;

        for (long long f : q_prime_factors) {
            // For each prime factor f of q, we want to find the largest divisor of p
            // that is not divisible by q, by "reducing" p using f.

            // Calculate p_temp = p
            // Divide p_temp by f until it's no longer divisible by q.
            // This means we divide p_temp by f until the power of f in p_temp is less than
            // the power of f in q.
            // Or, more simply, we divide p_temp by f until p_temp % q != 0.
            // But we need to be careful: p_temp might become not divisible by q
            // because some other prime factor's power was reduced.
            // The strategy is: take p, divide it by f until it's no longer divisible by q.
            // The resulting number is a candidate for x.

            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= f;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

