void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int k = 0; k <= 9; ++k) {
        std::string colors(n, ' ');
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_k = true;

        for (int i = 0; i < n; ++i) {
            if (d[i] < k) {
                colors[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > k) {
                colors[i] = '2';
                s2_digits.push_back(d[i]);
            } else { // d[i] == k
                // Try to put it in S2 first
                // If S2 is empty or its last element is <= k, put it in S2
                // Otherwise, it must go to S1
                if (s2_digits.empty() || s2_digits.back() <= d[i]) {
                    colors[i] = '2';
                    s2_digits.push_back(d[i]);
                } else {
                    colors[i] = '1';
                    s1_digits.push_back(d[i]);
                }
            }
        }

        // Check if S1 is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // Check if S2 is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_k = false;
                break;
            }
        }
        if (!possible_k) continue;

        // If we reach here, a valid coloring is found for this k
        std::cout << colors << "\n";
        return;
    }

    std::cout << "-\n";
}

