void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_password;

    for (size_t i = 0; i < s.length() - 1; ++i) {
        adj[s[i]].insert(s[i+1]);
        adj[s[i+1]].insert(s[i]);
        used_in_password.insert(s[i]);
        used_in_password.insert(s[i+1]);
    }
    if (s.length() == 1) { // Handle single character password
        used_in_password.insert(s[0]);
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout = "";
    std::set<char> visited;
    char start_node = '\0';

    // Find a starting node (a character with only one neighbor in the password graph)
    for (char c = 'a'; c <= 'z'; ++c) {
        if (used_in_password.count(c) && adj[c].size() == 1) {
            start_node = c;
            break;
        }
    }

    // If no node with one neighbor is found, it means all nodes in the password graph have two neighbors (a cycle)
    // or there's only one node (password length 1) or no nodes (empty password, not possible by constraints).
    // If it's a cycle, it's impossible to form a path.
    // If all nodes have 2 neighbors, and it's not a cycle, it means the graph is disconnected, which is fine.
    // But if it's a single connected component and all nodes have 2 neighbors, it's a cycle.
    // A path graph must have at least two endpoints (degree 1).
    // If all nodes in the password graph have degree 2, it means it's a cycle.
    // A cycle cannot be embedded into a path.
    // Exception: if the password graph has only one node (e.g., "a"), it has degree 0.
    // If the password graph has two nodes (e.g., "ab"), both have degree 1.
    // If the password graph has more than two nodes and all have degree 2, it's a cycle.
    if (start_node == '\0' && !used_in_password.empty()) {
        // This means all nodes in used_in_password have degree 2 (or 0 if it's a single char password).
        // If it's a single char password, start_node will be '\0' but it's valid.
        // If it's a cycle, it's impossible.
        // The only case where start_node is '\0' and it's possible is if used_in_password has only one element.
        if (used_in_password.size() > 1) { // If more than one char, and all have degree 2, it's a cycle.
            std::cout << "NO\n";
            return;
        } else { // Single char password, e.g., "a"
            start_node = *used_in_password.begin();
        }
    } else if (used_in_password.empty()) { // Empty password, not possible by constraints, but for robustness
        start_node = 'a'; // Just pick 'a' as a starting point
    }


    if (start_node != '\0') {
        char current = start_node;
        char prev = '\0'; // Sentinel for the previous character

        while (current != '\0' && visited.find(current) == visited.end()) {
            layout += current;
            visited.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
        }
    }

    // Add remaining characters not used in the password
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited.find(c) == visited.end()) {
            layout += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout << "\n";
}

