int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int L = s.length();

    std::vector<std::vector<int>> char_indices(26);
    for (int i = 0; i < L; ++i) {
        char_indices[s[i] - 'a'].push_back(i);
    }

    double total_win_prob = 0.0;

    for (int k_actual = 0; k_actual < L; ++k_actual) {
        char char0 = s[k_actual];

        std::vector<int> possible_k_values;
        for (int idx : char_indices[char0 - 'a']) {
            possible_k_values.push_back(idx);
        }

        if (possible_k_values.size() == 1) {
            total_win_prob += 1.0; // Vasya wins for sure if t[0] uniquely determines k
            continue;
        }

        // Vasya needs to choose p to maximize win probability for this char0
        // For a fixed char0, Vasya will choose p that maximizes the number of unique (k, (k+p)%L) pairs
        // among the possible_k_values.

        // For each possible p (1 to L-1), calculate how many k's are uniquely determined.
        // Vasya will pick the p that maximizes this count.

        int max_unique_k_count_for_char0 = 0;

        for (int p = 1; p < L; ++p) {
            std::map<char, std::vector<int>> char_p_to_k_map;
            for (int k_cand : possible_k_values) {
                char char_p = s[(k_cand + p) % L];
                char_p_to_k_map[char_p].push_back(k_cand);
            }

            int current_unique_k_count = 0;
            for (auto const& [char_p_val, k_list] : char_p_to_k_map) {
                if (k_list.size() == 1) {
                    current_unique_k_count++;
                }
            }
            max_unique_k_count_for_char0 = std::max(max_unique_k_count_for_char0, current_unique_k_count);
        }

        total_win_prob += static_cast<double>(max_unique_k_count_for_char0) / possible_k_values.size();
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

