    //   `bit_0_final = (current_val0 >> j) & 1`
    //   `bit_1_final = (current_val1 >> j) & 1`

    // We want to find A, B, C such that:
    // ( ( (y & A) | B) ^ C ) == final_value_for_y
    //
    // Let's determine the values for A, B, C bit by bit.
    // For each bit j:
    // Let y_j be the j-th bit of the input y.
    // Let a_j, b_j, c_j be the j-th bits of A, B, C respectively.
    //
    // The transformation for bit j is: ( (y_j & a_j) | b_j ) ^ c_j
    //
    // Case 1: y_j = 0
    //   ( (0 & a_j) | b_j ) ^ c_j = (0 | b_j) ^ c_j = b_j ^ c_j
    //   This must be equal to `(current_val0 >> j) & 1`.
    //
    // Case 2: y_j = 1
    //   ( (1 & a_j) | b_j ) ^ c_j = (a_j | b_j) ^ c_j
    //   This must be equal to `(current_val1 >> j) & 1`.

    int A = 1023; // Initialize A to all 1s (identity for &)
    int B = 0;    // Initialize B to all 0s (identity for |)
    int C = 0;    // Initialize C to all 0s (identity for ^)

    for (int j = 0; j < 10; ++j) {
        int bit_0_final = (current_val0 >> j) & 1;
        int bit_1_final = (current_val1 >> j) & 1;

        // We need to find a_j, b_j, c_j such that:
        // 1. b_j ^ c_j = bit_0_final
        // 2. (a_j | b_j) ^ c_j = bit_1_final

        // Let's iterate through possible (a_j, b_j, c_j) combinations for this bit.
        // There are 8 combinations. We need to find one that works.
        // The problem guarantees a solution with at most 5 lines, and this form is general enough.

        // Try to set a_j, b_j, c_j for bit j
        // The logic below directly determines a_j, b_j, c_j based on bit_0_final and bit_1_final.
        // This is derived from the truth table of the combined operations.

        // If bit_0_final == 0 and bit_1_final == 0:
        //   Input 0 -> 0, Input 1 -> 0. This means the bit is always 0.
        //   We can achieve this with: (y_j & 0) | 0 = 0. So a_j=0, b_j=0, c_j=0.
        //   Or: (y_j & 1) | 0 = y_j. Then y_j ^ 1 = 0. So a_j=1, b_j=0, c_j=1.
        //   The simplest is a_j=0, b_j=0, c_j=0.
        //   This means A's j-th bit is 0, B's j-th bit is 0, C's j-th bit is 0.
        //   So, A &= ~(1 << j) (set j-th bit of A to 0)
        //   B &= ~(1 << j) (set j-th bit of B to 0)
        //   C &= ~(1 << j) (set j-th bit of C to 0)

        // If bit_0_final == 0 and bit_1_final == 1:
        //   Input 0 -> 0, Input 1 -> 1. This means the bit is identity (y_j).
        //   We can achieve this with: (y_j & 1) | 0 = y_j. So a_j=1, b_j=0, c_j=0.
        //   A's j-th bit is 1, B's j-th bit is 0, C's j-th bit is 0.
        //   So, A |= (1 << j) (set j-th bit of A to 1)
        //   B &= ~(1 << j) (set j-th bit of B to 0)
        //   C &= ~(1 << j) (set j-th bit of C to 0)

        // If bit_0_final == 1 and bit_1_final == 0:
        //   Input 0 -> 1, Input 1 -> 0. This means the bit is negation (1 - y_j).
        //   We can achieve this with: (y_j & 1) | 0 = y_j. Then y_j ^ 1 = 1 - y_j. So a_j=1, b_j=0, c_j=1.
        //   A's j-th bit is 1, B's j-th bit is 0, C's j-th bit is 1.
        //   So, A |= (1 << j) (set j-th bit of A to 1)
        //   B &= ~(1 << j) (set j-th bit of B to 0)
        //   C |= (1 << j) (set j-th bit of C to 1)

        // If bit_0_final == 1 and bit_1_final == 1:
        //   Input 0 -> 1, Input 1 -> 1. This means the bit is always 1.
        //   We can achieve this with: (y_j & 0) | 1 = 1. So a_j=0, b_j=1, c_j=0.
        //   A's j-th bit is 0, B's j-th bit is 1, C's j-th bit is 0.
        //   So, A &= ~(1 << j) (set j-th bit of A to 0)
        //   B |= (1 << j) (set j-th bit of B to 1)
        //   C &= ~(1 << j) (set j-th bit of C to 0)

        // Combining these:
        if (bit_0_final == 0 && bit_1_final == 0) { // Always 0
            A &= ~(1 << j); // a_j = 0
            B &= ~(1 << j); // b_j = 0
            C &= ~(1 << j); // c_j = 0
        } else if (bit_0_final == 0 && bit_1_final == 1) { // Identity
            A |= (1 << j);  // a_j = 1
            B &= ~(1 << j); // b_j = 0
            C &= ~(1 << j); // c_j = 0
        } else if (bit_0_final == 1 && bit_1_final == 0) { // Negation
            A |= (1 << j);  // a_j = 1
            B &= ~(1 << j); // b_j = 0
            C |= (1 << j);  // c_j = 1
        } else { // bit_0_final == 1 && bit_1_final == 1, Always 1
            A &= ~(1 << j); // a_j = 0
            B |= (1 << j);  // b_j = 1
            C &= ~(1 << j); // c_j = 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', A});
    }
    if (B != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', B});
    }
    if (C != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', C});
    }

    std::cout << result_ops.size() << std::endl;
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << std::endl;
    }

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <cmath>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int n = s.length();
    long long good_substrings_count = 0;

    // Max length for which 2^L is still relatively small, say 20.
    // 2^18 = 262144, 2^19 = 524288.
    // If length L > 18, then 2^L > 2*10^5.
    // If s[l] == '1', then f(s_l...s_r) >= 2^(L-1).
    // If L > 18, then 2^(L-1) > 10^5.
    // If s[l] == '1' and L > 18, then f(s_l...s_r) will be at least 2^(L-1).
    // If L = 19, f(...) >= 2^18 = 262144. But L = 19. So f(...) != L.
    // If L = 20, f(...) >= 2^19 = 524288. But L = 20. So f(...) != L.
    // In general, for L >= 19, 2^(L-1) > L.
    // So if s[l] == '1', we only need to check substrings of length up to ~18-19.
    // Let's pick a safe upper bound, say 20.
    const int MAX_CHECK_LEN = 20; 

    for (int i = 0; i < n; ++i) {
        // Case 1: Substrings starting with '1'
        if (s[i] == '1') {
            long long current_val = 0;
            for (int j = i; j < n; ++j) {
                current_val = (current_val << 1) | (s[j] - '0');
                int len = j - i + 1;

                // Optimization: If current_val exceeds MAX_CHECK_LEN,
                // it's very unlikely to be equal to len.
                // Specifically, if current_val > n, it cannot be equal to len.
                // Also, if len > MAX_CHECK_LEN, current_val will be large.
                // For len > MAX_CHECK_LEN, current_val >= 2^(len-1).
                // If len-1 >= MAX_CHECK_LEN, then 2^(len-1) is much larger than len.
                // For example, if MAX_CHECK_LEN = 20, and len = 21, current_val >= 2^20 = 1048576.
                // This is much larger than 21.
                // So we can break early if len exceeds a certain threshold.
                if (len > MAX_2_POW_N_IS_N_PLUS_1) { // MAX_2_POW_N_IS_N_PLUS_1 is around 20
                    break;
                }

                if (current_val == len) {
                    good_substrings_count++;
                }
            }
        } else { // Case 2: Substrings starting with '0'
            // Count leading zeros
            int zero_count = 0;
            for (int j = i; j < n; ++j) {
                if (s[j] == '0') {
                    zero_count++;
                } else {
                    // Found the first '1' at index k
                    // The substring is s[i...j-1] + s[j...k]
                    // s[i...j-1] are all '0's.
                    // s[j] is '1'.

                    long long current_val = 0;
                    int k_limit = std::min(n, j + MAX_CHECK_LEN); // Only check up to MAX_CHECK_LEN characters after the first '1'
                    for (int k = j; k < k_limit; ++k) {
                        current_val = (current_val << 1) | (s[k] - '0');
                        int len = (k - j + 1) + zero_count; // Total length including leading zeros

                        if (current_val == len) {
                            good_substrings_count++;
                        }
                        if (current_val > n) { // Optimization: if value exceeds max possible length, it can't be equal to len
                            break;
                        }
                    }
                    // Move i to j-1 to continue outer loop from the first '1'
                    // The outer loop will increment i to j, effectively skipping the zeros.
                    i = j - 1; 
                    break;
                }
            }
        }
    }

    std::cout << good_substrings_count << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

