#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate initial balance
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) {
            initial_balance++;
        } else {
            initial_balance--;
        }
    }

    // If initial balance is 0, no jars need to be eaten.
    if (initial_balance == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Precompute prefix sums for left side (jars 1 to n)
    // `left_balance[k]` stores the balance of jars `n-k+1` to `n`.
    // This is equivalent to `prefix_sum[n] - prefix_sum[n-k]`.
    // Or, more simply, `left_balance[k]` is the balance of the last `k` jars on the left side.
    // `left_balance[0]` = 0 (no jars eaten from left)
    // `left_balance[1]` = balance of jar `n`
    // `left_balance[k]` = balance of jars `n-k+1, ..., n`
    std::map<int, int> left_balance_to_k; // Stores {balance_diff : k} for left side
    left_balance_to_k[0] = 0; // 0 jars eaten from left, balance diff 0

    int current_left_balance = 0;
    for (int k = 1; k <= n; ++k) {
        // Jar `n-k+1` is the `k`-th jar from the right end of the left segment.
        // Its index in `a` is `n-k`.
        if (a[n - k] == 1) {
            current_left_balance++;
        } else {
            current_left_balance--;
        }
        // We want to find the minimum `k` for a given `current_left_balance`.
        // Since we iterate `k` from 1 to `n`, the first time we see a balance,
        // it corresponds to the minimum `k`.
        if (left_balance_to_k.find(current_left_balance) == left_balance_to_k.end()) {
            left_balance_to_k[current_left_balance] = k;
        }
    }

    // Precompute prefix sums for right side (jars n+1 to 2n)
    // `right_balance[k]` stores the balance of jars `n+1` to `n+k`.
    // `right_balance[0]` = 0 (no jars eaten from right)
    // `right_balance[1]` = balance of jar `n+1`
    // `right_balance[k]` = balance of jars `n+1, ..., n+k`
    std::map<int, int> right_balance_to_k; // Stores {balance_diff : k} for right side
    right_balance_to_k[0] = 0; // 0 jars eaten from right, balance diff 0

    int current_right_balance = 0;
    for (int k = 1; k <= n; ++k) {
        // Jar `n+k` is the `k`-th jar from the left end of the right segment.
        // Its index in `a` is `n+k-1`.
        if (a[n + k - 1] == 1) {
            current_right_balance++;
        } else {
            current_right_balance--;
        }
        // Similar to left side, store minimum `k`.
        if (right_balance_to_k.find(current_right_balance) == right_balance_to_k.end()) {
            right_balance_to_k[current_right_balance] = k;
        }
    }

    int min_jars_eaten = 2 * n; // Max possible jars eaten

    // Iterate through all possible `k_L` (jars eaten from left) and their `left_balance`
    for (auto const& [lb_diff, k_L] : left_balance_to_k) {
        // If we eat `k_L` jars from the left, the remaining jars have a balance of
        // `initial_balance - lb_diff`.
        // We need to eat `k_R` jars from the right such that their balance `rb_diff`
        // makes the total remaining balance 0.
        // So, `initial_balance - lb_diff - rb_diff = 0`
        // This means `rb_diff = initial_balance - lb_diff`.
        int target_rb_diff = initial_balance - lb_diff;

        // Check if this `target_rb_diff` can be achieved by eating some `k_R` jars from the right.
        if (right_balance_to_k.count(target_rb_diff)) {
            int k_R = right_balance_to_k[target_rb_diff];
            min_jars_eaten = std::min(min_jars_eaten, k_L + k_R);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

