        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> current_a = a;
    std::vector<int> next_a(n);
    next_a[0] = current_a[0];
    next_a[n - 1] = current_a[n - 1];

    std::vector<int> diff_indices;
    for (int i = 1; i < n - 1; ++i) {
        int sum = current_a[i - 1] + current_a[i] + current_a[i + 1];
        next_a[i] = (sum >= 2) ? 1 : 0;
        if (next_a[i] != current_a[i]) {
            diff_indices.push_back(i);
        }
    }

    if (diff_indices.empty()) {
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    int max_k = 0;
    for (int idx : diff_indices) {
        int val = current_a[idx];
        int k_val = 0;
        if (val == 0) { // 0 -> 1
            // Find longest sequence of 0s to the left ending at idx-1
            int left_len = 0;
            for (int i = idx - 1; i >= 0; --i) {
                if (current_a[i] == 0) {
                    left_len++;
                } else {
                    break;
                }
            }
            // Find longest sequence of 0s to the right starting at idx+1
            int right_len = 0;
            for (int i = idx + 1; i < n; ++i) {
                if (current_a[i] == 0) {
                    right_len++;
                } else {
                    break;
                }
            }
            k_val = std::min(left_len, right_len) + 1;
        } else { // 1 -> 0
            // Find longest sequence of 1s to the left ending at idx-1
            int left_len = 0;
            for (int i = idx - 1; i >= 0; --i) {
                if (current_a[i] == 1) {
                    left_len++;
                } else {
                    break;
                }
            }
            // Find longest sequence of 1s to the right starting at idx+1
            int right_len = 0;
            for (int i = idx + 1; i < n; ++i) {
                if (current_a[i] == 1) {
                    right_len++;
                } else {
                    break;
                }
            }
            k_val = std::min(left_len, right_len) + 1;
        }
        max_k = std::max(max_k, k_val);
    }

    std::cout << max_k << "\n";

    std::vector<int> final_a = a;
    for (int i = 1; i < n - 1; ++i) {
        if (final_a[i] == 0) { // Check if it should become 1
            // Check if there's a 1 within max_k distance to the left and right
            bool left_one = false;
            for (int j = std::max(0, i - max_k); j < i; ++j) {
                if (final_a[j] == 1) {
                    left_one = true;
                    break;
                }
            }
            bool right_one = false;
            for (int j = i + 1; j <= std::min(n - 1, i + max_k); ++j) {
                if (final_a[j] == 1) {
                    right_one = true;
                    break;
                }
            }
            if (left_one && right_one) {
                final_a[i] = 1;
            }
        } else { // Check if it should become 0
            // Check if there's a 0 within max_k distance to the left and right
            bool left_zero = false;
            for (int j = std::max(0, i - max_k); j < i; ++j) {
                if (final_a[j] == 0) {
                    left_zero = true;
                    break;
                }
