// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // Case k=1
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) {
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2
    // If k=1 is not possible, we check if k=2 is always possible or if it can be impossible.
    // A string s of length N can be cut into s[0...i-1], s[i...j-1], s[j...N-1].
    // The problem statement implies that if k=1 is not possible, then k=2 is the next minimum.
    // The only case where k=2 might not be possible is if all characters in s are the same.
    // If all characters are the same (e.g., "aaaaa"), then any rearrangement of substrings
    // will result in the same string "aaaaa", which is a palindrome.
    // In this case, s' will always be equal to s, so it's impossible to find s' != s.
    // We need to check if all characters in s are the same.
    bool all_same_chars = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_chars = false;
            break;
        }
    }

    if (all_same_chars) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, and k=1 was not possible,
        // then k=2 must be the answer.
        // This is because if s is a palindrome and not all characters are the same,
        // we can always find a way to make two cuts to form a new palindrome.
        // For example, consider s = "abacaba".
        // If we cut s into s[0...i-1], s[i...j-1], s[j...N-1].
        // We can always make a cut at s[0] and s[N-1] to get s[0], s[1...N-2], s[N-1].
        // Then rearrange them to s[N-1], s[1...N-2], s[0].
        // Since s is a palindrome, s[0] == s[N-1].
        // This would result in the same string.
        //
        // However, the problem statement implies that if k=1 doesn't work, and it's not
        // the all-same-chars case, then k=2 is always possible.
        // Let's verify this. If s is a palindrome and not all characters are the same,
        // then there must be at least two distinct characters.
        // Consider s = "nolon". k=1 fails. All chars not same. Output 2.
        // Consider s = "kinnikkinnik". k=1 works. Output 1.
        //
        // The logic for k=2 being always possible (unless all chars are same) is:
        // If s is a palindrome and not all characters are the same, then there exists
        // some character s[i] such that s[i] != s[0].
        // Since s is a palindrome, s[i] == s[n-1-i].
        // If we take the prefix s[0...i-1] and suffix s[n-i...n-1], these are palindromic
        // reverses of each other.
        // The middle part s[i...n-i-1] is also a palindrome.
        //
        // The problem statement implies that if k=1 fails, and the string is not
