#include <string>
#include <vector>
#include <algorithm> // For std::min/max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    // prefix_counts[char_idx][i] stores the count of char_idx ('x', 'y', or 'z')
    // in the prefix s[0...i-1].
    // char_idx 0 for 'x', 1 for 'y', 2 for 'z'.
    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        // Adjust to 0-based indexing for prefix_counts
        // Substring is s[l-1 ... r-1]
        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a0 = elements[0].value;
    long long a1 = elements[1].value;
    long long an_2 = elements[n - 2].value;
    long long an_1 = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., all 1s).
    // min_f = a0 + a1
    // max_f = an_2 + an_1
    // goodness = (an_2 + an_1) - (a0 + a1)
    long long goodness1 = (an_2 + an_1) - (a0 + a1);

    // Case 2: Partition such that a0 and an_1 are in different subsequences.
    // This means a0 is in S1, an_1 is in S2 (WLOG).
    // The minimum possible f value is min(a0 + a1, a0 + an_1 + h, a1 + an_1 + h, ...)
    // The maximum possible f value is max(an_2 + an_1, a0 + an_1 + h, ...)
    //
    // Consider the partition where a0 is in S1, and all other elements are in S2.
    // min_f:
    //   - If S1 has other elements: a0 + a_k (k != 0)
    //   - If S2 has other elements: a_k + a_j (k,j != 0)
    //   - If a0 in S1, a_k in S2: a0 + a_k + h
    // The smallest possible sum is a0 + a1.
    // The smallest possible sum with h is a0 + a1 + h.
    //
    // If a0 is in S1, and all other elements are in S2:
    // Pairs within S1: None (if S1 only has a0)
    // Pairs within S2: (a1, a2), ..., (an_2, an_1). Min is a1+a2, Max is an_2+an_1.
    // Pairs across S1 and S2: (a0, a1), ..., (a0, an_1). Min is a0+a1+h, Max is a0+an_1+h.
    //
    // So, min_f = min(a1 + a2, a0 + a1 + h)
    // max_f = max(an_2 + an_1, a0 + an_1 + h)
    //
    // This is the partition where a0 is in one group, and all others are in the other.
    // The minimum f value will be min(a0 + a1 + h, a1 + a2).
    // The maximum f value will be max(a0 + an_1 + h, an_2 + an_1).
    //
    // Let's analyze the specific partition: a0 in S1, a1, ..., an-1 in S2.
    // Values of f:
    //   - a_i + a_j for i,j in {1, ..., n-1} (same group)
    //   - a0 + a_i + h for i in {1, ..., n-1} (different groups)
    //
    // min_f_val = min(a1 + a2, a0 + a1 + h)
    // max_f_val = max(an_2 + an_1, a0 + an_1 + h)
    //
    // Goodness for this partition: max_f_val - min_f_val
    //
    // This is one specific partition. What if a0 and an_1 are in different groups?
    // Then a0 + an_1 + h is definitely one of the f values.
    //
    // The minimum possible f value is `a0 + a1` (if a0, a1 same group) or `a0 + a1 + h` (if a0, a1 different group).
    // The maximum possible f value is `an_2 + an_1` (if an_2, an_1 same group) or `an_2 + an_1 + h` (if an_2, an_1 different group).
    //
    // Consider the case where a0 and an_1 are in different groups.
    // Let a0 be in S1, an_1 in S2.
    //
    // The minimum possible f value is `min(a0 + a_k, a_j + an_1, a_k + a_j + h)`
    // The maximum possible f value is `max(a0 + a_k, a_j + an_1, a_k + a_j + h)`
    //
    // The smallest possible sum is `a0 + a1`.
    // The largest possible sum is `an_2 + an_1`.
    //
    // If a0 and an_1 are in different groups, then `a0 + an_1 + h` is one of the values.
    //
    // The minimum possible value of `f` is `min(a0 + a1, a0 + a1 + h)`.
    // The maximum possible value of `f` is `max(an_2 + an_1, an_2 + an_1 + h)`.
    //
    // If `a0` and `an_1` are in different groups, then `a0 + an_1 + h` is one of the values.
    //
    // Let's consider two main strategies:
    // Strategy A: All elements in one group.
    //   min_f = a0 + a1
    //   max_f = an_2 + an_1
    //   goodness = (an_2 + an_1) - (a0 + a1)
    //   Partition: all 1s.
    //
    // Strategy B: a0 in group 1, all others in group 2.
    //   min_f = min(a1 + a2, a0 + a1 + h)
    //   max_f = max(an_2 + an_1, a0 + an_1 + h)
    //   goodness = max_f - min_f
    //   Partition: a0 gets 1, others get 2.
    //
    // Strategy C: an_1 in group 1, all others in group 2.
    //   min_f = min(a0 + a1, a0 + an_1 + h)
    //   max_f = max(an_3 + an_2, a_0 + an_1 + h) (if n >= 3)
    //   If n=2, a0 in S1, a1 in S2. min_f = a0+a1+h, max_f = a0+a1+h. Goodness = 0.
    //   This is covered by Strategy B if n=2.
    //   If n=2, a0 in S1, a1 in S2. min_f = a0+a1+h, max_f = a0+a1+h. Goodness = 0.
    //   If n=2, a0, a1 in S1. min_f = a0+a1, max_f = a0+a1. Goodness = 0.
    //   So for n=2, goodness is always 0.
    //   The code below handles n=2 correctly.
    //   If n=2, a0=elements[0].value, a1=elements[1].value.
    //   goodness1 = (a0+a1) - (a0+a1) = 0.
    //   goodness2: a0 in S1, a1 in S2.
    //     min_f = min(a1+a2 (not exist), a0+a1+h) = a0+a1+h
    //     max_f = max(an_2+an_1 (not exist), a0+an_1+h) = a0+a1+h
    //     goodness2 = 0.
    //   So for n=2, both strategies give 0.

    long long min_goodness = goodness1;
    std::vector<int> result_partition(n);
    for (int i = 0; i < n; ++i) {
        result_partition[elements[i].original_index] = 1;
    }

    // Strategy B: a0 in group 1, all others in group 2.
    // This means elements[0] is in group 1, elements[1]...elements[n-1] are in group 2.
    //
    // The values of f are:
    // 1. a_i + a_j for i,j in {1, ..., n-1} (both in group 2)
    //    Min of these: a1 + a2 (if n >= 3)
    //    Max of these: an_2 + an_1 (if n >= 3)
    // 2. a0 + a_i + h for i in {1, ..., n-1} (a0 in group 1, a_i in group 2)
    //    Min of these: a0 + a1 + h
    //    Max of these: a0 + an_1 + h
    //
    // If n=2: a0 in group 1, a1 in group 2.
    //   Only one pair: (a0, a1). They are in different groups.
    //   f(a0, a1) = a0 + a1 + h.
    //   min_f = a0 + a1 + h, max_f = a0 + a1 + h. Goodness = 0.
    // This is correctly handled by the general logic if we consider edge cases for min/max.
    //
    // For n >= 3:
    // min_f_val = std::min(a1 + a2, a0 + a1 + h);
    // max_f_val = std::max(an_2 + an_1, a0 + an_1 + h);
    //
    // For n=2:
    // a0 = elements[0].value, a1 = elements[1].value
    // min_f_val = a0 + a1 + h
    // max_f_val = a0 + a1 + h
    //
    // The logic for n=2 is implicitly handled if we define a2 and an_2 carefully.
    // If n=2, a2 doesn't exist. a1+a2 would be problematic.
    // an_2 doesn't exist. an_2+an_1 would be problematic.
    //
    // Let's handle n=2 explicitly for clarity, though it seems to be 0 for both cases.
    if (n == 2) {
        std::cout << 0 << std::endl;
        std::cout << "1 1" << std::endl; // Or 1 2, or 2 1, or 2 2. All give 0.
        return 0;
    }

    // For n >= 3:
    long long min_f_val_B = std::min(a1 + elements[2].value, a0 + a1 + h);
    long long max_f_val_B = std::max(an_2 + an_1, a0 + an_1 + h);
    long long goodness2 = max_f_val_B - min_f_val_B;

    if (goodness2 < min_goodness) {
        min_goodness = goodness2;
        result_partition[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            result_partition[elements[i].original_index] = 2;
        }
    }

    // Strategy C: an_1 in group 1, all others in group 2.
    // This means elements[n-1] is in group 1, elements[0]...elements[n-2] are in group 2.
    //
    // The values of f are:
    // 1. a_i + a_j for i,j in {0, ..., n-2} (both in group 2)
    //    Min of these: a0 + a1
    //    Max of these: an_3 + an_2 (if n >= 3)
    // 2. an_1 + a_i + h for i in {0, ..., n-2} (an_1 in group 1, a_i in group 2)
    //    Min of these: an_1 + a0 + h
    //    Max of these: an_1 + an_2 + h
    //
    // For n >= 3:
    long long min_f_val_C = std::min(a0 + a1, a0 + an_1 + h);
    long long max_f_val_C = std::max(elements[n-3].value + an_2, an_2 + an_1 + h);
    long long goodness3 = max_f_val_C - min_f_val_C;

    if (goodness3 < min_goodness) {
        min_goodness = goodness3;
        result_partition[elements[n-1].original_index] = 1;
        for (int i = 0; i < n - 1; ++i) {
            result_partition[elements[i].original_index] = 2;
        }
    }

    std::cout << min_goodness << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << result_partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

