        // And also, the total span covered by this head must be at most 2T.
        // If h[i] covers p[p_idx], it can also cover tracks up to p[p_idx] + 2T.
        // But it's constrained by its own reach: h[i] + T.
        // So the rightmost track it can cover is min(h[i] + T, p[p_idx] + 2T).
        // Let's call this `current_head_max_reach`.
        // This is the maximum track index that this head can cover, starting from p[p_idx].
        long long current_head_max_reach = std::min(h[i] + T, p[p_idx] + 2 * T);

        // Advance p_idx as long as tracks are covered by the current head.
        while (p_idx < m && p[p_idx] <= current_head_max_reach) {
            p_idx++;
        }
    }
    return p_idx == m;
}

