void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    // The problem guarantees a solution exists.
    // Reversing the permutation always produces a different permutation
    // (unless n=1, but n>=2) and has the same fingerprint.
    // The only case where p_rev == p is if p is a palindrome.
    // For example, [1,2,1] is a palindrome, but it's not a permutation.
    // A permutation [p_1, ..., p_n] can only be a palindrome if p_i = p_{n-i+1} for all i.
    // For example, if n=3, p=[1,2,3], p_rev=[3,2,1].
    // If n=4, p=[1,2,3,4], p_rev=[4,3,2,1].
    // A permutation cannot be a palindrome unless n=1 (which is not allowed)
    // because if p_i = p_{n-i+1}, then for distinct i and j, p_i and p_j must be distinct.
    // If n is odd, say n=2k+1, then p_{k+1} = p_{n-(k+1)+1} = p_{k+1}.
    // If n is even, say n=2k, then p_i = p_{n-i+1} means p_1=p_n, p_2=p_{n-1}, etc.
    // But all elements in a permutation must be distinct.
    // So p_1 cannot be equal to p_n unless n=1.
    // Therefore, p_rev is always different from p for n >= 2.

    // Construct p_rev
    std::vector<int> p_rev(n);
    for (int i = 0; i < n; ++i) {
        p_rev[i] = p[n - 1 - i];
    }

    // Output p_rev
    for (int i = 0; i < n; ++i) {
        std::cout << p_rev[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

