int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, d;
        std::cin >> n >> d;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        int haybales_in_pile1 = a[0];

        for (int i = 1; i < n; ++i) { // Iterate through piles from 2 to n (index 1 to n-1)
            int pile_idx = i; // 0-indexed pile index
            int distance_to_pile1 = pile_idx; // Number of moves needed

            if (distance_to_pile1 <= d) { // If we have enough days to move at least one haybale from this pile
                int haybales_available = a[pile_idx];

                // Calculate how many haybales we can move from this pile
                // Each haybale costs 'distance_to_pile1' days.
                // We have 'd' days remaining.
                int max_haybales_to_move = d / distance_to_pile1;

                int haybales_to_take = std::min(haybales_available, max_haybales_to_move);

                haybales_in_pile1 += haybales_to_take;
                d -= haybales_to_take * distance_to_pile1;
            }
            // If distance_to_pile1 > d, we cannot move any haybale from this pile
            // or any further piles, so we can stop.
            if (d == 0) {
                break;
            }
        }
        std::cout << haybales_in_pile1 << std::endl;
    }
    return 0;
}

