        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this specific element,
        // but the presence of 1s and -1s from previous elements is still important for future elements.

        // Update has_pos_one and has_neg_one for elements a[i] that are now "available"
        // to modify subsequent elements a[j] where j > i.
        // This is implicitly handled by the loop structure.
        // The `has_pos_one` and `has_neg_one` flags track if there was *any* 1 or -1
        // in a[0...i-1].
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }

    std::cout << "YES\n";
}

