void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n);

    int color_for_half_T = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (2 * a[i] < T) {
            p[i] = 0; // Smaller than T/2, assign to white (0)
        } else if (2 * a[i] > T) {
            p[i] = 1; // Larger than T/2, assign to black (1)
        } else { // a[i] == T/2
            p[i] = color_for_half_T;
            color_for_half_T = 1 - color_for_half_T; // Alternate color for T/2 elements
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

