    std::vector<bool> row_taken(n + 1, false);
    std::vector<bool> col_taken(m + 1, false);

    for (int i = 1; i <= n; ++i) {
        for (int j = 1; j <= m; ++j) {
            int val;
            std::cin >> val;
            if (val == 1) {
                row_taken[i] = true;
                col_taken[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (int i = 1; i <= n; ++i) {
        if (!row_taken[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 1; j <= m; ++j) {
        if (!col_taken[j]) {
            available_cols++;
        }
    }

    int moves_possible = std::min(available_rows, available_cols);

    if (moves_possible % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

