int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos = -1, it means the frog is at cell 0.
                             // If last_r_pos = i, it means the frog is at cell i.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' or start was at last_r_pos.
                // The gap is (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // Or, more simply, the distance from last_r_pos to i+1 is (i+1) - last_r_pos.
                // If last_r_pos is -1 (start at 0), distance is (i+1) - 0 = i+1.
                // If last_r_pos is some j, distance is (i+1) - j.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1) + 1); // Distance from last_r_pos+1 to i+1
                last_r_pos = i;
            }
        }

        // After iterating through the string, consider the jump from the last 'R'
        // (or from 0 if no 'R's) to n+1.
        // The last 'R' was at index last_r_pos (0-indexed).
        // The cell it represents is last_r_pos + 1 (1-indexed).
        // We need to jump from last_r_pos + 1 to n + 1.
        // The distance is (n + 1) - (last_r_pos + 1) = n - last_r_pos.
        max_gap = std::max(max_gap, (n + 1) - (last_r_pos + 1) + 1);

        std::cout << max_gap << "\n";
    }
    return 0;
}

