#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams 'k' is limited by three factors:
        // 1. The number of coders: k <= c
        // 2. The number of mathematicians: k <= m
        // 3. The total number of students: 3 * k <= c + m + x
        //
        // From (1) and (2), k <= min(c, m).
        // From (3), k <= (c + m + x) / 3.
        //
        // Combining these, k <= min(c, m, (c + m + x) / 3).
        // This is because if we form k teams, we need at least k coders and k mathematicians.
        // The remaining (c - k) coders, (m - k) mathematicians, and x non-specialized students
        // must be enough to fill the remaining 2*k slots in the k teams.
        // The total number of students available is c + m + x.
        // Each team needs 3 students. So, k teams need 3*k students.
        // Thus, 3*k <= c + m + x.
        //
        // The minimum of these three values gives the maximum possible number of teams.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 1; // Cost for a 1-stair staircase
        long long k = 1;            // Represents the 'n' in 2^n - 1
        while (true) {
            if (x >= current_cost) {
                x -= current_cost;
                count++;
                k = k * 2 + 1; // Next staircase size is 2k+1
                current_cost = k * (k + 1) / 2; // Cost for a k-stair staircase
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

