    for (int i = 1; i < n; ++i) {
        // The area of the triangle from the apex to the i-th cut (x_i)
        // should be i times the area of a single piece.
        // Area_total = h/2
        // Area_piece = Area_total / n = (h/2) / n = h / (2n)
        // Area_x_i = i * Area_piece = i * h / (2n)
        //
        // For a triangle with height x and base b', by similar triangles:
        // b' / x = 1 / h  => b' = x / h
        // Area_x = (1/2) * b' * x = (1/2) * (x/h) * x = x^2 / (2h)
        //
        // Equating the two expressions for Area_x_i:
        // x_i^2 / (2h) = i * h / (2n)
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)

        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

