    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between left and right pointers.
    // Example: k=2, n=3. right=3.
    // p_1 = 1 (left)
    // p_2 = 3 (right) -> diff = |1-3|=2
    // p_3 = 2 (left) -> diff = |3-2|=1
    // Permutation: 1 3 2. Differences: {2, 1}. Count = 2. Correct.

    // Example: k=1, n=3. right=2.
    // p_1 = 1 (left)
    // p_2 = 2 (right) -> diff = |1-2|=1
    // Remaining numbers: 3.
    // p_3 = 3.
    // Permutation: 1 2 3. Differences: {1, 1}. Count = 1. Correct.

    // Example: k=2, n=5. right=3.
    // p_1 = 1 (left)
    // p_2 = 3 (right) -> diff = |1-3|=2
    // p_3 = 2 (left) -> diff = |3-2|=1
    // Remaining numbers: 4, 5.
    // p_4 = 4
    // p_5 = 5
    // Permutation: 1 3 2 4 5. Differences: {2, 1, 2, 1}. Distinct: {1, 2}. Count = 2. Correct.

    for (int i = 0; i < k + 1; ++i) {
        if (i % 2 == 0) { // Even index, take from left
            std::cout << left++;
        } else { // Odd index, take from right
            std::cout << right--;
        }
        std::cout << (i == n - 1 ? "" : " ");
    }

    // After generating k+1 elements, we have used numbers from 1 to k+1.
    // The remaining numbers are k+2, k+3, ..., n.
    // To avoid introducing new distinct differences, we can append these numbers in increasing order.
    // This will only create differences of 1.
    // Since we already generated 1 as a difference (unless k=0, but k>=1), this is fine.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << i << (i == n ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

