    // Find the rightmost peak
    int p = n - 1;
    while (p > 0 && a[p-1] >= a[p]) {
        p--;
    }
    // Now a[p...n-1] is non-decreasing.
    // If p is 0, the whole array is non-decreasing.

    // Find the rightmost valley before the peak
    int q = p;
    while (q > 0 && a[q-1] <= a[q]) {
        q--;
    }
    // Now a[q...p-1] is non-increasing.
    // If q is 0, then a[0...p-1] is non-increasing.

    // The prefix to remove is of length q.
    // The remaining array is a[q...n-1].
    std::cout << q << std::endl;
}

