#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[k] stores the 0-indexed position of k in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. Its length is 1.
        // min_idx = pos[1], max_idx = pos[1].
        // current_max_idx - current_min_idx + 1 = 1.
        // This is always true.
        if (m == 1) {
            result += '1';
        } else {
            // For m > 1, we need to expand the current segment [min_idx, max_idx]
            // to include 'm'.
            // The number 'm' is at pos[m].
            // We need to update current_min_idx and current_max_idx
            // to cover the range from 1 to m.
            // This means the new segment must span from min(current_min_idx, pos[m])
            // to max(current_max_idx, pos[m]).
            current_min_idx = std::min(current_min_idx, pos[m]);
            current_max_idx = std::max(current_max_idx, pos[m]);

            // A number m is beautiful if the segment p[current_min_idx ... current_max_idx]
            // contains all numbers from 1 to m, and its length is exactly m.
            // The length of this segment is (current_max_idx - current_min_idx + 1).
            // If this length is equal to m, then it means all numbers from 1 to m
            // are located within this contiguous block of indices, and no other numbers
            // (specifically, no numbers greater than m) are included in this block
            // that would make its length greater than m.
            // Since we are building up from 1, 2, ..., m, we are guaranteed that
            // all numbers from 1 to m are present in p[current_min_idx ... current_max_idx].
            // The only condition left is that its length must be exactly m.
            if (current_max_idx - current_min_idx + 1 == m) {
                result += '1';
            } else {
                result += '0';
            }
        }
    }
    std::cout << result << "\n";
}

