int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        double d;
        std::cin >> d;

        if (d == 0.0) {
            std::cout << "Y 0.000000000 0.000000000\n";
        } else if (d < 4.0) {
            std::cout << "N\n";
        } else {
            // Discriminant: D = d^2 - 4d
            // For real solutions, D >= 0. This is true for d >= 4.
            // a = (d + sqrt(D)) / 2
            // b = (d - sqrt(D)) / 2
            double discriminant = d * d - 4.0 * d;
            double sqrt_discriminant = std::sqrt(discriminant);

            double a = (d + sqrt_discriminant) / 2.0;
            double b = (d - sqrt_discriminant) / 2.0;

            // Since d >= 4, d^2 >= 4d, so d^2 - 4d >= 0.
            // Also, d + sqrt(d^2 - 4d) >= 0.
            // For b, we need d - sqrt(d^2 - 4d) >= 0.
            // This is equivalent to d >= sqrt(d^2 - 4d).
            // Squaring both sides (both are non-negative):
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // d >= 0.
            // Since d is given as non-negative, both a and b will be non-negative.

            std::cout << "Y " << std::fixed << std::setprecision(9) << a << " " << b << "\n";
        }
    }
    return 0;
}

#include <iostream>
