int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Ensure the median element itself is s
    operations += std::abs(a[median_idx] - s);

    // Elements to the left of the median must be <= s
    // If an element a[i] < s, it's fine.
    // If an element a[i] > s, it must be decreased to s.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Elements to the right of the median must be >= s
    // If an element a[i] > s, it's fine.
    // If an element a[i] < s, it must be increased to s.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate max_left_len: the maximum length of a strictly increasing prefix starting from 0.
    // max_left_len[i] = max length of a strictly increasing sequence ending at index i,
    // where the sequence values are 0, 1, 2, ..., max_left_len[i]-1.
    // This means a[j] >= j for j from 0 to i.
    // More precisely, a[j] must be at least j.
    // So, max_left_len[i] is the maximum k such that a[0] >= 0, a[1] >= 1, ..., a[k-1] >= k-1.
    // We can find the first index `i` where `a[i] < i`.
    // All elements before this index `i` (i.e., `a[0]` to `a[i-1]`) satisfy `a[j] >= j`.
    // The length of this prefix is `i`.
    int max_left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            break;
        }
        max_left_len = i + 1;
    }

    // Calculate max_right_len: the maximum length of a strictly decreasing suffix ending at 0.
    // max_right_len[i] = max length of a strictly decreasing sequence starting at index i,
    // where the sequence values are max_right_len[i]-1, ..., 2, 1, 0.
    // This means a[j] >= (n-1-j) for j from i to n-1.
    // We can find the first index `i` (from right) where `a[i] < (n-1-i)`.
    // All elements after this index `i` (i.e., `a[i+1]` to `a[n-1]`) satisfy `a[j] >= (n-1-j)`.
    // The length of this suffix is `n-1-i`.
    int max_right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1 - i)) {
            break;
        }
        max_right_len = (n - 1 - i) + 1;
    }

    // If the sum of these two lengths is greater than or equal to n,
    // it means there's an overlap or they meet perfectly.
    // This implies there's at least one index k that can serve as a peak.
    // Specifically, if max_left_len + max_right_len >= n,
    // it means there is some index `i` such that `a[i] >= i` AND `a[i] >= (n-1-i)`.
    // This `i` can be the peak `k`.
    // The condition `max_left_len + max_right_len >= n` is equivalent to
    // `max_left_len >= n - max_right_len`.
    // `n - max_right_len` is the starting index of the valid right suffix.
    // So, if `max_left_len` (which is the count of elements from left)
    // extends to or past the start of the valid right suffix, then there's an overlap.
    if (max_left_len + max_right_len >= n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

