#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a box can be the special box
// Parameters:
// A, B, C, D: initial counts of toys in boxes 1, 2, 3, 4
// target_box: the box we are checking (0-indexed: 0 for R1, 1 for R2, 2 for R3, 3 for R4)
//
// The logic is based on analyzing the parity of negative numbers and the possibility of
// controlling the magnitude of the final product.
//
// Let N_neg = A + B (total negative numbers)
// Let N_mag_gt1 = A + D (total numbers with magnitude >= 1)
// Let N_mag_lt1 = B + C (total numbers with magnitude < 1)
//
// The final product's sign depends on N_neg:
// If N_neg is even, final product is positive.
// If N_neg is odd, final product is negative.
//
// The final product's magnitude relative to 1 depends on N_mag_gt1 and N_mag_lt1:
// If N_mag_gt1 = 0, then all numbers have magnitude < 1. The product will have magnitude < 1.
// If N_mag_lt1 = 0, then all numbers have magnitude >= 1. The product will have magnitude >= 1.
// If both N_mag_gt1 > 0 and N_mag_lt1 > 0, then the magnitude can be controlled.
//   - If N_mag_gt1 = 1 and N_mag_lt1 = 1, and total toys N=2, then product can be <1 or >=1.
//     e.g., 0.5 * 2 = 1 (can be >=1)
//     e.g., 0.1 * 2 = 0.2 (can be <1)
//     e.g., 0.5 * 1.5 = 0.75 (can be <1)
//     e.g., 0.8 * 1.5 = 1.2 (can be >=1)
//     So if N_mag_gt1 > 0 and N_mag_lt1 > 0, the magnitude can be controlled to be <1 or >=1.
//     This is because we can choose to multiply numbers with magnitude < 1 first to make a very small number,
//     then multiply by numbers with magnitude >= 1. Or vice versa.
//     The only exception is if N_mag_gt1 = 1 and N_mag_lt1 = 1, and N=2.
//     In this case, the product is fixed. If one is from R2/R3 and other from R1/R4,
//     the product can be <1 or >=1.
//     Example: 0.5 * 2 = 1.0 (R4 if positive, R1 if negative)
//     Example: 0.5 * 1.5 = 0.75 (R3 if positive, R2 if negative)
//     So if N_mag_gt1 > 0 and N_mag_lt1 > 0, the magnitude can always be controlled.

bool can_be_special(long long A, long long B, long long C, long long D, int target_box) {
    long long N = A + B + C + D;

    if (N == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // If only one toy, it's the special toy.
    if (N == 1) {
        if (A == 1 && target_box == 0) return true;
        if (B == 1 && target_box == 1) return true;
        if (C == 1 && target_box == 2) return true;
        if (D == 1 && target_box == 3) return true;
        return false;
    }

    long long N_neg = A + B; // Total count of negative numbers
    long long N_pos = C + D; // Total count of positive numbers
    long long N_mag_gt1 = A + D; // Total count of numbers with magnitude >= 1
    long long N_mag_lt1 = B + C; // Total count of numbers with magnitude < 1

    bool final_sign_negative_possible = (N_neg % 2 != 0);
    bool final_sign_positive_possible = (N_neg % 2 == 0);

    bool final_mag_ge1_possible = false;
    bool final_mag_lt1_possible = false;

    if (N_mag_gt1 == 0) { // All numbers have magnitude < 1
        final_mag_lt1_possible = true;
    } else if (N_mag_lt1 == 0) { // All numbers have magnitude >= 1
        final_mag_ge1_possible = true;
    } else { // Both types of magnitudes exist
        // If N_mag_gt1 > 0 and N_mag_lt1 > 0, we can always control the magnitude
        // to be <1 or >=1, unless N=2 and one is from R1/R4 and other from R2/R3.
        // Even in that N=2 case, we can pick values like 0.5 * 2 = 1 (>=1) or 0.5 * 1.5 = 0.75 (<1).
        // So, if both N_mag_gt1 > 0 and N_mag_lt1 > 0, both outcomes are possible.
        final_mag_ge1_possible = true;
        final_mag_lt1_possible = true;
    }

    // Special case: If there are no positive numbers (C=0, D=0),
    // and N_neg is even, the product will be positive.
    // This means we need to be careful about the magnitude control.
    // If N_neg is even and N_pos = 0, then the product is positive.
    // If N_mag_gt1 = 0 (i.e., A=0), then all numbers are from B. Product is <1.
    // If N_mag_lt1 = 0 (i.e., B=0), then all numbers are from A. Product is >=1.
    // If A>0 and B>0, and N_neg is even, then we can control magnitude.
    // Example: A=1, B=1. N_neg=2 (even). Product is positive.
    //   -3 * -0.5 = 1.5 (R4)
    //   -3 * -0.1 = 0.3 (R3)
    // So, the general rule for magnitude control holds even if N_pos = 0,
    // as long as both A > 0 and B > 0.

    // Check for target_box
    if (target_box == 0) { // R1: (-inf, -1]
        return final_sign_negative_possible && final_mag_ge1_possible;
    } else if (target_box == 1) { // R2: (-1, 0)
        return final_sign_negative_possible && final_mag_lt1_possible;
    } else if (target_box == 2) { // R3: (0, 1)
        return final_sign_positive_possible && final_mag_lt1_possible;
    } else if (target_box == 3) { // R4: [1, inf)
        return final_sign_positive_possible && final_mag_ge1_possible;
    }
    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::cout << (can_be_special(A, B, C, D, 0) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 1) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 2) ? "Ya" : "Tidak");
        std::cout << " " << (can_be_special(A, B, C, D, 3) ? "Ya" : "Tidak") << "\n";
    }
    return 0;
}

