    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    int count = 0;
    int left = 0; // Pointer for elements to be "beaten" (original array elements)
    int right = 0; // Pointer for elements to "beat" (permutation array elements)

    while (right < n) {
        // If a[right] is greater than a[left], we can form a pair
        // where a[right] replaces a[left] and a[right] > a[left].
        // We increment both pointers and the count.
        if (a[right] > a[left]) {
            count++;
            left++;
            right++;
        } else {
            // If a[right] is not greater than a[left], it means a[right]
            // is either equal to a[left] or smaller.
            // In this case, a[right] cannot beat a[left].
            // We try the next larger element from the sorted array to beat a[left].
            // So, we only increment the right pointer.
            right++;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
