#include <numeric>
#include <algorithm>
#include <map>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<long long> b(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    std::sort(a.begin(), a.end());

    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_indexed[i] = {b[i], i};
    }

    std::sort(b_indexed.begin(), b_indexed.end());

    std::vector<long long> a_prime(m);
    std::vector<long long> f_values(m);

    // Calculate F(n, k) = n / (k+1) for each pair (a_i, b_i)
    // We want to maximize sum(a_i / (b_i + 1))
    // To do this, we sort A in ascending order and B in ascending order.
    // Then we pair the largest A with the largest B, second largest A with second largest B, etc.
    // This is because F(n, k) is increasing in n and decreasing in k.
    // So, to maximize sum(A_i / (B_i + 1)), we want to pair large A_i with small (B_i + 1)
    // which means large A_i with small B_i.
    // However, the problem statement implies A_i >= B_j for all i, j.
    // The formula F(n, k) = n / (k+1) is derived from E[min(S)] = (n+1)/(k+1).
    // The problem statement uses F(n, k) as the expectation of the minimal element.
    // The standard result for the expectation of the minimum of k elements chosen from {1, ..., n} is (n+1)/(k+1).
    // Let's assume F(n, k) = (n+1)/(k+1).
    // We want to maximize sum((A'_i + 1) / (B_i + 1)).
    // This is a rearrangement inequality problem.
    // To maximize sum(X_i * Y_i), if X and Y are sequences, we sort both in the same order.
    // Here, we have (A'_i + 1) and 1/(B_i + 1).
    // Let X_i = A'_i + 1 and Y_i = 1/(B_i + 1).
    // To maximize sum(X_i * Y_i), we should sort X and Y in the same order.
    // A'_i + 1 should be sorted in ascending order (so A'_i in ascending order).
    // 1/(B_i + 1) should be sorted in ascending order. This means B_i + 1 should be sorted in descending order,
    // which means B_i should be sorted in descending order.
    // So, we sort A in ascending order and B in descending order.
    // Then we pair a[i] with b[i] (after sorting).

    // Sort A in ascending order (already done).
    // Sort B in descending order.
    std::sort(b.rbegin(), b.rend());

    // Now, pair a[i] with b[i] to maximize sum((a[i]+1)/(b[i]+1)).
    // The problem asks for the rearranged array A'.
    // We need to reconstruct A' based on the original indices of B.

    // Create pairs of (B_value, original_index) and sort by B_value in descending order.
    std::vector<std::pair<long long, int>> b_original_indexed(m);
    for (int i = 0; i < m; ++i) {
        b_original_indexed[i] = {b_indexed[i].first, b_indexed[i].second};
    }
    std::sort(b_original_indexed.rbegin(), b_original_indexed.rend());

    // The sorted 'a' array (ascending) is a[0], a[1], ..., a[m-1].
    // The sorted 'b' array (descending) is b_original_indexed[0].first, b_original_indexed[1].first, ...
    // We want to assign a[i] to the position corresponding to b_original_indexed[i].second.
    // So, a_prime[b_original_indexed[i].second] = a[i].
    for (int i = 0; i < m; ++i) {
        a_prime[b_original_indexed[i].second] = a[i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

