// Function to check if a sub-array is a permutation of length L
// `arr` is the full array, `start_idx` is the starting index of the sub-array,
// `len` is the length of the sub-array.
// Returns true if arr[start_idx ... start_idx + len - 1] is a permutation of 1 to len.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) { // An empty sequence is not a permutation of length > 0
        return false;
    }
    std::vector<bool> seen(len + 1, false); // Use 1-based indexing for values 1 to len
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false; // Value out of range or duplicate
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    // After checking all elements, ensure all numbers from 1 to len were seen
    // and the maximum value is exactly len.
    // The `seen` array check already covers all numbers from 1 to len being present.
    // If max_val is not len, it means some number > len was present (which is caught by val > len)
    // or some number < len was present and len itself was not present (caught by seen[len] being false).
    // So, just checking max_val == len is sufficient if we assume no duplicates and values are positive.
    // However, the `seen` array check is more robust.
    // The `seen` array check ensures all numbers from 1 to `len` are present exactly once.
    // If `max_val` is not `len`, it means either some `val > len` was present (caught by `val > len`)
    // or `len` itself was not present (caught by `seen[len]` being false).
    // So, the `seen` array check is sufficient.
    return true;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums and suffix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    std::vector<std::pair<int, int>> solutions;

    // Iterate through all possible split points l1
    // l1 ranges from 1 to n-1.
    // If l1 is the length of p1, then p1 is a[0...l1-1] and p2 is a[l1...n-1].
    // The length of p2 is l2 = n - l1.
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Optimization: Check if max element in p1 is l1 and max element in p2 is l2
        // If not, it cannot be a permutation.
        // The maximum value in a permutation of length L must be L.
        if (prefix_max[l1 - 1] != l1 || suffix_max[l1] != l2) {
            continue;
        }

        // Check if a[0...l1-1] is a permutation of length l1
        // We need a frequency map or a boolean array to check for duplicates and range.
        std::vector<bool> seen_p1(l1 + 1, false);
        bool p1_is_perm = true;
        for (int i = 0; i < l1; ++i) {
            int val = a[i];
            if (val < 1 || val > l1 || seen_p1[val]) {
                p1_is_perm = false;
                break;
            }
            seen_p1[val] = true;
        }
        if (!p1_is_perm) {
            continue;
        }

        // Check if a[l1...n-1] is a permutation of length l2
        std::vector<bool> seen_p2(l2 + 1, false);
        bool p2_is_perm = true;
        for (int i = 0; i < l2; ++i) {
            int val = a[l1 + i];
            if (val < 1 || val > l2 || seen_p2[val]) {
                p2_is_perm = false;
                break;
            }
            seen_p2[val] = true;
        }
        if (p2_is_perm) {
            solutions.push_back({l1, l2});
        }
    }

    std::cout << solutions.size() << "\n";
    for (const auto& p : solutions) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;
    long long opponent_coins = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_coins += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1 (odd). Opponent takes 1. Chanek takes 1. ...
                // This path is generally worse if N/2 is a good move.

                // Option 2: Take N/2 coins
                // If N is a power of 2 (N = 2^k, k > 0), taking N/2 leaves N/2.
                // The opponent will then face N/2, which is also a power of 2.
                // This leads to a sequence of N/2, N/4, N/8, ...
                // If N is 2^k, Chanek takes 2^(k-1), Opponent takes 2^(k-2), Chanek takes 2^(k-3), ...
                // Chanek gets 2^(k-1) + 2^(k-3) + ...
                // Opponent gets 2^(k-2) + 2^(k-4) + ...
                // Total coins for Chanek: N/2 + N/8 + N/32 + ... = N * (1/2 + 1/8 + 1/32 + ...) = N * ( (1/2) / (1 - 1/4) ) = N * (1/2) / (3/4) = N * 2/3.
                // Total coins for Opponent: N/4 + N/16 + ... = N * (1/4 + 1/16 + ...) = N * ( (1/4) / (1 - 1/4) ) = N * (1/4) / (3/4) = N * 1/3.
                // So if N is a power of 2, Chanek gets 2N/3 and Opponent gets N/3.
                // This is the optimal strategy for Chanek if N is a power of 2.

                // What if N is even but not a power of 2?
                // N = 6.
                // Chanek takes 1. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                // Chanek: 1+2+1 = 4. Opponent: 1+1 = 2.
                // Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1.
                // Chanek: 3+1 = 4. Opponent: 1+1 = 2.
                // In this case, both moves lead to 4 for Chanek.

                // N = 10.
                // Chanek takes 1. N=9. Opponent takes 1. N=8.
                //   Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1.
                //   Chanek: 1+4+1 = 6. Opponent: 1+2+1 = 4.
                // Chanek takes 5. N=5. Opponent takes 1. N=4.
                //   Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                //   Chanek: 5+2+1 = 8. Opponent: 1+1 = 2.
                // Here, taking N/2 is better.

                // The general strategy for Chanek when N is even:
                // If N is even, Chanek can either take 1 or N/2.
                // Taking 1 makes N odd. The opponent will then take 1, making N-2 even.
                // Taking N/2 makes N smaller.
                // The key observation is that if N is even, and N is not a power of 2,
                // then N can be written as N = 2^k * M, where M is odd and M > 1.
                // If Chanek takes N/2, the remaining coins are N/2 = 2^(k-1) * M.
                // If Chanek takes 1, the remaining coins are N-1 (odd). Opponent takes 1, remaining N-2.

                // Consider the case where N is even.
                // If N is a power of 2 (N = 2^k, k >= 1), Chanek should take N/2.
                // This is because taking 1 leaves N-1 (odd), opponent takes 1, leaves N-2.
                // If Chanek takes N/2, he gets N/2. The opponent faces N/2.
                // This continues until N becomes 1.
                // Chanek gets N/2 + N/8 + N/32 + ...
                // Opponent gets N/4 + N/16 + N/64 + ...
                // Total for Chanek: 2N/3. Total for Opponent: N/3.
                // If Chanek takes 1, he gets 1. Opponent faces N-1 (odd). Opponent takes 1. Chanek faces N-2 (even).
                // This seems worse than 2N/3 for large N.

                // If N is even and not a power of 2:
                // N = 2^k * M, where M is odd and M > 1.
                // Example: N = 12 = 2^2 * 3.
                // Chanek takes 1. N=11. Opponent takes 1. N=10.
                //   Chanek takes 5. N=5. Opponent takes 1. N=4. Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1.
                //   Chanek: 1+5+2+1 = 9. Opponent: 1+1+1 = 3.
                // Chanek takes N/2 = 6. N=6.
                //   Opponent takes 3. N=3. Chanek takes 1. N=2. Opponent takes 1. N=1. Chanek takes 1.
                //   Chanek: 6+1+1 = 8. Opponent: 3+1 = 4.
                // In this case, taking 1 is better for Chanek (9 vs 8).

                // This suggests a greedy approach:
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2, take N/2.
                //   If N is even but not a power of 2, take 1.
                // Let's test this hypothesis.

                // How to check if N is a power of 2: (N > 0) && ((N & (N - 1)) == 0)
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N is even, but not a power of 2
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_coins += 1;
                n -= 1;
            } else { // N is even
                // Opponent also plays optimally to maximize their own coins.
                // The logic should be symmetric.
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    opponent_coins += n / 2;
                    n /= 2;
                } else { // N is even, but not a power of 2
                    opponent_coins += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_coins;
}

