void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // We need to find b1, b2, ... such that (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))
    // Let S = current_sum, X = current_xor_sum
    // We need S' = 2 * X'
    // S' = S + b1 + b2 + ...
    // X' = X ^ b1 ^ b2 ^ ...

    // Strategy: Append at most 3 elements.
    // The problem guarantees a solution always exists.
    // A common strategy for such problems is to try to make the XOR sum equal to some value,
    // and then adjust the sum.

    // Let's try to append two elements, b1 and b2.
    // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2).
    // A simple choice for b1 and b2 is to make X ^ b1 ^ b2 equal to some value that simplifies the sum.
    // Consider making X ^ b1 ^ b2 = X. This means b1 ^ b2 = 0, so b1 = b2.
    // If we append b1 and b1, then the new XOR sum is X ^ b1 ^ b1 = X.
    // The new sum is S + b1 + b1 = S + 2*b1.
    // The condition becomes S + 2*b1 = 2 * X.
    // This implies S + 2*b1 = 2*X.
    // This means S must be even, and 2*b1 = 2*X - S.
    // If S is odd, this strategy doesn't work directly with b1=b2.

    // Let's try a different strategy.
    // We want S' = 2 * X'.
    // Let's try to make X' equal to some value that is easy to achieve.
    // For example, if we append one element `b1`, then X' = X ^ b1.
    // The condition becomes S + b1 = 2 * (X ^ b1).
    // This is a single equation with one unknown `b1`.
    // This equation is not always easy to solve for `b1` directly because of the XOR.

    // Consider appending two elements: `X` and `S + X`.
    // New XOR sum: X' = current_xor_sum ^ X ^ (S + X)
    // If current_xor_sum is X, then X' = X ^ X ^ (S + X) = S + X.
    // New sum: S' = current_sum + X + (S + X) = 2*S + 2*X.
    // We need S' = 2 * X'.
    // So, 2*S + 2*X = 2 * (S + X). This is always true!
    // So, if we append `X` and `S + X`, the condition S' = 2*X' is satisfied.
    // The elements to append are `current_xor_sum` and `current_sum + current_xor_sum`.
    // This uses 2 elements.

    // Let's verify this.
    // Initial state: sum = S, xor_sum = X.
    // Append b1 = X, b2 = S + X.
    // New sum S' = S + b1 + b2 = S + X + (S + X) = 2S + 2X.
    // New XOR sum X' = X ^ b1 ^ b2 = X ^ X ^ (S + X) = S + X.
    // Check condition: S' = 2 * X'
    // (2S + 2X) = 2 * (S + X)
    // This is always true.
    // So, we can always append two elements: `current_xor_sum` and `current_sum + current_xor_sum`.

    // The problem asks for at most 3 elements.
    // If the array is already good, we can append 0 elements.
    // If not, we can append 2 elements as described above.

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
    } else {
        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

