#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'a') {
            // If we encounter an 'a', it means this 'a' needs to move past
            // all 'b's to its right.
            // Each 'b' to its right will cause this 'a' to generate
            // a new 'b' and move past it.
            // The number of 'b's this 'a' needs to move past is `count_a`
            // (which represents the number of 'b's that were originally to its right,
            // plus the 'b's generated by 'a's to its right).
            // So, this 'a' contributes `count_a` steps.
            total_steps = (total_steps + count_a) % MOD;
            // After this 'a' moves past all 'b's to its right, it effectively
            // becomes a 'b' for any 'a's further to its left.
            // This is because the operation "ab" -> "bba" effectively
            // moves the 'a' to the right of the 'b', and inserts a new 'b'.
            // The 'a' that was at `s[i]` will eventually be at the end of the string,
            // but it will have generated `count_a` new 'b's.
            // So, for any 'a' to its left, this 'a' (at `s[i]`) and the `count_a`
            // 'b's it generated, will act as `count_a + 1` 'b's.
            // This is equivalent to saying that this 'a' itself becomes a 'b'
            // for the purpose of counting 'b's for 'a's to its left.
            // So, we double `count_a` for the next 'a' to its left.
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'b'
            // If we encounter a 'b', it simply adds to the count of 'b's
            // that an 'a' to its left would need to move past.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

