// Function to convert a long long integer to its parity pattern string
std::string to_parity_pattern(long long n) {
    std::string pattern_str;
    if (n == 0) {
        pattern_str = "0"; // Special case for 0
    } else {
        while (n > 0) {
            if ((n % 10) % 2 == 0) {
                pattern_str += '0';
            } else {
                pattern_str += '1';
            }
            n /= 10;
        }
    }
    std::reverse(pattern_str.begin(), pattern_str.end()); // Digits were added in reverse order
    return pattern_str;
}

// Function to normalize a pattern string to 18 characters
// by padding with '0's from the left.
std::string normalize_pattern(const std::string& s) {
    std::string normalized_s = s;
    if (normalized_s.length() < 18) {
        normalized_s = std::string(18 - normalized_s.length(), '0') + normalized_s;
    }
    return normalized_s;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t;
    std::cin >> t;

    std::map<std::string, int> counts;

    for (int i = 0; i < t; ++i) {
        char type;
        std::cin >> type;

        if (type == '+') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[normalize_pattern(pattern)]++;
        } else if (type == '-') {
            long long a;
            std::cin >> a;
            std::string pattern = to_parity_pattern(a);
            counts[normalize_pattern(pattern)]--;
        } else { // type == '?'
            std::string s;
            std::cin >> s;
            std::cout << counts[normalize_pattern(s)] << "\n";
        }
    }

    return 0;
}

