            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Now, verify if this constructed w can produce the given s.
    // For each s[i], check if it's consistent with w.
    // s_i should be '1' if (w[i-x] == '1' or w[i+x] == '1').
    // s_i should be '0' if (w[i-x] == '0' and w[i+x] == '0').
    for (int i = 0; i < n; ++i) {
        bool possible_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            possible_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            possible_one = true;
        }

        if ((s[i] == '1' && !possible_one) || (s[i] == '0' && possible_one)) {
            // If s[i] is '1' but no '1' from w[i-x] or w[i+x] can make it '1',
            // OR if s[i] is '0' but a '1' from w[i-x] or w[i+x] forces it to be '1'.
            // In either case, it's impossible.
            std::cout << -1 << std::endl;
            return;
        }
    }

    std::cout << w << std::endl;
}

