int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // 'i' represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Calculate energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += prefix_sum[i] * l;

        // Calculate energy for items taken from the right
        // These are w[i]...w[n-1] (if i items taken from left, then n-i items from right)
        // The sum of weights for items w[i]...w[n-1] is prefix_sum[n] - prefix_sum[i]
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Calculate penalty for extra items
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items from left, so (left_count - right_count - 1) extra items from left
            // The last item taken from the left side will be the (right_count + 1)-th item from the left.
            // The remaining (left_count - (right_count + 1)) items from the left will incur Ql penalty.
            // This is equivalent to (left_count - right_count - 1) * Ql
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items from right, so (right_count - left_count - 1) extra items from right
            // The last item taken from the right side will be the (left_count + 1)-th item from the right.
            // The remaining (right_count - (left_count + 1)) items from the right will incur Qr penalty.
            // This is equivalent to (right_count - left_count - 1) * Qr
            current_energy += (right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no penalty is added.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

