int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Declare a 2D vector to store the matrix b.
    // Using long long for elements just in case, though int is sufficient for 10^9.
    std::vector<std::vector<int>> b(n, std::vector<int>(n));

    // Read the matrix b.
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> b[i][j];
        }
    }

    // Declare a vector to store the restored sequence a.
    std::vector<int> a(n);

    // For each element a_i in the sequence:
    // a_i is the bitwise OR of all b_ij where j != i.
    for (int i = 0; i < n; ++i) {
        int current_a_i = 0; // Initialize with 0, as ORing with 0 doesn't change bits.
        for (int j = 0; j < n; ++j) {
            if (i == j) {
                continue; // Skip diagonal elements (b_ii = -1).
            }
            current_a_i |= b[i][j]; // Perform bitwise OR.
        }
        a[i] = current_a_i; // Store the computed a_i.
    }

    // Print the restored sequence a.
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " "); // Print space between numbers, no space after the last.
    }
    std::cout << std::endl; // Newline at the end.

    return 0;
}

