// Function to get prime factors of a number
std::map<long long, int> get_prime_factors(long long n) {
    std::map<long long, int> factors;
    for (long long i = 2; i * i <= n; ++i) {
        while (n % i == 0) {
            factors[i]++;
            n /= i;
        }
    }
    if (n > 1) {
        factors[n]++;
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x < p such that x | p and x % q != 0.
        // Let q = q_1^a_1 * q_2^a_2 * ... * q_k^a_k be the prime factorization of q.
        // If x is divisible by q, then x must be divisible by q_i^a_i for all i.
        // To make x not divisible by q, we need to remove enough factors of at least one q_i from p.
        // Specifically, for some q_i, x must not be divisible by q_i^a_i.
        // The largest such x would be p / (q_i^b_i) where b_i is the smallest power such that
        // p / (q_i^b_i) is not divisible by q_i^a_i.
        // This means p / (q_i^b_i) has fewer than a_i factors of q_i.
        // Let p = q_i^c_i * R, where R is not divisible by q_i.
        // If c_i < a_i, then p is not divisible by q_i^a_i, so p is not divisible by q.
        // But we are in the case where p is divisible by q, so c_i >= a_i for all i.
        // We want to find the largest x = p / (q_i^k) such that x % q != 0.
        // This means we want to find the smallest k such that p / (q_i^k) is not divisible by q.
        // The smallest k is 1. So we consider p / q_i.
        // We want to find max(p / (q_i^k)) such that p / (q_i^k) is not divisible by q.
        // This is equivalent to finding max(p / (q_i^k)) such that (p / (q_i^k)) % q != 0.
        // For each prime factor q_i of q, we can try to remove factors of q_i from p.
        // Let p = P * q_i^count_p and q = Q * q_i^count_q, where P, Q are not divisible by q_i.
        // We know count_p >= count_q because p is divisible by q.
        // We want to find x = p / q_i^k such that x % q != 0.
        // The largest such x will be p / q_i^(count_p - count_q + 1).
        // This x will have count_q - 1 factors of q_i, so it won't be divisible by q_i^count_q,
        // and thus not divisible by q.
        // We need to do this for each distinct prime factor of q and take the maximum resulting x.

        long long max_x = 0;
        std::map<long long, int> q_factors = get_prime_factors(q);

        for (auto const& [prime_factor, q_exponent] : q_factors) {
            long long current_p = p;
            int p_exponent = 0;
            while (current_p > 0 && current_p % prime_factor == 0) {
                p_exponent++;
                current_p /= prime_factor;
            }

            // We need to remove enough factors of prime_factor from p
            // such that the resulting number is not divisible by prime_factor^q_exponent.
            // The number of factors of prime_factor to remove is p_exponent - q_exponent + 1.
            // This ensures the resulting number has q_exponent - 1 factors of prime_factor.
            long long divisor_to_remove = 1;
            for (int i = 0; i < p_exponent - q_exponent + 1; ++i) {
                divisor_to_remove *= prime_factor;
            }
            max_x = std::max(max_x, p / divisor_to_remove);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

