int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 1: can move left (x_c - 1, y_c)
            // If f1 = 0, robot cannot move left.
            // This means it cannot reach any point (X, Y) where X < x_i.
            // So, X must be >= x_i.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }

            // f2 = 1: can move up (x_c, y_c + 1)
            // If f2 = 0, robot cannot move up.
            // This means it cannot reach any point (X, Y) where Y > y_i.
            // So, Y must be <= y_i.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }

            // f3 = 1: can move right (x_c + 1, y_c)
            // If f3 = 0, robot cannot move right.
            // This means it cannot reach any point (X, Y) where X > x_i.
            // So, X must be <= x_i.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }

            // f4 = 1: can move down (x_c, y_c - 1)
            // If f4 = 0, robot cannot move down.
            // This means it cannot reach any point (X, Y) where Y < y_i.
            // So, Y must be >= y_i.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a point exists, one with coordinates
            // not exceeding 10^5 by absolute value exists.
            // We can pick any valid point, e.g., (min_x, min_y).
            // However, min_x/min_y could be outside [-10^5, 10^5] if the initial
            // bounds were very large. The problem statement implies that the
            // *final* chosen X, Y should not exceed 10^5 by absolute value.
            // The actual bounds for X, Y are [-10^5, 10^5].
            // So we should clamp the chosen point to these bounds.
            // The problem statement says "if there exists at least one point reachable by all robots,
            // then at least one of such points has both coordinates not exceeding 10^5 by absolute value."
            // This means we can just output min_x, min_y directly, as they will be within the range
            // if a solution exists. The initial large values for min_x/max_x/min_y/max_y are just
            // to represent "no constraint yet". The actual coordinates x_i, y_i are within [-10^5, 10^5].
            // So min_x, max_x, min_y, max_y will eventually be clamped by some x_i or y_i,
            // or remain at their initial large values if no constraint applies.
            // If a solution exists, then min_x, min_y will be within [-10^5, 10^5].
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

