                temp_ans[i] = '2';
            }
        }

        // Second pass: determine the split point for digits equal to split_digit
        // Find the first index `k` such that `s[k] - '0' == split_digit` and `s[k]` should be colored '2'.
        // This happens if `s[k]` is greater than or equal to the first digit that *must* be '2' (i.e., `first2`).
        // Or, if `s[k]` is less than the last digit that *must* be '1' (i.e., `last1`), then it's impossible.

        // Let's find the actual `last1` and `first2` from the partial assignment.
        int actual_last1 = -1;
        for (int i = 0; i < n; ++i) {
            if (temp_ans[i] == '1') {
                actual_last1 = s[i] - '0';
            }
        }
        int actual_first2 = 10;
        for (int i = n - 1; i >= 0; --i) {
            if (temp_ans[i] == '2') {
                actual_first2 = s[i] - '0';
            }
        }

        // If `actual_last1 > actual_first2`, then it's impossible for this `split_digit`.
        // This check is implicitly handled by the full validation below.

        // Now, assign digits equal to `split_digit`.
        // All `split_digit`s before `pivot_idx` are '1', all after are '2'.
        // We need to find the smallest `pivot_idx` such that `split_digit >= actual_first2`
        // and `split_digit >= actual_last1` (if `split_digit` is colored '1').
        // This is equivalent to finding the first `split_digit` that we *must* color '2'.
        // This `split_digit` must be >= `actual_first2`.
        // All `split_digit`s before it must be >= `actual_last1`.

        // Let's try to find the `pivot_idx` for `split_digit`s.
        // All `d_i = split_digit` before `pivot_idx` are '1'.
        // All `d_i = split_digit` from `pivot_idx` onwards are '2'.
        int pivot_idx_for_equal = n; // Default: all `split_digit`s are '1'

        // Find the first `split_digit` that *must* be '2'.
        // This is the first `split_digit` that appears after `actual_last1` (if `actual_last1` exists)
        // AND is greater than or equal to `actual_first2` (if `actual_first2` exists).
        // More simply, find the first `split_digit` that, if colored '1', would violate `S1` non-decreasing
        // (i.e., `split_digit < actual_last1` which is impossible as `split_digit` is fixed)
        // OR, if colored '2', would violate `S2` non-decreasing (i.e., `split_digit > actual_first2`).

        // The simplest way to find `pivot_idx_for_equal`:
        // Iterate through `s`. If `s[i] - '0' == split_digit`:
        //   If `s[i] - '0' < actual_last1`, then it's impossible.
        //   If `s[i] - '0' > actual_first2`, then it's impossible.
        //   If `s[i] - '0' == split_digit` and we color it '1', `last1` becomes `split_digit`.
        //   If `s[i] - '0' == split_digit` and we color it '2', `first2` becomes `split_digit`.

        // Let's try to find the `pivot_idx_for_equal` by iterating through `s`.
        // `pivot_idx_for_equal` is the first index `i` such that `s[i] - '0' == split_digit` and we decide to color it '2'.
        // All `s[j] - '0' == split_digit` for `j < i` are colored '1'.
        // All `s[k] - '0' == split_digit` for `k >= i` are colored '2'.

        // We need to find the smallest `pivot_idx_for_equal` such that the resulting sequence is valid.
        // This means we want to color as many `split_digit`s '1' as possible.
        // So, we color `split_digit`s '1' until we *must* color one '2'.
        // A `split_digit` at index `i` *must* be '2' if `split_digit > actual_first2`.
        // (This is not quite right, `actual_first2` is the first digit > `split_digit` that is colored '2'.
        // If `split_digit` is colored '2', it must be `<= actual_first2`.)

        // Let's try the example: 040425524644, split_digit = 4
        // d: 0 4 0 4 2 5 5 2 4 6 4 4
        // s: 1 1 1 1 1 2 2 1 1 2 1 1 (from example output)
        // S1: 0022444
        // S2: 44556
        // Last S1: 4, First S2: 4. Valid.

        // For split_digit = 4:
        // d_i < 4: 0, 0, 2, 2. These are '1'.
        // d_i > 4: 5, 5, 6. These are '2'.
        // d_i = 4: 4, 4, 4, 4, 4. These need to be assigned.

        // Initial `temp_ans`:
        // d: 0 4 0 4 2 5 5 2 4 6 4 4
        // t: 1 _ 1 _ 1 2 2 1 _ 2 _ _
        // `actual_last1` (from 0,0,2,2) = 2.
        // `actual_first2` (from 5,5,6) = 5.

        // Now, assign `split_digit`s (which are 4).
        // We need to find a `pivot_idx_for_equal`.
        // All `s[i] = 4` for `i < pivot_idx_for_equal` are '1'.
        // All `s[i] = 4` for `i >= pivot_idx_for_equal` are '2'.

        // Let's try to find the `pivot_idx_for_equal` by iterating through all possible values.
        // `pivot_idx_for_equal` can be `0` to `n`.
        // `pivot_idx_for_equal = 0` means all `split_digit`s are '2'.
        // `pivot_idx_for_equal = n` means all `split_digit`s are '1'.

        for (int pivot_idx_for_equal = 0; pivot_idx_for_equal <= n; ++pivot_idx_for_equal) {
            std::string current_coloring = temp_ans;
            bool current_possible = true;

            for (int i = 0; i < n; ++i) {
                if (s[i] - '0' == split_digit) {
                    if (i < pivot_idx_for_equal) {
                        current_coloring[i] = '1';
                    } else {
                        current_coloring[i] = '2';
                    }
                }
            }

            // Validate `current_coloring`
            std::string s1_str = "";
            std::string s2_str = "";
            int last_s1_digit = -1;
            int first_s2_digit = 10;

            for (int i = 0; i < n; ++i) {
                if (current_coloring[i] == '1') {
                    int digit = s[i] - '0';
                    if (digit < last_s1_digit) {
                        current_possible = false;
                        break;
                    }
                    last_s1_digit = digit;
                    s1_str += s[i];
                }
            }
            if (!current_possible) continue;

            for (int i = 0; i < n; ++i) {
                if (current_coloring[i] == '2') {
                    int digit = s[i] - '0';
                    if (digit < first_s2_digit) {
                        current_possible = false;
                        break;
                    }
                    first_s2_digit = digit;
                    s2_str += s[i];
                }
            }
            if (!current_possible) continue;

            // Check condition 3: last digit of S1 <= first digit of S2
            if (!s1_str.empty() && !s2_str.empty()) {
                if (s1_str.back() > s2_str.front()) {
                    current_possible = false;
                }
            }
            if (!current_possible) continue;

            // If all checks pass, we found a solution
            ans = current_coloring;
            found = true;
            break; // Found a valid coloring for this split_digit and pivot_idx_for_equal
        }

        if (found) {
            break; // Found a valid coloring for this split_digit
        }
    }

    if (found) {
        std::cout << ans << "\n";
    } else {
        std::cout << "-\n";
    }
}

