// Z-algorithm implementation
std::vector<int> calculate_z_function(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    for (int i = 1, l = 0, r = 0; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int L = s.length();

    // Precompute Z-functions for all suffixes of s
    // z_functions[i] stores the Z-array for s.substr(i)
    // To optimize, we can compute Z-function for s + '#' + s.substr(i)
    // Or, more simply, for s_i = s[i..L-1] + s[0..i-1]
    // Let's use the standard Z-algorithm on concatenated strings.

    // For each possible starting character s[k] (which becomes t[0]),
    // we want to find the best p.
    // The character s[k] is at index k in the original string s.
    // The character s[(k + p - 1) % L] is at index (k + p - 1) % L in s.

    // `counts[c]` will store the number of `k` values for which `s[k] == c`.
    std::vector<int> char_counts(26, 0);
    for (char ch : s) {
        char_counts[ch - 'a']++;
    }

    double total_win_prob = 0.0;

    // Iterate over all possible values of k (0 to L-1)
    // Each k corresponds to a specific t[0] = s[k]
    // We group k's by their s[k] value.
    // For each s[k], we want to find the optimal p.
    // The optimal p maximizes the number of unique k's that satisfy
    // t[0] = s[k] AND t[p-1] = s[(k+p-1)%L].
    // This is equivalent to maximizing the number of k's such that
    // s[k] = s[k_fixed] AND s[(k+p-1)%L] = s[(k_fixed+p-1)%L]
    // and this pair (s[k], s[(k+p-1)%L]) is unique among all k's.

    // Let's iterate through each possible first character `c` (from 'a' to 'z').
    for (int char_idx = 0; char_idx < 26; ++char_idx) {
        char current_first_char = 'a' + char_idx;
        if (char_counts[char_idx] == 0) {
            continue; // This character does not appear as t[0]
        }

        // `possible_k_indices` stores all `k` such that `s[k] == current_first_char`.
        std::vector<int> possible_k_indices;
        for (int k = 0; k < L; ++k) {
            if (s[k] == current_first_char) {
                possible_k_indices.push_back(k);
            }
        }

        int max_unique_k_for_this_char = 0;

        // If there's only one k for this t[0], Vasya wins for sure.
        if (possible_k_indices.size() == 1) {
            max_unique_k_for_this_char = 1;
        } else {
            // Try all possible positions p (from 2 to L)
            for (int p = 2; p <= L; ++p) {
                // For a fixed `current_first_char` and a fixed `p`,
                // count how many unique pairs (s[k], s[(k+p-1)%L]) exist.
                // Since s[k] is fixed to `current_first_char`, we only need to count
                // unique values of s[(k+p-1)%L].
                std::vector<bool> seen_second_char(26, false);
                int current_unique_count = 0;
                for (int k_val : possible_k_indices) {
                    char second_char = s[(k_val + p - 1) % L];
                    if (!seen_second_char[second_char - 'a']) {
                        seen_second_char[second_char - 'a'] = true;
                        current_unique_count++;
                    }
                }
                max_unique_k_for_this_char = std::max(max_unique_k_for_this_char, current_unique_count);
            }
        }
        total_win_prob += (double)max_unique_k_for_this_char;
    }

    std::cout << std::fixed << std::setprecision(15) << total_win_prob / L << std::endl;

    return 0;
}

