#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for each bit.
    // For each bit position (0-9), we track how an initial 0 and an initial 1
    // would transform after all operations.
    // bit_state[j][0] = final value of bit j if initial bit j was 0
    // bit_state[j][1] = final value of bit j if initial bit j was 1
    std::vector<std::vector<int>> bit_state(10, std::vector<int>(2));
    for (int j = 0; j < 10; ++j) {
        bit_state[j][0] = 0; // Initial 0 remains 0
        bit_state[j][1] = 1; // Initial 1 remains 1
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int j = 0; j < 10; ++j) {
            int bit_x = (x >> j) & 1; // j-th bit of constant x

            if (op_char == '&') {
                bit_state[j][0] &= bit_x;
                bit_state[j][1] &= bit_x;
            } else if (op_char == '|') {
                bit_state[j][0] |= bit_x;
                bit_state[j][1] |= bit_x;
            } else if (op_char == '^') {
                bit_state[j][0] ^= bit_x;
                bit_state[j][1] ^= bit_x;
            }
        }
    }

    // Now, determine the combined operations.
    // We need to find A_AND, A_OR, A_XOR such that:
    // ( ( (input & A_AND) | A_OR ) ^ A_XOR )
    // produces the same result for all bits.

    // Initialize A_AND to all 1s (1023), A_OR to all 0s (0), A_XOR to all 0s (0).
    // This represents the identity transformation: ( (input & 1023) | 0 ) ^ 0 = input
    int A_AND = 1023;
    int A_OR = 0;
    int A_XOR = 0;

    for (int j = 0; j < 10; ++j) {
        int final_0 = bit_state[j][0];
        int final_1 = bit_state[j][1];

        if (final_0 == 0 && final_1 == 0) {
            // Bit j always becomes 0.
            // To achieve this:
            // ( (input_j & A_AND_j) | A_OR_j ) ^ A_XOR_j = 0
            // If input_j is 0: (0 & A_AND_j) | A_OR_j ) ^ A_XOR_j = 0 => A_OR_j ^ A_XOR_j = 0 => A_OR_j = A_XOR_j
            // If input_j is 1: (1 & A_AND_j) | A_OR_j ) ^ A_XOR_j = 0
            //
            // Simplest way to force 0: set A_AND_j = 0.
            // Then ( (input_j & 0) | A_OR_j ) ^ A_XOR_j = 0
            // (0 | A_OR_j) ^ A_XOR_j = 0
            // A_OR_j ^ A_XOR_j = 0 => A_OR_j = A_XOR_j
            // We can set A_AND_j = 0, A_OR_j = 0, A_XOR_j = 0.
            // This means: A_AND &= ~(1 << j)
            A_AND &= ~(1 << j);
            // A_OR and A_XOR bits remain 0.
        } else if (final_0 == 1 && final_1 == 1) {
            // Bit j always becomes 1.
            // To achieve this:
            // ( (input_j & A_AND_j) | A_OR_j ) ^ A_XOR_j = 1
            // Simplest way to force 1: set A_OR_j = 1.
            // Then ( (input_j & A_AND_j) | 1 ) ^ A_XOR_j = 1
            // (1) ^ A_XOR_j = 1 => A_XOR_j = 0
            // We can set A_OR_j = 1, A_XOR_j = 0. A_AND_j can be 1.
            // This means: A_OR |= (1 << j)
            A_OR |= (1 << j);
            // A_AND and A_XOR bits remain 1 and 0 respectively.
        } else if (final_0 == 0 && final_1 == 1) {
            // Bit j remains unchanged (input_j).
            // ( (input_j & A_AND_j) | A_OR_j ) ^ A_XOR_j = input_j
            // If input_j is 0: (0 & A_AND_j) | A_OR_j ) ^ A_XOR_j = 0 => A_OR_j ^ A_XOR_j = 0 => A_OR_j = A_XOR_j
            // If input_j is 1: (1 & A_AND_j) | A_OR_j ) ^ A_XOR_j = 1
            //
            // Simplest way to pass through: A_AND_j = 1, A_OR_j = 0, A_XOR_j = 0.
            // This means: A_AND |= (1 << j) (already 1 by default)
            // A_OR and A_XOR bits remain 0.
        } else if (final_0 == 1 && final_1 == 0) {
            // Bit j is flipped (~input_j).
            // ( (input_j & A_AND_j) | A_OR_j ) ^ A_XOR_j = ~input_j
            // If input_j is 0: (0 & A_AND_j) | A_OR_j ) ^ A_XOR_j = 1 => A_OR_j ^ A_XOR_j = 1
            // If input_j is 1: (1 & A_AND_j) | A_OR_j ) ^ A_XOR_j = 0
            //
            // Simplest way to flip: A_AND_j = 1, A_OR_j = 0, A_XOR_j = 1.
            // This means: A_XOR |= (1 << j)
            // A_AND bit remains 1. A_OR bit remains 0.
            A_XOR |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (A_AND != 1023) { // If A_AND is not all 1s, we need an AND operation
        result_ops.push_back({'&', A_AND});
    }
    if (A_OR != 0) { // If A_OR is not all 0s, we need an OR operation
        result_ops.push_back({'|', A_OR});
    }
    if (A_XOR != 0) { // If A_XOR is not all 0s, we need an XOR operation
        result_ops.push_back({'^', A_XOR});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

