    }

    long long low = 0;
    long long high = m - 1; // Max possible operations is m-1 (e.g., change 0 to m-1)
    long long ans = m - 1;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, a)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y and intermediate sums to prevent overflow
// a_i can be up to 10^9, n up to 2*10^5.
// y can grow large. x can also be large if a_x is large.

// Memoization table for results
// dp[x][parity] stores the pair {final_x, final_y} if starting from x with given parity
// parity 0: x = x + a[x], y = y + a[x]
// parity 1: x = x - a[x], y = y + a[x]
// We need to store the *change* in x and y from the current state.
// dp[x][parity] = {delta_x, delta_y}
// If it terminates, delta_x will be outside [1, n].
// If it loops, delta_x will be 0 and delta_y will be 0 (or some special value).
// Let's use a state representation:
// dp[x][parity] = {final_x_val, total_y_added}
// final_x_val: the x value when it terminates or reaches a cycle.
// total_y_added: the y value accumulated from the start of this subproblem until termination/cycle.
// Special values:
// final_x_val = 0: indicates termination (x <= 0 or x > n)
// final_x_val = -1: indicates an infinite loop

std::vector<long long> a;
std::vector<std::vector<std::pair<long long, long long>>> dp; // dp[x][parity] = {final_x, total_y_added}
std::vector<std::vector<bool>> visited; // visited[x][parity] = true if currently exploring this state

int N;

std::pair<long long, long long> solve(int current_x, int parity) {
    if (current_x <= 0 || current_x > N) {
        return {0, 0}; // Terminated, no further y added, final_x_val = 0
    }

    if (visited[current_x][parity]) {
        return {-1, 0}; // Infinite loop detected
    }

    if (dp[current_x][parity].first != -2) { // -2 is initial uncomputed state
        return dp[current_x][parity];
    }

    visited[current_x][parity] = true;

    long long val_a_x = a[current_x];
    long long next_x;
    long long y_added_this_step = val_a_x;

    if (parity == 0) { // x = x + a[x], y = y + a[x]
        next_x = current_x + val_a_x;
    } else { // x = x - a[x], y = y + a[x]
        next_x = current_x - val_a_x;
    }

    std::pair<long long, long long> result_from_next_state = solve(next_x, 1 - parity);

    visited[current_x][parity] = false; // Backtrack

    if (result_from_next_state.first == -1) { // Infinite loop
        dp[current_x][parity] = {-1, 0};
    } else if (result_from_next_state.first == 0) { // Terminated
        dp[current_x][parity] = {0, y_added_this_step + result_from_next_state.second};
    } else { // Continues to another state
        // The next state was (next_x, 1-parity). It returned {final_x, total_y_added_from_next_state}.
        // This means from (next_x, 1-parity) it eventually reached final_x, adding total_y_added_from_next_state.
        // So from (current_x, parity), it reaches final_x, adding y_added_this_step + total_y_added_from_next_state.
        dp[current_x][parity] = {result_from_next_state.first, y_added_this_step + result_from_next_state.second};
    }

    return dp[current_x][parity];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a.resize(N + 1);
    for (int i = 2; i <= N; ++i) {
        std::cin >> a[i];
    }

    // Initialize DP table with a special value indicating uncomputed state
    // -2 for final_x_val means uncomputed
    dp.assign(N + 1, std::vector<std::pair<long long, long long>>(2, {-2, 0}));
    visited.assign(N + 1, std::vector<bool>(2, false));

    for (int i = 1; i < N; ++i) {
        a[1] = i; // Set a[1] for the current run

        // Initial state: x=1, y=0.
        // First operation is x = x + a[x], y = y + a[x]. This corresponds to parity 0.
        // The initial y is 0. The first step adds a[1] to y.
        // So we call solve(1, 0) and add a[1] to its result.

        // Clear visited for each new run, but DP table is shared.
        // This is incorrect. DP table should be cleared or recomputed for each a[1].
        // However, the problem states "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This means a[1] changes for each run. So the DP table depends on a[1].
        // We must reinitialize dp and visited for each i.

        // Reinitialize DP table and visited for each i
        dp.assign(N + 1, std::vector<std::pair<long long, long long>>(2, {-2, 0}));
        visited.assign(N + 1, std::vector<bool>(2, false));

        long long initial_x = 1;
        long long initial_y = 0;

        long long val_a_initial_x = a[initial_x];
        long long next_x_after_first_step = initial_x + val_a_initial_x;
        long long y_added_first_step = val_a_initial_x;

        std::pair<long long, long long> result_from_next_state = solve(next_x_after_first_step, 1);

        if (result_from_next_state.first == -1) { // Infinite loop
            std::cout << -1 << "\n";
        } else if (result_from_next_state.first == 0) { // Terminated
            std::cout << y_added_first_step + result_from_next_state.second << "\n";
        } else { // Should not happen if the logic is correct, as solve(next_x, 1-parity) should eventually terminate or loop.
                 // The problem states "If, after any step, x <= 0 or x > n, the program immediately terminates."
                 // So, the solve function should always return 0 or -1 for its first element.
                 // The only way it returns a non-zero, non-minus-one first element is if it's an intermediate step
                 // that eventually leads to termination/loop. But the top-level call to solve(next_x_after_first_step, 1)
                 // should resolve to a final state.
                 // Let's re-evaluate the meaning of dp[x][parity].first.
                 // If dp[x][parity].first is 0, it means it terminated.
                 // If dp[x][parity].first is -1, it means it looped.
                 // It should never be anything else.
            std::cout << -1 << "\n"; // Fallback, should not be reached
        }
    }

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int count_ones(const std::string& s) {
    return std::count(s.begin(), s.end(), '1');
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // If ones_a is odd, we can add a '1' to make it even.
    // If ones_a is even, we can add a '0' to keep it even.
    // So, if ones_a is odd, we can effectively have ones_a + 1 '1's.
    // If ones_a is even, we can only have ones_a '1's.
    // This means the maximum number of '1's we can achieve is ones_a if ones_a is even,
    // and ones_a + 1 if ones_a is odd.
    // This can be compactly written as ones_a + (ones_a % 2).
    int max_ones_a_possible = ones_a + (ones_a % 2);

    if (max_ones_a_possible >= ones_b && a.length() <= b.length()) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }

    return 0;
}

