    // Let's pick a safe upper bound, say 20.
    const int MAX_LEN_TO_CHECK = 20; // 2^19 is 524288, 2^20 is 1048576.
                                     // If len > 19, then f(s_l...s_r) > 2^19-1 > 2e5.
                                     // So, if len > 19, f(s_l...s_r) > n.
