                    //       // This means `l_required` must be `k`.
                    //       // No, this is wrong. `current_val` is `f(s_k...s_j)`.
                    //       // If `s[k] == '0'`, then `k` is not the first '1'.
                    //       // So `current_val` should not be updated with `s[k]`.
                    //       // This means `k` must be the index of the first '1'.
                    //       // So we only update `current_val` if `s[k] == '1'`.
                    //       // And `k` is the first '1' in `s_l...s_j`.
                    //       // This means `s_l...s_{k-1}` are all '0's.

                    // Let's refine the `j` and `k` loop.
                    // For each `j` (right endpoint):
                    //   `current_val = 0` (value of `s_k...s_j`)
                    //   For `k` from `j` down to `0`:
                    //     If `j - k + 1 > MAX_LEN_TO_CHECK` and `s[k] == '1'`:
                    //       // If the significant part `s_k...s_j` is already too long,
                    //       // its value will be too large.
                    //       // Example: n=2e5. MAX_LEN_TO_CHECK=20.
                    //       // If j-k+1 = 20, current_val can be up to 2^20-1.
                    //       // If j-k+1 = 21, current_val can be up to 2^21-1.
                    //       // If s[k] == '1', then current_val will be at least 2^(j-k).
                    //       // If j-k >= 19, then current_val >= 2^19 > n.
                    //       // So we can break if j-k >= 19.
                    //       // This means k <= j-19.
                    //       // So we can iterate k down to max(0, j-19).
                    //       // Let's use a constant `MAX_SIG_LEN = 19`.
                    //       // If `j - k + 1 > MAX_SIG_LEN`, then `current_val` will be too large.
                    //       // So we can break if `j - k + 1 > MAX_SIG_LEN`.
                    //       // This means `k < j - MAX_SIG_LEN + 1`.
                    //       // So `k` goes from `j` down to `max(0, j - MAX_SIG_LEN)`.
                    //       // This is the range for `k` where `s_k...s_j` has length at most `MAX_SIG_LEN`.
                    //       // If `s[k] == '1'`, then `current_val` is updated.
                    //       // `current_val = current_val + (1LL << (j - k))`.
                    //       // If `current_val > n`, break.
                    //       // `l_required = j + 1 - current_val`.
                    //       // If `l_required >= 0` and `l_required <= k`:
                    //       //   Check `s_l_required...s_{k-1}` are all '0's.
                    //       //   This means `last_one_idx[k-1] < l_required`.
                    //       //   If `k == 0`, then `l_required` must be `0`.
                    //       //   If `k > 0` and `last_one_idx[k-1] < l_required`, then count++.
                    //       //   If `k == 0` and `l_required == 0`, then count++.
                    //       //   This can be simplified: `(k == 0 && l_required == 0) || (k > 0 && last_one_idx[k-1] < l_required)`.
                    //       //   This is equivalent to `(k == 0 && l_required == 0) || (k > 0 && (last_one_idx[k-1] == -1 || last_one_idx[k-1] < l_required))`.
                    //       //   The `last_one_idx` array should be `last_one_idx[p]` = index of last '1' in `s_0...s_p`.
                    //       //   So `last_one_idx[k-1]` is the index of the last '1' in `s_0...s_{k-1}`.
                    //       //   If `last_one_idx[k-1] < l_required`, it means all characters from `s_l_required` to `s_{k-1}` are '0's.
                    //       //   This is correct.

                    // Precompute `last_one_idx`.
                    std::vector<int> last_one_idx(n);
                    int last_one = -1;
                    for (int i = 0; i < n; ++i) {
                        if (s[i] == '1') {
                            last_one = i;
                        }
                        last_one_idx[i] = last_one;
                    }

                    // Iterate `j` (right endpoint)
                    for (int j = 0; j < n; ++j) {
                        long long current_val = 0;
                        // Iterate `k` (start of the '1' part) from `j` down to `0`.
                        // We only need to consider `k` such that `j - k + 1` is small.
                        // If `j - k + 1 > MAX_LEN_TO_CHECK`, then `current_val` will be too large.
                        // `j - k + 1 <= MAX_LEN_TO_CHECK` implies `k >= j - MAX_LEN_TO_CHECK + 1`.
                        for (int k = j; k >= std::max(0, j - MAX_LEN_TO_CHECK); --k) {
                            if (s[k] == '1') {
                                // Add 2^(j-k) to current_val
                                // Check for overflow before adding, though current_val > n check handles it.
                                // 1LL << (j-k) can be up to 2^19.
                                // current_val can be up to 2^20.
                                // If current_val + (1LL << (j-k)) overflows long long, it's definitely > n.
                                // But n is 2e5, so current_val won't overflow long long.
                                current_val += (1LL << (j - k));
                            }

                            // If current_val exceeds n, it can't be equal to any length <= n.
                            if (current_val > n) {
                                break; // Break from inner loop (for k)
                            }

                            // Calculate required left endpoint `l`
                            long long l_required = j + 1 - current_val;

                            // Check conditions for `l_required`:
                            // 1. `l_required >= 0` (valid index)
                            // 2. `l_required <= k` (the '0' prefix is valid or empty)
                            // 3. All characters `s_l_required...s_{k-1}` must be '0's.
                            //    This is true if `last_one_idx[k-1] < l_required`.
                            //    If `k == 0`, then `s_l_required...s_{k-1}` is an empty prefix.
                            //    In this case, `l_required` must be `0`.
                            if (l_required >= 0 && l_required <= k) {
                                if (k == 0) { // Empty prefix of '0's, so l_required must be 0.
                                    if (l_required == 0) {
                                        count++;
                                    }
                                } else { // Non-empty prefix of '0's or no prefix (l_required == k).
                                    if (last_one_idx[k - 1] < l_required) {
                                        count++;
                                    }
                                }
                            }
                        }
                    }
    }
    std::cout << count << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize initial_a with a large negative value to represent -infinity
    // This is because we are looking for the maximum possible initial_a[i]
    // that satisfies all constraints.
    std::vector<long long> initial_a(n, -2000000000000000000LL); // A value smaller than -10^9

    // For each type 2 operation, we need to find the maximum possible initial_a[k]
    // for k in [l, r] such that the current value at k is m.
    // current_a[k] = initial_a[k] + sum_of_deltas_up_to_this_op[k]
    // So, initial_a[k] = m - sum_of_deltas_up_to_this_op[k]
    // We want to find the maximum initial_a[k] that satisfies this for all k in [l, r].
    // This means initial_a[k] <= m - sum_of_deltas_up_to_this_op[k] for all k in [l, r].
    // To maximize initial_a[k], we set initial_a[k] = min(initial_a[k], m - sum_of_deltas_up_to_this_op[k])
    // for all k in [l, r].
    // The initial_a[k] values are initialized to a very small number.
    // If an initial_a[k] is not constrained by any type 2 operation, it will remain very small.
    // We need to ensure that all initial_a[k] are at least -10^9.
    // A better approach is to initialize initial_a[k] to 10^9, and then take min.
    // But the problem asks for *any* suitable array.
    // Let's try to find the maximum possible initial_a[i] for each i.
    // Initialize initial_a[i] to 10^9.
    // For each type 2 op (l, r, m):
    //   Calculate current_deltas for all j in [l, r] up to this op.
    //   For each j in [l, r]:
    //     initial_a[j] = min(initial_a[j], m - current_deltas[j])
    // This is still not quite right. The problem is that m is the *maximum* in the range.
    // So, for a type 2 op (l, r, m), we know that for all j in [l, r]:
    //   initial_a[j] + current_deltas[j] <= m
    //   initial_a[j] <= m - current_deltas[j]
    // This gives an upper bound for initial_a[j].
    // To maximize initial_a[j], we should set initial_a[j] to the minimum of all such upper bounds.
    // Initialize initial_a[j] to 10^9 + 7 (a value larger than 10^9).
    for (int i = 0; i < n; ++i) {
        initial_a[i] = 1000000000LL; // Max allowed value
    }

    std::vector<long long> current_deltas(n, 0); // Stores sum of d for type 1 ops up to current point
    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_deltas[j] += op.val;
            }
        } else { // type 2
            for (int j = op.l; j <= op.r; ++j) {
                initial_a[j] = std::min(initial_a[j], op.val - current_deltas[j]);
            }
        }
    }

    // After processing all operations, initial_a[j] contains the maximum possible value
    // for the j-th element of the initial array that satisfies all type 2 constraints.
    // We must ensure |initial_a[j]| <= 10^9.
    // If initial_a[j] is still 10^9 + 7, it means it was never constrained by a type 2 op.
    // In this case, we can set it to 0 (or any value within [-10^9, 10^9]).
    // The problem states "all numbers in his array didn't exceed 10^9 in their absolute value".
    // So, if initial_a[j] is greater than 10^9, it's invalid.
    // If initial_a[j] is less than -10^9, it's invalid.
    // The current logic sets initial_a[j] to 10^9 initially, then takes min.
    // So initial_a[j] will be at most 10^9.
    // If it's less than -10^9, it's invalid.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] < -1000000000LL) {
            // This means even with the smallest possible initial_a[i],
            // the constraint m - current_deltas[i] was too small.
            // This should not happen if a solution exists, as m is up to 5*10^7 and d up to 10^4.
            // The sum of deltas can be up to 5000 * 10^4 = 5*10^7.
            // So m - current_deltas[i] can be as low as -5*10^7 - 5*10^7 = -10^8.
            // This is within the -10^9 limit.
            // The only way initial_a[i] could be less than -10^9 is if m - current_deltas[i] was less than -10^9.
            // This is possible if m is small negative and current_deltas is large positive.
            // E.g., m = -5*10^7, current_deltas = 5*10^7, then initial_a[i] <= -10^8.
            // If m = -5*10^7, current_deltas = 10^9, then initial_a[i] <= -10^9 - 5*10^7.
            // This is a valid constraint.
            // The problem is that we need to output an array where |a_i| <= 10^9.
            // If initial_a[i] is forced to be less than -10^9, then no solution exists.
            std::cout << "NO\n";
            return 0;
        }
    }

    // Now, verify the constructed initial_a
    std::vector<long long> a = initial_a;
    current_deltas.assign(n, 0); // Reset current_deltas for verification

    for (const auto& op : ops) {
        if (op.type == 1) {
            for (int j = op.l; j <= op.r; ++j) {
                current_deltas[j] += op.val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = op.l; j <= op.r; ++j) {
                max_val_in_range = std::max(max_val_in_range, a[j] + current_deltas[j]);
            }
            if (max_val_in_range != op.val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false;

        long long current_v_cry = children[i].v;
        long long accumulated_d_cry = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previous children who left
            if (accumulated_d_cry > 0) {
                children[j].p -= accumulated_d_cry;
            }

            // Apply v_cry from the child currently being treated
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry = std::max(0LL, current_v_cry - 1);
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                accumulated_d_cry += children[j].d;
            }
        }
    }

    std::cout << treated_children_indices.size() << "\n";
    for (size_t i = 0; i < treated_children_indices.size(); ++i) {
        std::cout << treated_children_indices[i] << (i == treated_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    // Case 1: All elements in one subsequence (e.g., S1).
    // All f values are a_i + a_j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    long long goodness1 = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition such that elements[0] and elements[1] are in different subsequences.
    // This is the only other case that can potentially yield a smaller goodness.
    // We put elements[0] in S1, elements[1] in S2.
    // All other elements can be put in S1.
    //
    // min_f:
    //   - elements[0] + elements[k] (k > 1, k in S1): elements[0] + elements[2]
    //   - elements[1] + elements[k] (k > 1, k in S1): elements[1] + elements[2] + h
    //   - elements[0] + elements[1] + h
    // The minimum of these is min(elements[0] + elements[2], elements[0] + elements[1] + h).
    //
    // max_f:
    //   - elements[n-1] + elements[n-2] (both in S1)
    //   - elements[n-1] + elements[1] + h (elements[n-1] in S1, elements[1] in S2)
    // The maximum of these is max(elements[n-1] + elements[n-2], elements[n-1] + elements[1] + h).
    //
    // Goodness = max_f - min_f

    long long min_f2_candidate1 = elements[0].value + elements[1].value + h;
    long long min_f2_candidate2 = elements[0].value + elements[2].value; // elements[0] and elements[2] are in S1
    long long min_f2 = std::min(min_f2_candidate1, min_f2_candidate2);

    long long max_f2_candidate1 = elements[n-1].value + elements[n-2].value; // elements[n-1] and elements[n-2] are in S1
    long long max_f2_candidate2 = elements[n-1].value + elements[1].value + h; // elements[n-1] in S1, elements[1] in S2
    long long max_f2 = std::max(max_f2_candidate1, max_f2_candidate2);

    long long goodness2 = max_f2 - min_f2;
    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1; // elements[0] in S1
    partition2[elements[1].original_index] = 2; // elements[1] in S2
    for (int i = 2; i < n; ++i) {
        partition2[elements[i].original_index] = 1; // Others in S1
    }

    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

// Function to check if all target tracks can be covered within time T
bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // If T is 0, we just need to check if all p_j are among h_i
    if (T == 0) {
        std::set<long long> h_set(h.begin(), h.end());
        for (long long val_p : p) {
            if (h_set.find(val_p) == h_set.end()) {
                return false;
            }
        }
        return true;
    }

    // For each head h_i, it can cover the range [h_i - T, h_i + T].
    // We need to cover all p_j.
    // This is a greedy approach.
    // We iterate through the target points p_j.
    // For each p_j, we try to cover it with the leftmost available head that can reach it.

    int p_idx = 0; // Current index for target tracks p
    int h_idx = 0; // Current index for heads h

    while (p_idx < m) {
        // Find the first head h_k that can reach p[p_idx]
        // A head h_k can reach p[p_idx] if h_k - T <= p[p_idx]
        // Since h is sorted, we can advance h_idx until h[h_idx] - T <= p[p_idx]
        // or h_idx reaches n.
        while (h_idx < n && h[h_idx] + T < p[p_idx]) { // Head h[h_idx] is too far left to reach p[p_idx]
            h_idx++;
        }

        if (h_idx == n) { // No more heads available
            return false;
        }

        // At this point, h[h_idx] is the first head (from left) that *might* be able to cover p[p_idx].
        // It can cover p[p_idx] if h[h_idx] - T <= p[p_idx] <= h[h_idx] + T.
        // We already ensured h[h_idx] + T >= p[p_idx] by the previous loop condition.
        // So we just need to check h[h_idx] - T <= p[p_idx].
        if (h[h_idx] - T > p[p_idx]) { // This head is too far right to reach p[p_idx]
            return false; // No head can cover p[p_idx]
        }

        // If we reach here, h[h_idx] can cover p[p_idx].
        // Now, we use this head h[h_idx] to cover as many subsequent p_j's as possible.
        // The head h[h_idx] covers the range [h[h_idx] - T, h[h_idx] + T].
        // We advance p_idx past all points that fall within this range.
        long long current_head_reach_max = h[h_idx] + T;
        while (p_idx < m && p[p_idx] <= current_head_reach_max) {
            p_idx++;
        }

        // Move to the next head for the remaining points.
        h_idx++;
    }

    return true; // All points covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible time: (max_p - min_h) or (max_h - min_p)
    // A loose upper bound: difference between max p and min h, or max h and min p.
    // Max value of p or h is 10^10. So max diff is 10^10.
    // A single head might need to cover a range of 10^10.
    // So T can be up to 10^10.
    long long high = 20000000000LL; // A sufficiently large upper bound, e.g., 2 * 10^10

    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    long long total_pairs = (long long)n * (n + 1) / 2;
    long long bad_pairs = 0;

    // max_r_for_l[i] stores the maximum r such that the substring s[i...r]
    // does NOT contain any pattern s_x = s_{x+k} = s_{x+2k}.
    // If s[i...r] contains a pattern, then max_r_for_l[i] will be less than r.
    // Specifically, max_r_for_l[i] will be the largest index j such that
    // s[i...j] is "bad" (contains no pattern).
    // Initialize with n-1, meaning s[i...n-1] is initially considered bad.
    // This will be updated as we find patterns.
    std::vector<int> max_r_for_l(n);
    for (int i = 0; i < n; ++i) {
        max_r_for_l[i] = n - 1;
    }

    // Iterate through all possible starting positions x (0-indexed)
    // and all possible k values.
    // The pattern is s[x], s[x+k], s[x+2k].
    // The minimum length of such a pattern is 3 (when k=1).
    // So x+2k must be less than n.
    for (int x = 0; x < n; ++x) {
        // For k=1: check s[x], s[x+1], s[x+2]
        if (x + 2 < n && s[x] == s[x+1] && s[x+1] == s[x+2]) {
            // Pattern found: s[x] = s[x+1] = s[x+2]
            // This pattern starts at x and ends at x+2.
            // Any substring s[l...r] that contains this pattern
            // (i.e., l <= x and r >= x+2) is a "good" pair.
            // We are interested in "bad" pairs.
            // For any l' <= x, the maximum r' such that s[l'...r'] is bad
            // cannot exceed x+1.
            // So, for all l from 0 to x, update max_r_for_l[l] to min(current_value, x+1).
            // This means any r >= x+2 will make s[l...r] a good pair.
            for (int l = 0; l <= x; ++l) {
                max_r_for_l[l] = std::min(max_r_for_l[l], x + 1);
            }
        }

        // For k=2: check s[x], s[x+2], s[x+4]
        if (x + 4 < n && s[x] == s[x+2] && s[x+2] == s[x+4]) {
            // Pattern found: s[x] = s[x+2] = s[x+4]
            // This pattern starts at x and ends at x+4.
            // For any l' <= x, the maximum r' such that s[l'...r'] is bad
            // cannot exceed x+3.
            for (int l = 0; l <= x; ++l) {
                max_r_for_l[l] = std::min(max_r_for_l[l], x + 3);
            }
        }

        // For k=3: check s[x], s[x+3], s[x+6]
        if (x + 6 < n && s[x] == s[x+3] && s[x+3] == s[x+6]) {
            // Pattern found: s[x] = s[x+3] = s[x+6]
            // This pattern starts at x and ends at x+6.
            // For any l' <= x, the maximum r' such that s[l'...r'] is bad
            // cannot exceed x+5.
            for (int l = 0; l <= x; ++l) {
                max_r_for_l[l] = std::min(max_r_for_l[l], x + 5);
            }
        }
    }

    // Calculate the number of bad pairs (l, r)
    // For each l, r can range from l to max_r_for_l[l].
    // The number of such r's is max_r_for_l[l] - l + 1.
    for (int l = 0; l < n; ++l) {
        bad_pairs += (long long)max_r_for_l[l] - l + 1;
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
