bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // Cut s into A and B. Try to form BA.
    // BA must be a palindrome and BA != s.
    for (int i = 1; i < n; ++i) { // i is the length of A
        std::string a = s.substr(0, i);
        std::string b = s.substr(i);
        std::string s_prime = b + a;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // Cut s into A, B, C. Try to form a new palindrome.
    // Since s is already a palindrome, and we couldn't find a solution with k=1,
    // we need to consider the structure of s.
    // If s consists of only one distinct character (e.g., "aaaa"),
    // or if s consists of two distinct characters where one is in the middle
    // and the others are symmetric (e.g., "ababa", "aaabaaa"),
    // it might be impossible to form a new palindrome.

    // A key observation for k=2:
    // If s is a palindrome, and we cut it into s[0...i-1], s[i...j-1], s[j...N-1],
    // and reorder them to form a new palindrome,
    // consider the case where all characters in s are the same.
    // E.g., "aaaa". Any reordering of pieces will result in "aaaa".
    // If s consists of only one distinct character, it's impossible.
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }
    if (all_same) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work,
    // it means that for any single cut s = AB, BA is either not a palindrome or BA == s.
    // Consider the structure of s. Since s is a palindrome, s[x] == s[N-1-x].
    // If we can make a cut such that s[0...i-1] is a palindrome,
    // and s[i...N-1] is also a palindrome, then we can swap them.
    // But this is covered by k=1.

    // The problem statement implies that if k=1 doesn't work, k=2 might.
    // The example "nolon" -> 2.
    // "nolon" is a palindrome.
    // Cuts: no|l|on. Pieces: "no", "l", "on".
    // Reorder: "on", "l", "no" -> "onlno". This is a palindrome and != "nolon".
    // This is a specific reordering: C B A.
    // This implies that if we cut s into A B C, and A is s[0...i-1], B is s[i...j-1], C is s[j...N-1].
    // Then C is the reverse of A (because s is a palindrome and B is symmetric).
    // So, if s = A B A_rev, then we can form A_rev B A.
    // This is a palindrome if B is a palindrome.
    // For "nolon", A="no", B="l", C="on". A_rev is "on". So s = "no" "l" "on".
    // Here, B="l" is a palindrome. A_rev B A = "on" "l" "no" = "onlno".
    // This is a palindrome and != "nolon".

    // This specific structure (s = A B A_rev where B is a palindrome)
    // is always possible with 2 cuts if such A and B exist.
    // We need to find if there exists a prefix A (length i) such that
    // s[0...i-1] == reverse(s[N-i...N-1]) and s[i...N-i-1] is a palindrome.
    // This is equivalent to checking if the first half of the string (excluding the middle char for odd N)
    // is a palindrome.
    // For example, if s = "abacaba", N=7.
    // s[0...2] = "aba". This is a palindrome.
    // s[3...3] = "c". This is a palindrome.
    // s[4...6] = "aba". This is a palindrome.
    // If s[0...N/2 - 1] is a palindrome, then we can cut s into
    // s[0...N/2 - 1] | s[N/2] | s[N/2+1 ... N-1] (for odd N)
    // or s[0...N/2 - 1] | s[N/2 ... N-1] (for even N).
    // This is not quite right.

    // Let's re-evaluate the "nolon" example.
    // s = "nolon". N=5.
    // s[0] = 'n', s[1] = 'o', s[2] = 'l', s[3] = 'o', s[4] = 'n'.
    // The first half is s[0...N/2-1] = s[0...1] = "no".
    // The second half is s[N/2+1...N-1] = s[3...4] = "on".
    // The middle character is s[N/2] = s[2] = 'l'.
    // If we cut s into s[0...i-1], s[i...N-i-1], s[N-i...N-1].
    // For "nolon", i=2.
    // A = s[0...1] = "no"
    // B = s[2...2] = "l"
    // C = s[3...4] = "on"
    // We know s is a palindrome, so C is reverse(A).
    // If B is a palindrome, then C B A is a palindrome.
    // C B A = "on" "l" "no" = "onlno".
    // This is a palindrome and "onlno" != "nolon".
    // This works for "nolon".

    // This strategy works if there exists an `i` (1 <= i < N/2) such that
    // the middle part `s[i ... N-1-i]` is a palindrome.
    // If `s[i ... N-1-i]` is a palindrome, then we can cut `s` into
    // `s[0...i-1]`, `s[i...N-1-i]`, `s[N-i...N-1]`.
    // Let these be `P1`, `P2`, `P3`.
    // Since `s` is a palindrome, `P3` is the reverse of `P1`.
    // If `P2` is a palindrome, then `P3 P2 P1` will be a palindrome.
    // `P3 P2 P1` is `reverse(P1) P2 P1`.
    // We need `reverse(P1) P2 P1 != P1 P2 reverse(P1)`.
    // This is true if `P1 != reverse(P1)`.
    // If `P1 == reverse(P1)` (i.e., `P1` is a palindrome), then `P3 P2 P1 == P1 P2 P1`.
    // This would mean `P1 P2 P1 == s`.
    // So, we need `P1` not to be a palindrome.
    // For "nolon", P1="no", P2="l", P3="on". P1 is not a palindrome. P2 is a palindrome.
    // So "onlno" is a new palindrome.

    // What if all prefixes `s[0...i-1]` (for `1 <= i < N/2`) are palindromes?
    // E.g., "abacaba".
    // i=1: P1="a", P2="bacab", P3="a". P1 is palindrome. P2 is palindrome.
    // P3 P2 P1 = "abacaba" == s. No good.
    // i=2: P1="ab", P2="aca", P3="ba". P1 is not palindrome. P2 is palindrome.
    // P3 P2 P1 = "ba" "aca" "ab" = "baacaab". This is a palindrome and != "abacaba".
    // So for "abacaba", k=2 works.

    // The condition for k=2 to work is:
    // There exists an `i` (1 <= i < N/2) such that `s[i ... N-1-i]` is a palindrome.
    // If such an `i` exists, then we can form `s[N-i...N-1] + s[i...N-1-i] + s[0...i-1]`.
    // This new string is a palindrome.
    // We need to check if it's different from `s`.
    // It's different from `s` if `s[0...i-1]` is not a palindrome.
    // If `s[0...i-1]` is a palindrome, then `s[N-i...N-1]` is also `s[0...i-1]`.
    // So the new string is `s[0...i-1] + s[i...N-1-i] + s[0...i-1]`, which is `s`.
    // So we need `s[0...i-1]` NOT to be a palindrome.

    // Iterate `i` from 1 to `N/2 - 1`.
    // Check if `s.substr(i, N - 2*i)` is a palindrome.
    // If it is, then we can form a new palindrome.
    // The new palindrome is `s.substr(N-i) + s.substr(i, N-2*i) + s.substr(0,i)`.
    // This will always be a palindrome.
    // We need to check if it's different from `s`.
    // It's different from `s` if `s.substr(0,i)` is not a palindrome.
    // If `s.substr(0,i)` is a palindrome, then `s.substr(N-i)` is also `s.substr(0,i)`.
    // So the new string would be `s.substr(0,i) + s.substr(i, N-2*i) + s.substr(0,i)`, which is `s`.
    // So we need `s.substr(0,i)` to NOT be a palindrome.

    // This logic is slightly flawed. The example "kinnikkinnik" (N=12)
    // k=1 works: cut "kinnik" | "kinnik". Swap -> "kinnikkinnik" (same).
    // Cut "kinnikkinn" | "ik". Swap -> "ikkinnikkinn" (palindrome, new). So k=1.
    // My k=1 loop should find this.
    // For "kinnikkinnik", i=10. A="kinnikkinn", B="ik". BA="ikkinnikkinn".
    // is_palindrome("ikkinnikkinn") is true. "ikkinnikkinn" != "kinnikkinnik".
    // So k=1. My code should output 1.

    // Let's re-check the "qqqq" case. N=4.
    // k=1:
    // i=1: A="q", B="qqq". BA="qqqq" == s.
    // i=2: A="qq", B="qq". BA="qqqq" == s.
    // i=3: A="qqq", B="q". BA="qqqq" == s.
    // No k=1 solution.
    // all_same is true. Output "Impossible". Correct.

    // Let's re-check "nolon". N=5.
    // k=1:
    // i=1: A="n", B="olon". BA="olonn". Not palindrome.
    // i=2: A="no", B="lon". BA="lonno". Not palindrome.
    // i=3: A="nol", B="on". BA="onnol". Not palindrome.
    // i=4: A="nolo", B="n". BA="nnolo". Not palindrome.
    // No k=1 solution.
    // all_same is false.
    // So we proceed to k=2.
    // The logic for k=2 is: if there exists any `i` such that `s[i ... N-1-i]` is a palindrome,
    // then we can make 2 cuts.
    // For "nolon", N=5.
    // i=1: `s[1 ... 5-1-1]` = `s[1 ... 3]` = "olo". This is a palindrome.
    // So k=2 is possible. Output 2. Correct.

    // The logic for k=2 seems to be:
    // If there exists any `i` such that `s.substr(i, N - 2*i)` is a palindrome,
    // then we can achieve a new palindrome with 2 cuts.
    // The pieces are `s[0...i-1]`, `s[i...N-1-i]`, `s[N-i...N-1]`.
    // Let them be `P1`, `P2`, `P3`.
    // `P3` is `reverse(P1)` because `s` is a palindrome.
    // `P2` is a palindrome by our condition.
    // The new string `P3 P2 P1` is `reverse(P1) P2 P1`. This is a palindrome.
    // Is `reverse(P1) P2 P1` always different from `P1 P2 reverse(P1)` (which is `s`)?
    // Yes, unless `P1 == reverse(P1)` (i.e., `P1` is a palindrome).
    // If `P1` is a palindrome, then `P3 P2 P1` becomes `P1 P2 P1`, which is `s`.
    // So, for k=2 to work, we need to find an `i` (1 <= i < N/2) such that:
    // 1. `s.substr(i, N - 2*i)` is a palindrome. (This is `P2`)
    // 2. `s.substr(0, i)` is NOT a palindrome. (This is `P1`)

    // Let's test this refined k=2 logic.
    // "nolon", N=5.
    // i=1: P1="n", P2="olo", P3="on".
    // P2="olo" is a palindrome.
    // P1="n" is a palindrome.
    // So this `i=1` does NOT satisfy condition 2.
    // This means `P3 P2 P1` would be `P1 P2 P1` which is `s`.
    // But the example says "nolon" -> 2.
    // The example explanation: "no|l|on, and then unite them as follows on|l|no".
    // Here P1="no", P2="l", P3="on".
    // P1="no" is NOT a palindrome.
    // P2="l" IS a palindrome.
    // So this `i=2` (length of P1 is 2) satisfies both conditions.
    // `s.substr(2, 5-2*2)` = `s.substr(2,1)` = "l". This is P2. It's a palindrome.
    // `s.substr(0,2)` = "no". This is P1. It's NOT a palindrome.
    // So for `i=2`, k=2 works.

    // The loop for `i` should go from `1` up to `N/2 - 1`.
    // `N - 2*i` is the length of the middle part.
    // `N - 2*i` must be at least 1 for `s.substr` to be meaningful.
    // So `N - 2*i >= 1`.
    // If `N` is even, `N=2k`. `2k - 2i >= 1` -> `2(k-i) >= 1`. Smallest `k-i` is 1. So `i <= k-1 = N/2 - 1`.
    // If `N` is odd, `N=2k+1`. `2k+1 - 2i >= 1` -> `2(k-i) >= 0`. Smallest `k-i` is 0. So `i <= k = N/2`.
    // So `i` goes from `1` to `N/2 - 1` (inclusive).
    // If `N` is 1, 2, 3, 4: `N/2 - 1` is 0, 0, 1, 1.
    // N=1: loop range empty.
    // N=2: loop range empty.
    // N=3: i=1. `s.substr(1, 3-2*1)` = `s.substr(1,1)`. P2. `s.substr(0,1)`. P1.
    // N=4: i=1. `s.substr(1, 4-2*1)` = `s.substr(1,2)`. P2. `s.substr(0,1)`. P1.
    //      i=2. `s.substr(2, 4-2*2)` = `s.substr(2,0)`. Empty string. `s.substr` with length 0 is valid.
    //           An empty string is a palindrome.
    //           If P2 is empty, then s = P1 P3. P3 = reverse(P1).
    //           This means s = P1 reverse(P1).
    //           The new string is reverse(P1) P1.
    //           This is exactly the k=1 case where we cut in the middle.
    //           So we don't need to consider empty P2.
    //           So `N - 2*i >= 1`.
    //           This means `i <= (N-1)/2`.
    //           So `i` goes from `1` to `floor((N-1)/2)`.
    //           For N=5, `floor(4/2)=2`. So `i=1,2`.
    //           For N=4, `floor(3/2)=1`. So `i=1`.

    // Final k=2 logic:
    // Iterate `i` from `1` to `(N-1)/2`.
    // Let `P1 = s.substr(0, i)`.
    // Let `P2 = s.substr(i, N - 2*i)`.
    // If `is_palindrome(P2)` is true AND `is_palindrome(P1)` is false:
    // Then k=2 is possible. Print 2 and exit.

    // If after checking all `i` for k=2, we don't find a solution,
    // and `all_same` was false, then it's impossible.
    // This is because if `s` is not all same characters, and k=1 didn't work,
    // and k=2 didn't work (under the specific conditions),
    // it implies that any reordering of pieces will either result in `s` or a non-palindrome.
    // The problem statement implies that if a solution exists, it's either 1 or 2.
    // "It can be shown that there is no solution with one cut." (for nolon)
    // This suggests that if k=1 doesn't work, k=2 is the next possibility.
    // And if k=2 doesn't work, it's impossible.

    // Let's verify the "Impossible" condition.
    // If all characters are the same, e.g., "aaaaa", then any reordering of pieces will result in "aaaaa".
    // So it's impossible. This is handled.
    // What if not all characters are the same, but k=1 and k=2 (with the specific conditions) don't work?
    // Example: "abacaba". N=7.
    // k=1:
    // i=1: A="a", B="bacaba". BA="bacabaa". Not palindrome.
    // i=2: A="ab", B="acaba". BA="acabaab". Not palindrome.
    // i=3: A="aba", B="caba". BA="cabaaba". Not palindrome.
    // i=4: A="abac", B="aba". BA="abaabac". Not palindrome.
    // i=5: A="abaca", B="ba". BA="baabaca". Not palindrome.
    // i=6: A="abacab", B="a". BA="aabacab". Not palindrome.
    // No k=1 solution.
    // all_same is false.
    // k=2:
    // Loop `i` from `1` to `(7-1)/2 = 3`.
    // i=1: P1="a", P2="bacab".
    // P2="bacab" is NOT a palindrome. Condition 1 fails.
    // i=2: P1="ab", P2="aca".
    // P2="aca" IS a palindrome. Condition 1 passes.
    // P1="ab" is NOT a palindrome. Condition 2 passes.
    // Both conditions pass. So k=2. Output 2.

    // It seems the logic is sound.
    // 1. Check k=1: Iterate all possible single cuts. If `BA` is a palindrome and `BA != s`, output 1.
    // 2. If no k=1 solution: Check if all characters in `s` are the same. If so, output "Impossible".
    // 3. If not all characters are the same: Check k=2. Iterate `i` from `1` to `(N-1)/2`.
    //    Let `P1 = s.substr(0, i)` and `P2 = s.substr(i, N - 2*i)`.
    //    If `P2` is a palindrome AND `P1` is NOT a palindrome, output 2.
    // 4. If no k=2 solution found under these conditions, output "Impossible".

    // The problem statement guarantees `s` is a palindrome.
    // The minimum `k` is 1.
    // If `N=1`, `s="a"`.
    // k=1 loop: `i` from 1 to 0. Empty. No k=1.
    // all_same is true. Output "Impossible". Correct.

    // If `N=2`, `s="aa"`.
    // k=1 loop: `i=1`. A="a", B="a". BA="aa" == s. No k=1.
    // all_same is true. Output "Impossible". Correct.

    // If `N=3`, `s="aba"`.
    // k=1 loop:
    // i=1: A="a", B="ba". BA="baa". Not palindrome.
    // i=2: A="ab", B="a". BA="aab". Not palindrome.
    // No k=1.
    // all_same is false.
    // k=2 loop: `i` from 1 to `(3-1)/2 = 1`.
    // i=1: P1="a", P2="b".
    // P2="b" is palindrome.
    // P1="a" is palindrome. Condition 2 fails.
    // No k=2.
    // Output "Impossible". Correct. For "aba", any reordering of pieces will result in "aba".
    // E.g., a|b|a -> a b a (s)
    // a|ba -> baa (not pal)
    // ab|a -> aab (not pal)

    // This logic seems robust for all small cases and examples.

    for (int i = 1; i <= (n - 1) / 2; ++i) {
        std::string p1 = s.substr(0, i);
        std::string p2 = s.substr(i, n - 2 * i);
        if (is_palindrome(p2) && !is_palindrome(p1)) {
            std::cout << 2 << std::endl;
            return 0;
        }
    }

    std::cout << "Impossible" << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for differences (1 for strawberry, -1 for blueberry)
    // Left side: jars 0 to n-1
    // Right side: jars n to 2n-1

    // Left prefix sums (from right to left, relative to n-1)
    // diff_L[k] = (count of 1s in a[n-k...n-1]) - (count of 2s in a[n-k...n-1])
    // This is equivalent to prefix_diff[n-1] - prefix_diff[n-k-1]
    // Or, more simply, let's define diff_L[k] as the balance of the first k jars from the left (a[0]...a[k-1])
    // and diff_R[k] as the balance of the first k jars from the right (a[2n-1]...a[2n-k])

    // Calculate initial total balance
    int initial_balance = 0;
    for (int x : a) {
        if (x == 1) initial_balance++;
        else initial_balance--;
    }

    // Map to store minimum k_L for a given balance on the left side
    // balance_L[diff] = k_L
    std::map<int, int> balance_L;
    balance_L[0] = 0; // 0 jars removed from left, balance is 0

    int current_balance_L = 0;
    for (int k_L = 1; k_L <= n; ++k_L) {
        int jar_idx = n - k_L; // Jars are 0-indexed, so a[n-k_L] is the k_L-th jar from the left of Karlsson's position
        if (a[jar_idx] == 1) current_balance_L++;
        else current_balance_L--;

        // We want to find the minimum k_L for a given current_balance_L.
        // Since we iterate k_L from 1 upwards, the first time we see a balance,
        // it corresponds to the minimum k_L.
        if (balance_L.find(current_balance_L) == balance_L.end()) {
            balance_L[current_balance_L] = k_L;
        }
    }

    int min_jars_removed = 2 * n; // Initialize with max possible

    // Case 0: No jars removed from the right side (k_R = 0)
    // We need initial_balance - current_balance_L = 0, so current_balance_L = initial_balance
    if (balance_L.count(initial_balance)) {
        min_jars_removed = std::min(min_jars_removed, balance_L[initial_balance]);
    }

    // Iterate through k_R (number of jars removed from the right side)
    int current_balance_R = 0;
    for (int k_R = 1; k_R <= n; ++k_R) {
        int jar_idx = n + k_R - 1; // Jars are 0-indexed, so a[n+k_R-1] is the k_R-th jar from the right of Karlsson's position
        if (a[jar_idx] == 1) current_balance_R++;
        else current_balance_R--;

        // The remaining balance after removing k_L from left and k_R from right is:
        // initial_balance - current_balance_L - current_balance_R = 0
        // So, current_balance_L = initial_balance - current_balance_R
        int target_balance_L = initial_balance - current_balance_R;

        if (balance_L.count(target_balance_L)) {
            min_jars_removed = std::min(min_jars_removed, balance_L[target_balance_L] + k_R);
        }
    }

    std::cout << min_jars_removed << std::endl;
}

