    std::cin >> T;
    while (T--) {
        long long a, b;
        std::cin >> a >> b;
        if (a == b) {
            std::cout << 0 << "\n";
            continue;
        }

        long long diff = std::abs(a - b);
        long long presses = 0;

        // Greedy approach for denominations 5, 2, 1
        // This works because 1, 2, 5 form a canonical coin system
        // for which the greedy algorithm provides the optimal solution.
        presses += diff / 5;
        diff %= 5;

        if (diff == 0) {
            // No remaining difference
        } else if (diff == 1) {
            // Can be 1 (1 press)
            // Or 2-1 (2 presses)
            // Or 5-2-2 (3 presses)
            // Or 5-2-1-1-1 (5 presses)
            // The optimal is 1 press.
            presses += 1;
        } else if (diff == 2) {
            // Can be 2 (1 press)
            // Or 1+1 (2 presses)
            // The optimal is 1 press.
            presses += 1;
        } else if (diff == 3) {
            // Can be 2+1 (2 presses)
            // Or 5-2 (2 presses)
            // The optimal is 2 presses.
            presses += 2;
        } else if (diff == 4) {
            // Can be 2+2 (2 presses)
            // Or 5-1 (2 presses)
            // Or 1+1+1+1 (4 presses)
            // The optimal is 2 presses.
            presses += 2;
        }
        std::cout << presses << "\n";
    }
    return 0;
}

