int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
        }
        // The problem statement guarantees that a solution exists.
        // Reversing the permutation always produces a different permutation
        // (unless n=1, but n >= 2) and maintains the same set of adjacent sums.
        // For p = [p_1, p_2, ..., p_{n-1}, p_n], the sums are
        // [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n].
        // For p' = [p_n, p_{n-1}, ..., p_2, p_1], the sums are
        // [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1].
        // These two sets of sums are identical, just in reverse order.
        // Sorting them will result in the same fingerprint.
        // Since n >= 2, p and reverse(p) are different unless p is a palindrome.
        // However, a permutation cannot be a palindrome if n > 1 and elements are distinct 1 to n.
        // For example, if p = [1,2,3,2,1], it's not a permutation.
        // If p = [1,2,3,4,5], reverse is [5,4,3,2,1].
        // If p = [1,2], reverse is [2,1].
        // The only case where p == reverse(p) for a permutation is not possible for n > 1.
        // A permutation of distinct integers from 1 to n cannot be a palindrome
        // unless n=1 (which is not allowed here, n>=2).
        // For example, if n=2, p=[1,2], reverse is [2,1]. Different.
        // If n=3, p=[1,2,3], reverse is [3,2,1]. Different.
        // If p is a permutation, then p_1 != p_n (unless n=1).
        // So p and reverse(p) are always different for n >= 2.
        std::reverse(p.begin(), p.end());
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

