#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    bool possible = true;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] == b[i]) {
            continue;
        }

        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                possible = false;
                break;
            }
        } else { // a[i] > b[i], Need to decrease a[i]
            if (!has_neg_one) {
                possible = false;
                break;
            }
        }

        // Update has_pos_one/has_neg_one for elements to the left
        // This is crucial: if a[i] was the only 1 or -1, it's no longer available for elements to its left.
        // However, the problem states "choose any pair of indexes (i, j) such that 1 <= i < j <= n".
        // This means a[i] can only be modified by elements a[k] where k < i.
        // And a[i] can only modify elements a[j] where j > i.
        // The current logic is checking if a[i] can be made equal to b[i] using elements a[k] where k < i.
        // The `has_pos_one` and `has_neg_one` flags should reflect the availability of 1s and -1s *to the left* of the current index `i`.
        // So, when processing index `i`, `has_pos_one` should indicate if there's any `a[k] == 1` for `k < i`.
        // The current loop iterates from `n-1` down to `0`.
        // `has_pos_one` and `has_neg_one` are initialized based on the *entire* array `a`.
        // This is incorrect. These flags should only consider elements `a[0]...a[i-1]`.

        // Let's re-evaluate the flags.
        // When we are at index `i`, we need to check if there's a `1` or `-1` at an index `k < i`.
        // The initial `has_pos_one` and `has_neg_one` are for the whole array.
        // We need to maintain these flags as we iterate from left to right, or precompute.
        // Since we are iterating from right to left, the flags should be updated *after* processing `a[i]`.
        // If `a[i]` was 1, and we needed to use it to change `a[j]` (j > i), it's fine.
        // But if `a[i]` itself needs to be changed, it cannot be changed by elements to its right.
        // It can only be changed by elements to its left.
        // The problem states "Add a_i to a_j". This means a_i is the source, a_j is the destination.
        // So a_i itself is never changed. This is the key.
        // If a_i is never changed, then the initial values of a_i are what we have to work with.
        // The flags `has_pos_one` and `has_neg_one` should be based on elements `a[0]...a[i-1]` when considering `a[i]`.

        // Let's restart the logic for the flags.
        // We need to check if there's a `1` in `a[0...i-1]` and a `-1` in `a[0...i-1]`.
        // We can maintain these flags as we iterate from left to right.
        // Or, since we iterate from right to left, we can precompute prefix sums of `1`s and `-1`s.
        // No, that's not right. The flags `has_pos_one` and `has_neg_one` should indicate if there's a `1` or `-1` *before* the current index `i`.
        // Let's iterate from `i = 0` to `n-1`.
    }

    // Corrected logic: Iterate from left to right.
    // `can_add_one` means there's an `a[k] == 1` for some `k < current_index`.
    // `can_sub_one` means there's an `a[k] == -1` for some `k < current_index`.

    bool current_can_add_one = false;
    bool current_can_sub_one = false;

    for (int i = 0; i < n; ++i) {
        if (a[i] == b[i]) {
            // If a[i] is 1 or -1, it can be used for elements to its right.
            if (a[i] == 1) current_can_add_one = true;
            if (a[i] == -1) current_can_sub_one = true;
            continue;
        }

        // If a[i] != b[i], we need to change a[i].
        // The only way to change a[i] is by adding a[k] to it, where k < i.
        // This means a[i] must be the 'j' in the operation (i, j).
        // But the problem states "Add a_i to a_j". This means a_i is the source, a_j is the destination.
        // So a_i itself is never changed. This is the key.
        // If a_i is never changed, then `a[i]` must be equal to `b[i]` for all `i`.
        // This interpretation would make the problem trivial: if `a != b`, output NO.
        // The example `[1, -1, 0]` to `[1, 1, -2]` clearly shows `a[1]` changed from `-1` to `1`.
        // This means the problem statement "Add a_i to a_j. In other words, j-th element of the array becomes equal to a_i + a_j."
        // implies that `a_i` is the *original* value of `a_i` at the time of the operation.
        // And `a_j` is the *current* value of `a_j`.
        // The example `[1, -1, 0]` -> `[1, -1, -2]` (by (2,3) twice, i.e., `a_3 = a_3 + a_2 + a_2`)
        // Then `[1, -1, -2]` -> `[1, 1, -2]` (by (1,2) twice, i.e., `a_2 = a_2 + a_1 + a_1`)
        // This means `a_i` is the value *at the time of the operation*.
        // And `a_j` is also the value *at the time of the operation*.
        // The crucial part is that `a_i` can be added to `a_j` only if `i < j`.
        // This means `a[0]` can never be changed. So `a[0]` must equal `b[0]`.
        // For any `a[i]`, it can be changed by adding `a[k]` where `k < i`.
        // The values `a[k]` themselves might have been changed by `a[p]` where `p < k`.
        // This means `a[i]` can become `a[i] + C_1 * a[k_1] + C_2 * a[k_2] + ...` where `k_x < i`.
        // The coefficients `C_x` can be any non-negative integer.
        // So, `a[i]` can be transformed to `a[i] + X` where `X` is a sum of `a[k]`s for `k < i`.
        // If there is a `1` among `a[0]...a[i-1]`, we can add any positive integer to `a[i]`.
        // If there is a `-1` among `a[0]...a[i-1]`, we can add any negative integer to `a[i]`.
        // If both `1` and `-1` are present among `a[0]...a[i-1]`, we can add any integer (positive or negative) to `a[i]`.

        // Let's re-re-evaluate.
        // `a[0]` cannot be changed. So `a[0]` must be equal to `b[0]`.
        if (i == 0) {
            if (a[0] != b[0]) {
                possible = false;
                break;
            }
        } else { // For i > 0
            if (a[i] < b[i]) { // Need to increase a[i]
                if (!current_can_add_one) { // Need a '1' from a[0...i-1]
                    possible = false;
                    break;
                }
            } else if (a[i] > b[i]) { // Need to decrease a[i]
                if (!current_can_sub_one) { // Need a '-1' from a[0...i-1]
                    possible = false;
                    break;
                }
            }
        }

        // Update flags for the next iteration (i+1)
        if (a[i] == 1) current_can_add_one = true;
        if (a[i] == -1) current_can_sub_one = true;
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

