void solve() {
    int n;
    long long T;
    std::cin >> n >> T;
    std::vector<long long> a(n);
    std::vector<int> p(n);

    bool T_is_even = (T % 2 == 0);
    long long T_half = T / 2;

    int current_color_for_half = 0; // 0 for white, 1 for black

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (T_is_even && a[i] == T_half) {
            // For elements equal to T/2, alternate colors
            p[i] = current_color_for_half;
            current_color_for_half = 1 - current_color_for_half;
        } else if (a[i] < T_half) {
            // Elements less than T/2 go to white (0)
            p[i] = 0;
        } else { // a[i] > T_half (or T is odd and a[i] != T/2)
            // Elements greater than T/2 go to black (1)
            p[i] = 1;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";
}

