int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            max_val_in_row = std::max(max_val_in_row, a[i][j]);
        }
        p[i] = max_val_in_row;
    }

    // Check if any element in p is n-1 and no element is n.
    // This happens if the original permutation contained n, and we replaced it with n-1.
    // If so, we need to find the element that was originally n and change it back.
    bool n_found = false;
    for (int val : p) {
        if (val == n) {
            n_found = true;
            break;
        }
    }

    if (!n_found) {
        // This means the original 'n' was replaced by 'n-1' in our reconstruction.
        // We need to find one such 'n-1' and change it to 'n'.
        // Any 'n-1' will do, as there must be exactly one 'n' in the original permutation.
        // If there are multiple 'n-1's, it means one of them was originally 'n' and others were 'n-1'.
        // We can just pick the first one we find.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break; 
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

