        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_R_pos = 0; // Position of the last 'R' or 0

        // Iterate through the string, considering cells 1 to n
        // The string s has indices 0 to n-1, corresponding to cells 1 to n.
        // So s[i] corresponds to cell i+1.
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // If we encounter an 'R' at cell i+1, it means we can jump right from here.
                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - last_R_pos.
                // We need to be able to cover this distance.
                max_dist = std::max(max_dist, (i + 1) - last_R_pos);
                last_R_pos = i + 1; // Update the last 'R' position
            }
        }

        // After checking all 'R's, we need to be able to jump from the last 'R' position
        // (or 0 if no 'R's) to the target cell n+1.
        // The distance is (n+1) - last_R_pos.
        max_dist = std::max(max_dist, (n + 1) - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

