#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of the suffix that is non-increasing
    // from right to left.
    // This is equivalent to finding the first element from the right
    // that breaks the non-decreasing sequence from right to left.
    // Example: [4, 3, 3, 8, 4, 5, 2]
    // i=6, a[6]=2
    // i=5, a[5]=5. a[5] > a[6] (5 > 2). OK.
    // i=4, a[4]=4. a[4] < a[5] (4 < 5). OK.
    // i=3, a[3]=8. a[3] > a[4] (8 > 4). OK.
    // i=2, a[2]=3. a[2] < a[3] (3 < 8). This is the first break.
    // So, the suffix [3, 8, 4, 5, 2] is not good.
    // The suffix [8, 4, 5, 2] is not good.
    // The suffix [4, 5, 2] is good.
    // The "peak" is the first element from the right that is greater than its right neighbor.
    // The "valley" is the first element from the right that is smaller than its right neighbor.

    int i = n - 1;
    // Step 1: Find the end of the non-decreasing suffix (from right to left)
    // This means finding the first element `a[i]` such that `a[i] < a[i+1]`
    // (or `a[i]` is the start of the suffix).
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // i=6, a[6]=2
    // i=5, a[5]=3. a[5] > a[6] (3 > 2). OK.
    // i=4, a[4]=5. a[4] > a[5] (5 > 3). OK.
    // i=3, a[3]=4. a[3] < a[4] (4 < 5). This is the first break.
    // So, the suffix [4, 5, 3, 2] is non-decreasing from right to left.
    // The index `i` will be 3.
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // After this loop, `a[i...n-1]` is non-decreasing from right to left.
    // `i` is the index of the first element of this suffix.
    // If `i` is 0, the whole array is non-decreasing from right to left.

    // Step 2: Find the end of the non-increasing suffix (from right to left)
    // This means finding the first element `a[j]` such that `a[j] > a[j+1]`
    // (or `a[j]` is the start of the suffix).
    // We continue from the `i` found in Step 1.
    // Example: [1, 3, 1, 4, 5, 3, 2]
    // `i` is 3 (a[3]=4).
    // Now we look for `a[j-1] <= a[j]` starting from `j=i`.
    // j=3, a[3]=4.
    // j=2, a[2]=1. a[2] < a[3] (1 < 4). This is the first break.
    // So, the suffix [1, 4, 5, 3, 2] is not non-increasing from right to left.
    // The index `j` will be 2.
    int j = i;
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // After this loop, `a[j...n-1]` is the candidate "good" suffix.
    // `j` is the index of the first element of this candidate suffix.
    // The length of the prefix to erase is `j`.

    std::cout << j << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

