long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m > n) {
        return 0;
    }

    long long count = n / m;
    int m_last_digit = m % 10;

    std::vector<int> cycle_digits;
    long long cycle_sum = 0;

    for (int i = 1; i <= 10; ++i) {
        int current_last_digit = (static_cast<long long>(i) * m_last_digit) % 10;
        cycle_digits.push_back(current_last_digit);
        cycle_sum += current_last_digit;
    }

    long long num_full_cycles = count / 10;
    int remaining_terms = count % 10;

    long long total_sum = num_full_cycles * cycle_sum;

    for (int i = 0; i < remaining_terms; ++i) {
        total_sum += cycle_digits[i];
    }

    return total_sum;
}

