        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
            continue;
        }

        // The quadratic equation for 'a' is a^2 - d*a + d = 0
        // Discriminant delta = (-d)^2 - 4*1*d = d^2 - 4d
        double discriminant = d * d - 4.0 * d;

        if (discriminant < 0.0) {
            std::cout << "N\n";
        } else {
            // Solutions for 'a' are (d +/- sqrt(discriminant)) / 2
            double sqrt_discriminant = std::sqrt(discriminant);

            // We need a and b to be non-negative.
            // Let's choose the '+' sign for 'a' to get a larger value,
            // and then 'b' will be d - a.
            // If a = (d + sqrt_discriminant) / 2, then b = d - a = d - (d + sqrt_discriminant) / 2
            // b = (2d - d - sqrt_discriminant) / 2 = (d - sqrt_discriminant) / 2
            // So the two solutions are (d + sqrt_discriminant) / 2 and (d - sqrt_discriminant) / 2.
            // Let a1 = (d + sqrt_discriminant) / 2
            // Let a2 = (d - sqrt_discriminant) / 2

            // Since d >= 0 and sqrt_discriminant >= 0, a1 will always be non-negative.
            // For a2 to be non-negative, we need d - sqrt_discriminant >= 0, which means d >= sqrt_discriminant.
            // Squaring both sides (since d >= 0 and sqrt_discriminant >= 0), we get d^2 >= discriminant.
            // d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true for all d >= 0.
            // So both solutions for 'a' (and consequently 'b') will be non-negative.

            // We can assign a to be the larger root and b to be the smaller root, or vice versa.
            // The problem statement doesn't specify order.
            // Let's pick a = (d + sqrt_discriminant) / 2.0
            // Then b = d - a.
            double a = (d + sqrt_discriminant) / 2.0;
            double b = d - a; // This will be (d - sqrt_discriminant) / 2.0

            std::cout << std::fixed << std::setprecision(9) << "Y " << a << " " << b << "\n";
        }
    }
    return 0;
}

