            // (c - mid) + (m - mid) + x
            // If this sum is >= mid, then 'mid' teams are possible.
            if (c >= mid && m >= mid && (c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
