#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Check if a peak can exist at index k.
    // For a peak at k, we need:
    // a_i >= i-1 for i = 0 to k-1 (left side)
    // a_i >= n-1-i for i = k to n-1 (right side)
    // The actual values for a_i are a[i].
    // So, we need a[i] >= i for the left side (0-indexed)
    // and a[i] >= n-1-i for the right side (0-indexed)

    // Find the maximum possible length of the strictly increasing prefix
    // starting from 0.
    // This means a[i] must be at least i.
    // If a[i] < i, then we cannot form a strictly increasing sequence
    // 0, 1, ..., i.
    int left_len = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] >= i) {
            left_len++;
        } else {
            break;
        }
    }

    // Find the maximum possible length of the strictly decreasing suffix
    // ending at n-1.
    // This means a[i] must be at least (n-1-i).
    // If a[i] < (n-1-i), then we cannot form a strictly decreasing sequence
    // ..., 1, 0 ending at n-1.
    int right_len = 0;
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] >= (n - 1 - i)) {
            right_len++;
        } else {
            break;
        }
    }

    // If the sum of these lengths is greater than or equal to n,
    // it means there's an overlap or they meet, implying a possible peak.
    // For example, if left_len = 3 and right_len = 3 for n=4,
    // it means a[0]>=0, a[1]>=1, a[2]>=2 (left)
    // and a[3]>=0, a[2]>=1, a[1]>=2 (right)
    // The indices covered by left_len are 0, ..., left_len-1.
    // The indices covered by right_len are n-right_len, ..., n-1.
    // If left_len + right_len > n, it means there's at least one index
    // that can be part of both the increasing prefix and decreasing suffix.
    // This index can be the peak.
    if (left_len + right_len > n) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

