int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        long long total_toys = A + B + C + D;

        // Case 0: Only one toy initially
        if (total_toys == 1) {
            print_bool(A == 1);
            std::cout << " ";
            print_bool(B == 1);
            std::cout << " ";
            print_bool(C == 1);
            std::cout << " ";
            print_bool(D == 1);
            std::cout << "\n";
            continue;
        }

        // Initialize possibilities for each box
        bool can_be_box1 = false; // (-inf, -1]
        bool can_be_box2 = false; // (-1, 0)
        bool can_be_box3 = false; // (0, 1)
        bool can_be_box4 = false; // [1, inf)

        // Total number of negative toys
        long long neg_toys = A + B;

        // Possibility for Box 1: Result is negative and magnitude >= 1
        // To get negative: odd number of negative toys.
        // To get magnitude >= 1:
        //   - At least one toy from Box 1 (value <= -1)
        //   - Or at least one toy from Box 4 (value >= 1)
        //   - And enough other toys to keep magnitude >= 1 (e.g., not too many from Box 2/3)

        // Scenario 1: Final product is negative.
        // This requires an odd number of negative toys (A+B) in the final multiplication chain.
        // If A+B is even, we can always make it odd by introducing a negative toy from A or B,
        // or by pairing up negative toys until one is left.
        // If A+B is odd, the final product will be negative.
        // If A+B is even, the final product will be positive.
        // However, we can control the parity of negative toys by strategically multiplying.
        // For example, if we have two negative toys, we can multiply them to get a positive.
        // If we have three negative toys, we can multiply two to get positive, then positive * negative to get negative.
        // The key is that we can always choose to multiply two negative toys together first to reduce the count of negative toys by 2,
        // or multiply a negative toy with a positive toy, keeping the negative count the same.
        // So, the final sign depends on the parity of the initial count of negative toys (A+B).
        // If (A+B) is odd, the final product must be negative.
        // If (A+B) is even, the final product must be positive.

        // Let's re-evaluate the sign.
        // The final product's sign is determined by the parity of the total number of negative toys (A+B).
        // If (A+B) is odd, the final product is negative.
        // If (A+B) is even, the final product is positive.
        // This is because multiplication preserves the parity of negative factors.
        // (neg * neg = pos), (neg * pos = neg), (pos * pos = pos).
        // Each multiplication either reduces the total number of toys by one,
        // and if it involves two negative toys, it reduces the count of negative toys by two (parity unchanged).
        // If it involves one negative and one positive, it reduces total toys by one, negative count by zero (parity unchanged).
        // If it involves two positive toys, it reduces total toys by one, negative count by zero (parity unchanged).
        // So, the parity of negative toys (A+B) is invariant.

        // Possibility for Box 1 (negative, magnitude >= 1)
        // Requires (A+B) to be odd.
        // Requires at least one toy from Box 1 or Box 4 (to potentially get magnitude >= 1).
        // If A+B is odd:
        //   If A > 0 or D > 0: We have at least one toy with magnitude >= 1.
        //     We can try to keep its magnitude >= 1 by multiplying with other magnitude >= 1 toys (from A or D)
        //     or by multiplying with magnitude < 1 toys (from B or C) but not too many.
        //     It's always possible to end up in Box 1 if A+B is odd and (A>0 or D>0).
        //     Example: If we have one toy in A, and others in B/C/D. Multiply A with B/C/D.
        //     If we have one toy in D, and others in A/B/C. Multiply D with A/B/C.
        //     The only way to guarantee magnitude < 1 is if all toys are from B and C, or if we have very few A/D and many B/C.
        //     But we can always choose to multiply A/D toys together first to maintain magnitude >= 1.
        //     So, if A+B is odd AND (A > 0 OR D > 0), Box 1 is possible.
        //     What if A=0 and D=0? Then all toys are in B and C.
        //     If A=0 and D=0, then all toys have magnitude < 1. The final product will also have magnitude < 1.
        //     So, if A=0 and D=0, Box 1 is impossible.
        if ((A + B) % 2 != 0) { // Final product must be negative
            if (A > 0 || D > 0) { // At least one toy with magnitude >= 1
                can_be_box1 = true;
            }
        }

        // Possibility for Box 2 (negative, magnitude < 1)
        // Requires (A+B) to be odd.
        // Requires that we can make the final magnitude < 1.
        // This is always possible if A+B is odd.
        // We can always multiply with enough toys from B or C to reduce the magnitude below 1.
        // For example, if we have a toy with value -5 (from A) and a toy with value 0.1 (from C),
        // we can multiply them to get -0.5 (Box 2).
        // If we have a toy with value 5 (from D) and a toy with value -0.1 (from B),
        // we can multiply them to get -0.5 (Box 2).
        // The only way this is not possible is if we only have toys from A and D, and A+B is odd.
        // But if A+B is odd, and we only have A and D, then A must be odd and D can be anything.
        // If A is odd and D is anything, we can multiply all D toys together, then multiply all A toys together.
        // The final product will be (product of A toys) * (product of D toys).
        // Both products will have magnitude >= 1. So the final product will have magnitude >= 1.
        // So, if A+B is odd, and (B > 0 or C > 0), Box 2 is possible.
        // What if B=0 and C=0? Then all toys are in A and D.
        // If B=0 and C=0, then all toys have magnitude >= 1. The final product will also have magnitude >= 1.
        // So, if B=0 and C=0, Box 2 is impossible.
        if ((A + B) % 2 != 0) { // Final product must be negative
            if (B > 0 || C > 0) { // At least one toy with magnitude < 1
                can_be_box2 = true;
            }
        }

        // Possibility for Box 3 (positive, magnitude < 1)
        // Requires (A+B) to be even.
        // Requires that we can make the final magnitude < 1.
        // This is always possible if A+B is even.
        // Similar logic to Box 2. If (A+B) is even AND (B > 0 or C > 0), Box 3 is possible.
        // If B=0 and C=0, then all toys are in A and D. All products will have magnitude >= 1.
        // So, if B=0 and C=0, Box 3 is impossible.
        if ((A + B) % 2 == 0) { // Final product must be positive
            if (B > 0 || C > 0) { // At least one toy with magnitude < 1
                can_be_box3 = true;
            }
        }

        // Possibility for Box 4 (positive, magnitude >= 1)
        // Requires (A+B) to be even.
        // Requires at least one toy from Box 1 or Box 4 (to potentially get magnitude >= 1).
        // Similar logic to Box 1. If (A+B) is even AND (A > 0 or D > 0), Box 4 is possible.
        // If A=0 and D=0, then all toys are in B and C. All products will have magnitude < 1.
        // So, if A=0 and D=0, Box 4 is impossible.
        if ((A + B) % 2 == 0) { // Final product must be positive
            if (A > 0 || D > 0) { // At least one toy with magnitude >= 1
                can_be_box4 = true;
            }
        }

        // Edge case: What if all toys are in B and C? (A=0, D=0)
        // Then all magnitudes are < 1. The final product will always have magnitude < 1.
        // So Box 1 and Box 4 are impossible.
        // If A=0, D=0:
        //   (A+B) % 2 != 0 (B is odd): Box 1 (false), Box 2 (true), Box 3 (false), Box 4 (false)
        //   (A+B) % 2 == 0 (B is even): Box 1 (false), Box 2 (false), Box 3 (true), Box 4 (false)
        // This is covered by the logic above:
        // If A=0, D=0:
        //   can_be_box1 = false (because A=0, D=0)
        //   can_be_box2 = (B%2 != 0) && (B>0 || C>0) -> (B%2 != 0) && (B+C > 0)
        //   can_be_box3 = (B%2 == 0) && (B>0 || C>0) -> (B%2 == 0) && (B+C > 0)
        //   can_be_box4 = false (because A=0, D=0)
        // This seems correct. If B+C > 0, then one of Box 2 or Box 3 will be true based on B's parity.

        // Edge case: What if all toys are in A and D? (B=0, C=0)
        // Then all magnitudes are >= 1. The final product will always have magnitude >= 1.
        // So Box 2 and Box 3 are impossible.
        // If B=0, C=0:
        //   (A+B) % 2 != 0 (A is odd): Box 1 (true), Box 2 (false), Box 3 (false), Box 4 (false)
        //   (A+B) % 2 == 0 (A is even): Box 1 (false), Box 2 (false), Box 3 (false), Box 4 (true)
        // This is covered by the logic above:
        // If B=0, C=0:
        //   can_be_box1 = (A%2 != 0) && (A>0 || D>0) -> (A%2 != 0) && (A+D > 0)
        //   can_be_box2 = false (because B=0, C=0)
        //   can_be_box3 = false (because B=0, C=0)
        //   can_be_box4 = (A%2 == 0) && (A>0 || D>0) -> (A%2 == 0) && (A+D > 0)
        // This seems correct. If A+D > 0, then one of Box 1 or Box 4 will be true based on A's parity.

        print_bool(can_be_box1);
        std::cout << " ";
        print_bool(can_be_box2);
        std::cout << " ";
        print_bool(can_be_box3);
        std::cout << " ";
        print_bool(can_be_box4);
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

// Function to check if a sub-array is a permutation of its length
// `arr` is the full array, `start_idx` is the starting index of the sub-array,
// `len` is the length of the sub-array.
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) return false; // Permutations must have non-zero length
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute prefix maximums and suffix maximums
    std::vector<int> prefix_max(n);
    prefix_max[0] = a[0];
    for (int i = 1; i < n; ++i) {
        prefix_max[i] = std::max(prefix_max[i - 1], a[i]);
    }

    std::vector<int> suffix_max(n);
    suffix_max[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        suffix_max[i] = std::max(suffix_max[i + 1], a[i]);
    }

    // Precompute prefix counts and suffix counts
    std::vector<int> prefix_counts(n + 1, 0);
    std::vector<int> suffix_counts(n + 1, 0);

    // Calculate prefix counts for all possible lengths
    std::vector<bool> is_prefix_perm(n + 1, false); // is_prefix_perm[L] means a[0...L-1] is a perm of length L
    std::vector<bool> seen_prefix(n + 1, false);
    int distinct_prefix_count = 0;
    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val > n || seen_prefix[val]) { // val > n is an optimization, can be val > i+1
            // This prefix cannot be a permutation, nor can any longer prefix starting from here
            break; 
        }
        seen_prefix[val] = true;
        distinct_prefix_count++;
        if (distinct_prefix_count == i + 1 && prefix_max[i] == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    // Calculate suffix counts for all possible lengths
    std::vector<bool> is_suffix_perm(n + 1, false); // is_suffix_perm[L] means a[n-L...n-1] is a perm of length L
    std::vector<bool> seen_suffix(n + 1, false);
    int distinct_suffix_count = 0;
    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        if (val > n || seen_suffix[val]) { // val > n is an optimization, can be val > n-i
            // This suffix cannot be a permutation, nor can any longer suffix ending here
            break;
        }
        seen_suffix[val] = true;
        distinct_suffix_count++;
        if (distinct_suffix_count == n - i && suffix_max[i] == n - i) {
            is_suffix_perm[n - i] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 can range from 1 to n-1
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

