    for (int i = 0; i < m; ++i) {
        std::cin >> b[i];
    }

    // Sort A in ascending order of values
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order of values
    std::sort(b.rbegin(), b.rend());

    // Create the result array A'
    // The i-th smallest A value should be paired with the i-th largest B value
    // This is because F(n, k) = k * (n+1) / (k+1)
    // To maximize sum(F(A'_i, B_i)), we want to maximize sum(B_i * (A'_i+1) / (B_i+1))
    // This is equivalent to maximizing sum(A'_i * B_i / (B_i+1) + B_i / (B_i+1))
    // The term B_i / (B_i+1) is always positive and increases with B_i.
    // The term A'_i * B_i / (B_i+1) is also positive.
    // The coefficient B_i / (B_i+1) increases with B_i.
    // To maximize sum(x_i * y_i) where x_i and y_i are positive,
