    // Here, A'_i are the x_i and B_i / (B_i+1) are the y_i.
    // Since B_i / (B_i+1) increases with B_i, we pair the largest A'_i with the largest B_i,
    // the second largest A'_i with the second largest B_i, etc.
    // This means sorting A ascending and B descending, then pairing A[i] with B[i].

    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        result_a_prime[a_elements[i].original_index] = a_elements[i].value;
    }

