#include <numeric>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number to use for generating k distinct differences

    // Generate k distinct differences: k, k-1, ..., 1
    // This is done by alternating between the smallest available and largest available numbers
    // from the range [1, k+1].
    // Example: k=4. Range [1, 5].
    // 1, 5, 2, 4, 3
    // Differences: |5-1|=4, |2-5|=3, |4-2|=2, |3-4|=1
    // This generates k distinct differences: k, k-1, ..., 1.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, pick from left (smallest available)
            p[i] = left;
            left++;
        } else { // Odd index, pick from right (largest available)
            p[i] = right;
            right--;
        }
    }

    // The remaining numbers are k+2, k+3, ..., n.
    // Append them in increasing order to ensure their differences are 1.
    // This does not introduce new distinct differences beyond 1.
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1;
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

