#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left side
    // `i` represents the number of items taken from the left (0 to n)
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Calculate energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += prefix_sum[i] * l;

        // Calculate energy for items taken from the right
        // These are w[i]...w[n-1]
        // The number of items taken from the right is (n - i)
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Apply extra energy costs based on the difference in counts
        int left_count = i;
        int right_count = n - i;

        if (left_count > right_count) {
            // More items taken from left. The last (left_count - right_count) items
            // must have been taken from the left, after all right items were taken.
            // This means (left_count - right_count - 1) times, a left item was taken
            // consecutively after another left item.
            current_energy += (left_count - right_count - 1) * Ql;
        } else if (right_count > left_count) {
            // More items taken from right. The last (right_count - left_count) items
            // must have been taken from the right, after all left items were taken.
            // This means (right_count - left_count - 1) times, a right item was taken
            // consecutively after another right item.
            current_energy += (right_count - left_count - 1) * Qr;
        }
        // If left_count == right_count, no extra Ql or Qr cost is applied.
        // This is because the items are taken alternately, or all from one side then all from other.
        // The problem statement implies that if we take `k` from left and `n-k` from right,
        // the extra cost applies to the *difference* in counts, not the total number of items.
        // For example, if 3 left, 2 right, the sequence could be LRLRL. The 3rd L is consecutive.
        // The number of "extra" items from the left is 3-2=1. The cost is (1-1)*Ql = 0.
        // If 4 left, 2 right, the sequence could be LRLRLL. The 3rd L is consecutive, 4th L is consecutive.
        // The number of "extra" items from the left is 4-2=2. The cost is (2-1)*Ql = Ql.
        // This interpretation matches the sample cases.

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

