#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    // q can be up to 10^9, so its prime factors are relatively small.
    // The largest prime factor of 10^9 is less than 10^9.
    // sqrt(10^9) is approx 31622.
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            long long current_prime_factor = i;

            // Remove all occurrences of current_prime_factor from temp_q
            while (temp_q % current_prime_factor == 0) {
                temp_q /= current_prime_factor;
            }

            // Now current_prime_factor is a prime factor of original q.
            // We need to find the largest divisor of p that is not divisible by q.
            // Consider p / (current_prime_factor^k) such that it's not divisible by q.
            // To make p / (current_prime_factor^k) not divisible by q, we need to remove
            // enough factors of current_prime_factor from p.
            // Specifically, we need to remove one more factor of current_prime_factor
            // than what q has.

            long long current_p = p;
            while (current_p % current_prime_factor == 0 && current_p % q == 0) {
                current_p /= current_prime_factor;
            }
            max_x = std::max(max_x, current_p);
        }
    }

    // If temp_q is still greater than 1, it means temp_q itself is a prime factor
    // (the largest one, if any, after dividing out smaller ones).
    if (temp_q > 1) {
        long long current_prime_factor = temp_q;
        long long current_p = p;
        while (current_p % current_prime_factor == 0 && current_p % q == 0) {
            current_p /= current_prime_factor;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

