    long long chanek_coins = 0;

    while (n > 0) {
        // Chanek's turn
        if (n % 2 != 0) { // N is odd
            chanek_coins += 1;
            n -= 1;
        } else { // N is even
            if (n == 2) { // Special case for N=2
                chanek_coins += 1;
                n -= 1;
            } else {
                // Check if N/2 is odd or even
                // If N/2 is odd, opponent will be forced to take 1 next turn,
                // leaving an even number for Chanek.
                // If N/2 is even, opponent can take N/4, leaving N/4 for Chanek.
                // This is equivalent to checking if N is a power of 2.
                // If N is a power of 2 (and N > 2), then N/2 is also a power of 2.
                // If N is not a power of 2, then N/2 might be odd or even.
                // The optimal strategy for Chanek is to take N/2 if N/2 is odd,
                // or if N/2 is even and taking 1 leads to a worse outcome.
                // The optimal strategy for Chanek is to take 1 if N/2 is even
                // and taking 1 leads to a better outcome.

                // The key insight is that if N is even, Chanek wants to leave an odd number for the opponent
                // if possible, so the opponent is forced to take 1.
                // If N/2 is odd, Chanek takes N/2. Opponent gets an odd number.
                // If N/2 is even, Chanek takes 1. Opponent gets an odd number (N-1).
                // This is not quite right. The opponent also plays optimally.

                // Let's re-evaluate:
                // If N is even:
                // Option 1: Take 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2 (even).
                // Option 2: Take N/2. Remaining N/2.

                // If N is a power of 2 (e.g., 4, 8, 16, ...):
                // Chanek takes N/2. Remaining N/2.
                // Opponent takes N/4. Remaining N/4.
                // Chanek takes N/8. Remaining N/8.
                // ... until N=2. Chanek takes 1. Opponent takes 1.
                // In this scenario, Chanek gets N/2 + N/8 + N/32 + ... + 1.
                // Opponent gets N/4 + N/16 + N/64 + ... + 1.
                // Chanek gets 2/3 of N, Opponent gets 1/3 of N (approximately).
                // Example N=4: Chanek takes 2. N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 2+1=3. Opponent: 1.
                // Example N=8: Chanek takes 4. N=4. Opponent takes 2. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 4+1=5. Opponent: 2+1=3.

                // If N is even but not a power of 2 (e.g., 6, 10, 12, ...):
                // N = 2^k * M, where M is odd and M > 1.
                // Chanek takes N/2. Remaining N/2 = 2^(k-1) * M.
                // If k-1 = 0, then N/2 is odd. Opponent takes 1.
                // If k-1 > 0, then N/2 is even. Opponent can take N/4.

                // The optimal strategy for Chanek when N is even:
                // If N is a power of 2 (N = 2^k, k >= 1):
                // Chanek takes N/2. This leaves N/2 for the opponent.
                // This is because if Chanek takes 1, N-1 is odd. Opponent takes 1. N-2 is even.
                // This seems to lead to Chanek getting less.
                // Example N=4:
                // Chanek takes 1. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 1+1=2. Opponent: 1+1=2.
                // If Chanek takes N/2 (2). N=2. Opponent takes 1. N=1. Chanek takes 1. N=0.
                // Chanek: 2+1=3. Opponent: 1.
                // So for N=4, Chanek takes N/2.

                // If N is even and not a power of 2:
                // N = 2^k * M, where M is odd and M > 1.
                // Chanek takes 1. Remaining N-1 (odd). Opponent takes 1. Remaining N-2 (even).
                // Chanek takes N/2. Remaining N/2 = 2^(k-1) * M.
                // If N/2 is odd (i.e., k=1, N = 2*M):
                // Chanek takes N/2. Remaining N/2 (odd). Opponent takes 1. Remaining N/2 - 1 (even).
                // Chanek takes 1. Remaining N/2 - 2 (odd).
                // This seems better for Chanek.

                // Let's consider the opponent's move.
                // If Chanek leaves an odd number, opponent must take 1.
                // If Chanek leaves an even number, opponent can choose.

                // The optimal strategy for Chanek when N is even:
                // If N is a power of 2 (N = 2^k, k >= 1):
                // Chanek takes N/2. This is always optimal for Chanek.
                // This is because taking 1 leaves N-1 (odd), opponent takes 1, leaving N-2 (even).
                // The game continues with N-2.
                // Taking N/2 leaves N/2 (even). The game continues with N/2.
                // The total coins Chanek gets from N is C(N).
                // If N is power of 2: C(N) = N/2 + C(N/2) (if Chanek takes N/2)
                // C(N) = 1 + C_opp(N-1) (if Chanek takes 1)
                // C_opp(N-1) = 1 + C(N-2) (opponent takes 1 from N-1)
                // So C(N) = 2 + C(N-2)
                // For N=4: C(4) = 2 + C(2) = 2 + (1 + C_opp(1)) = 2 + 1 + 0 = 3. (Chanek takes 1, Opponent takes 1, Chanek takes 1)
                // If Chanek takes N/2: C(4) = 2 + C_opp(2) = 2 + 1 = 3. (Chanek takes 2, Opponent takes 1, Chanek takes 1)
                // Wait, the example for N=4 gives 3.
                // Example N=6: Chanek takes 3. N=3. Opponent takes 1. N=2. Chanek takes 1. N=1. Opponent takes 1. N=0.
                // Chanek: 3+1=4. Opponent: 1+1=2.
