                //   Take 1: Chanek gets 1 + Opponent's_coins_from(N-1).
                //   Opponent's_coins_from(N-1) = 1 + Chanek's_coins_from(N-2).
                //   So Chanek gets 1 + (1 + Chanek's_coins_from(N-2)) = 2 + Chanek's_coins_from(N-2).
                //   It's known that for powers of 2, taking N/2 is optimal.

                // If N is even but not a power of 2:
                // N = 2^k * M, M > 1 odd.
                // If Chanek takes N/2: N/2 = 2^(k-1) * M.
                // If k=1, N/2 is odd. Opponent takes 1.
                // If k>1, N/2 is even. Opponent can take N/4.
                // If Chanek takes 1: N-1 is odd. Opponent takes 1. N-2 is even.
                // The strategy is to try to leave an odd number for the opponent if possible.
                // If N is even:
                //   If N/2 is odd (i.e., N = 2 * M, M is odd):
                //     Chanek takes N/2. Leaves M (odd) for opponent. Opponent takes 1.
                //     Chanek gets N/2.
                //   If N/2 is even (i.e., N = 4 * M, M can be anything):
                //     Chanek takes 1. Leaves N-1 (odd) for opponent. Opponent takes 1.
                //     Chanek gets 1.
                // This is the correct logic.

                // Check if N/2 is odd. This is equivalent to checking if N is 2 * (odd number).
                // Or, N is even, and N/2 is odd.
                // This means N has exactly one factor of 2.
                // N % 4 != 0 implies N = 2 * (odd number).
                if ((n / 2) % 2 != 0) { // N/2 is odd (e.g., N=6, N/2=3)
                    chanek_coins += n / 2;
                    n /= 2;
                } else { // N/2 is even (e.g., N=4, N/2=2; N=8, N/2=4; N=12, N/2=6)
                    // This means N is divisible by 4.
                    // In this case, Chanek takes 1.
                    chanek_coins += 1;
                    n -= 1;
                }
            }
        }

        if (n == 0) break;

        // Opponent's turn (same logic, but we don't care about their coins, just N)
        if (n % 2 != 0) { // N is odd
            n -= 1;
        } else { // N is even
            if (n == 2) {
                n -= 1;
            } else {
                if ((n / 2) % 2 != 0) { // N/2 is odd
                    n /= 2;
                } else { // N/2 is even
                    n -= 1;
                }
            }
        }
    }
    return chanek_coins;
}

