        long long abs_m = std::abs(m);
        long long max_coord = std::max(abs_n, abs_m);
        long long min_coord = std::min(abs_n, abs_m);

        if (k < max_coord) {
            std::cout << -1 << "\n";
            continue;
        }

        long long ans;
        long long diff = max_coord - min_coord;

        if (diff % 2 == 0) { // max_coord and min_coord have same parity
            if ((k - max_coord) % 2 == 0) {
                ans = k;
            } else {
                ans = k - 2;
            }
        } else { // max_coord and min_coord have different parity
            ans = k - 1;
        }

        std::cout << ans << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool possible = false;

    for (char pivot_char = '0'; pivot_char <= '9'; ++pivot_char) {
        char last1 = '0'; // Last digit colored 1
        char first2 = '9' + 1; // First digit colored 2 (initialized to a value greater than any digit)
        bool current_possible = true;

        // First pass: assign colors based on pivot_char
        // Digits < pivot_char get 1
        // Digits > pivot_char get 2
        // Digits == pivot_char are initially unassigned (marked with '0')
        for (int i = 0; i < n; ++i) {
            if (s[i] < pivot_char) {
                result[i] = '1';
            } else if (s[i] > pivot_char) {
                result[i] = '2';
            } else { // s[i] == pivot_char
                result[i] = '0'; // Mark as unassigned for now
            }
        }

        // Second pass: assign '0's (digits equal to pivot_char)
        // The first occurrence of pivot_char and subsequent ones that maintain non-decreasing order for color 1
        // will be colored 1.
        // The remaining pivot_char digits will be colored 2.
        // This means we find the *last* pivot_char that can be colored 1.
        // All pivot_chars before or at this index are 1, all after are 2.
        int last_pivot_for_1 = -1;
        for (int i = n - 1; i >= 0; --i) {
            if (result[i] == '0') { // This is a pivot_char digit
                last_pivot_for_1 = i;
                break;
            }
        }

        // If no pivot_char digits exist, last_pivot_for_1 remains -1.
        // In this case, all '0's are already assigned to '1' or '2'.
        // The loop below will correctly handle this as it won't find any '0's.

        for (int i = 0; i < n; ++i) {
            if (result[i] == '0') { // This is a pivot_char digit
                if (i <= last_pivot_for_1) {
                    result[i] = '1';
                } else {
                    result[i] = '2';
                }
            }
        }

        // Third pass: validate the coloring
        std::string s1_digits;
        std::string s2_digits;

        for (int i = 0; i < n; ++i) {
            if (result[i] == '1') {
                s1_digits.push_back(s[i]);
            } else { // result[i] == '2'
                s2_digits.push_back(s[i]);
            }
        }

        // Check if s1_digits is non-decreasing
        for (size_t i = 0; i + 1 < s1_digits.length(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                current_possible = false;
                break;
            }
        }
        if (!current_possible) continue;

        // Check if s2_digits is non-decreasing
        for (size_t i = 0; i + 1 < s2_digits.length(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                current_possible = false;
                break;
            }
        }
        if (!current_possible) continue;

        // Check if last digit of s1_digits <= first digit of s2_digits
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                current_possible = false;
            }
        }

        if (current_possible) {
            possible = true;
            break;
        }
    }

    if (possible) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

