#include <iostream>
#include <string>
#include <vector>
#include <set>
#include <map>
#include <algorithm>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_password;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_password.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i - 1]);
            adj[s[i - 1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find a starting character for the layout chain
    char start_char = '\0';
    for (char c : used_in_password) {
        if (adj[c].size() <= 1) { // Degree 0 or 1
            start_char = c;
            break;
        }
    }

    // If all characters in password have degree 2, it means they form a cycle.
    // This is problematic because a keyboard layout is a path, not a cycle.
    // However, if there's only one connected component and all nodes have degree 2,
    // it means it's a cycle. If there are multiple components, some might be paths.
    // The problem implies a single path for the password characters.
    // If all characters in `used_in_password` have degree 2, and they form a single component,
    // then it's a cycle. A cycle cannot be laid out as a single path.
    // Example: abcda -> a-b-c-d-a. All have degree 2.
    // If `used_in_password` is not empty and `start_char` is still `\0`, it means all
    // characters in `used_in_password` have degree 2.
    if (!used_in_password.empty() && start_char == '\0') {
        // This means all characters in `used_in_password` have degree 2.
        // We need to check if they form a single connected component.
        // If they do, it's a cycle, which is impossible.
        // If they form multiple components, some might be paths, but the problem
        // implies a single path for the password characters.
        // A simple check: if we start from any character and traverse,
        // if we visit all `used_in_password` characters and return to start, it's a cycle.
        // This is implicitly handled by the path construction below.
        // If we can't find a start_char with degree <= 1, it means all password chars
        // have degree 2. This implies a cycle or multiple cycles.
        // A single path cannot accommodate a cycle.
        // So, if start_char is still '\0', it's impossible.
        std::cout << "NO\n";
        return;
    }

    // If password is empty or contains only one unique character, start_char might be '\0'.
    // In this case, any character can be a start. Let's pick 'a'.
    if (start_char == '\0' && !used_in_password.empty()) {
        // This case should be covered by the previous check.
        // If used_in_password is not empty and start_char is still '\0', it means all
        // characters in used_in_password have degree 2. This implies a cycle.
        // So, it should have printed NO already.
        // If used_in_password is empty (e.g., s is empty, but |s| >= 1), this branch is not taken.
        // If s has only one unique char, e.g., "a", then adj is empty, used_in_password = {'a'}.
        // start_char will be 'a'.
    }

    if (start_char == '\0') { // This happens if s is empty, but problem says |s| >= 1.
                              // Or if s has only one unique character, e.g., "a".
                              // In this case, adj is empty, used_in_password has one char.
                              // The loop for start_char will find it.
                              // So start_char should never be '\0' here if used_in_password is not empty.
        // If used_in_password is empty, it means s is empty. But |s| >= 1.
        // So this branch should not be reached.
        // Let's just pick 'a' if somehow it's still null.
        start_char = 'a';
    }

    char current_char = start_char;
    char prev_char = '\0'; // Sentinel for the first character

    while (visited_in_layout.size() < used_in_password.size()) {
        if (visited_in_layout.count(current_char)) {
            // This means we've encountered a cycle that we can't resolve as a path.
            // Or we've tried to add a character already in the layout.
            // This should not happen if we correctly identify start_char and follow neighbors.
            // If it happens, it implies an issue with the graph structure (e.g., a cycle).
            std::cout << "NO\n";
            return;
        }
        layout_str += current_char;
        visited_in_layout.insert(current_char);

        char next_char = '\0';
        for (char neighbor : adj[current_char]) {
            if (neighbor != prev_char) {
                next_char = neighbor;
                break;
            }
        }

        if (next_char == '\0') { // End of a path
            break;
        }

        prev_char = current_char;
        current_char = next_char;
    }

    // Add remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    if (layout_str.length() != 26) {
        // This should not happen if logic is correct, but as a safeguard.
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;

    if (n == 0) {
        return 0;
    }

    int k = static_cast<int>(std::ceil(std::sqrt(static_cast<double>(n))));

    for (int i = 0; i < n; ++i) {
        int block_idx = i / k;
        int start_of_block = block_idx * k;
        int end_of_block = std::min(n, (block_idx + 1) * k);

        // The element at index `i` in the output permutation
        // should be `end_of_block - 1 - (i % k)`
        // This effectively reverses the order of blocks, and within each block,
        // it places elements in increasing order.
        // Example: n=4, k=2
        // Blocks: [1,2], [3,4]
        // Output: [3,4,1,2]
        // i=0: block_idx=0. start=0, end=2. Output element is (2-1) - (0%2) = 1. This is wrong.
        // The logic should be:
        // For block_idx = 0, elements are 1, 2.
        // For block_idx = 1, elements are 3, 4.
        // We want to print block 1, then block 0.
        // So, for i=0, print 3. For i=1, print 4.
        // For i=2, print 1. For i=3, print 2.

        // Let's re-think the construction:
        // We want to print numbers in groups of `k`, but in reverse order of groups.
        // Group `j` (0-indexed) contains numbers `j*k + 1` to `min((j+1)*k, n)`.
        // The last group is `(num_blocks - 1)`.
        // The second to last group is `(num_blocks - 2)`.
        // ...
        // The first group is `0`.

        // So, for the `i`-th element of the output:
        // Determine which block it belongs to in the *reversed* sequence.
        // The `i`-th element (0-indexed) will be from block `(num_blocks - 1) - (i / k)`.
        // Within that block, it will be the `(i % k)`-th element.

        int num_blocks = (n + k - 1) / k; // ceil(n/k)

        int current_block_in_reversed_order = (num_blocks - 1) - (i / k);

        int value_in_block = (i % k); // 0-indexed position within the block

        int actual_value = current_block_in_reversed_order * k + 1 + value_in_block;

        std::cout << actual_value << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>
#include <iomanip>
#include <map>

// Function to compute Z-array for a string
std::vector<int> compute_z_array(const std::string& s) {
    int n = s.length();
    std::vector<int> z(n);
    z[0] = n; // Conventionally, z[0] is n
    int l = 0, r = 0;
    for (int i = 1; i < n; ++i) {
        if (i <= r) {
            z[i] = std::min(r - i + 1, z[i - l]);
        }
        while (i + z[i] < n && s[z[i]] == s[i + z[i]]) {
            ++z[i];
        }
        if (i + z[i] - 1 > r) {
            l = i;
            r = i + z[i] - 1;
        }
    }
    return z;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;
    int n = s.length();

    // Precompute Z-arrays for all suffixes of s
    // z_arrays[i] stores the Z-array for s.substr(i)
    std::vector<std::vector<int>> z_arrays(n);
    for (int i = 0; i < n; ++i) {
        z_arrays[i] = compute_z_array(s.substr(i));
    }

    // Precompute LCP for s[i..] and s[j..]
    // lcp_val[i][j] stores LCP(s[i..], s[j..])
    // This is equivalent to z_arrays[i][j-i] if j > i, or z_arrays[j][i-j] if i > j
    auto get_lcp = [&](int i, int j) {
        if (i == j) return n - i; // LCP of a string with itself is its length
        if (i > j) std::swap(i, j); // Ensure i < j
        // Now i < j. We need LCP(s[i..], s[j..]).
        // This is z_arrays[i][j-i]
        return z_arrays[i][j - i];
    };

    // Group indices by their starting character
    std::map<char, std::vector<int>> char_indices;
    for (int i = 0; i < n; ++i) {
        char_indices[s[i]].push_back(i);
    }

    double total_win_probability = 0.0;

    // Iterate over each possible first character c_0
    for (auto const& [c0_char, k_candidates] : char_indices) {
        // k_candidates contains all indices i such that s[i] == c0_char
        int num_k_candidates = k_candidates.size();
        if (num_k_candidates == 0) continue; // Should not happen if char_indices is built correctly

        // If only one k is possible, Vasya wins immediately
        if (num_k_candidates == 1) {
            total_win_probability += 1.0 / n;
            continue;
        }

        // Vasya needs to choose a position p to maximize his win probability for this c_0
        double max_win_prob_for_c0 = 0.0;

        // Iterate over all possible positions p (1-indexed, so p_idx = p-1)
        // p_idx can range from 0 to n-1.
        // Vasya already knows t[0], so he can choose p_idx from 1 to n-1.
        // The problem statement says "open one more letter on some position",
        // implying it's different from the first one.
        // However, if p_idx=0 is allowed, it means he asks for t[0] again, which gives no new info.
        // Let's assume p_idx can be any index from 0 to n-1, but he'll only choose p_idx > 0 if it helps.
        // The problem states "after he sees it, open one more letter on some position".
        // This implies p_idx != 0.
        // Let's iterate p_idx from 1 to n-1.
        for (int p_idx = 1; p_idx < n; ++p_idx) {
            // For a fixed c_0 and chosen p_idx, count how many k's lead to a unique outcome.
            int wins_for_this_p = 0;

            // Group k_candidates by the pair (s[k], s[(k+p_idx)%n])
            // This is equivalent to (t[0], t[p_idx])
            std::map<std::pair<char, char>, std::vector<int>> outcomes;
            for (int k_val : k_candidates) {
                outcomes[{s[k_val], s[(k_val + p_idx) % n]}].push_back(k_val);
            }

            // Check if each outcome group leads to a unique k
            for (auto const& [outcome_pair, current_k_group] : outcomes) {
                if (current_k_group.size() == 1) {
                    wins_for_this_p++;
                } else {
                    // If multiple k's lead to the same (t[0], t[p_idx]) pair,
                    // Vasya needs to check if these k's can be distinguished.
                    // These k's are k_1, k_2, ..., k_m.
                    // They all satisfy s[k_i] = t[0] and s[(k_i + p_idx) % n] = t[p_idx].
                    // Vasya wins if for any two distinct k_a, k_b in this group,
                    // the string s_k_a is different from s_k_b.
                    // This is equivalent to checking if s_k_a == s_k_b for any pair.
                    // If s_k_a == s_k_b, then Vasya cannot distinguish them.
                    // Vasya wins for this group if all s_k_i are distinct.

                    // To check if all s_k_i are distinct:
                    // For any two k_a, k_b in current_k_group, if s_k_a == s_k_b, Vasya loses for this group.
                    // s_k_a == s_k_b means s[k_a..] is cyclically equal to s[k_b..].
                    // This happens if and only if s[k_a..] == s[k_b..] (as strings)
                    // or s[k_a..] is a cyclic shift of s[k_b..] and vice versa.
                    // More simply, s_k_a == s_k_b if and only if LCP(s[k_a..], s[k_b..]) == n - k_a
                    // AND LCP(s[k_b..], s[k_a..]) == n - k_b.
                    // This is equivalent to checking if s[k_a..] == s[k_b..] as substrings of length n-k_a and n-k_b.
                    // No, this is not correct. s_k_a == s_k_b means the full strings are identical.
                    // This means s[k_a]s[k_a+1]...s[n-1]s[0]...s[k_a-1] == s[k_b]s[k_b+1]...s[n-1]s[0]...s[k_b-1].
                    // This is true if and only if k_a and k_b are "equivalent" shifts.
                    // Two shifts i and j are equivalent if s_i == s_j.
                    // This happens if s is periodic and j-i is a multiple of the period.
                    // For example, if s = "abab", s_0 = "abab", s_2 = "abab".
                    // We need to count how many *distinct* cyclic shifts are in current_k_group.
                    // If this count is 1, Vasya wins for this group. Otherwise, he loses.

                    // Use a set to store canonical representations or just compare full strings.
                    // Comparing full strings is too slow.
                    // We need to check if all k_i in current_k_group correspond to distinct cyclic shifts.
                    // For any two k_a, k_b in current_k_group, if s_k_a == s_k_b, then Vasya loses for this group.
                    // So, Vasya wins for this group if and only if all s_k_i are distinct.
                    // This means we need to count the number of distinct cyclic shifts among current_k_group.
                    // If this count is 1, Vasya wins. Otherwise, he loses.

                    // To check if s_k_a == s_k_b:
                    // This is true if and only if s[k_a..n-1] + s[0..k_a-1] == s[k_b..n-1] + s[0..k_b-1].
                    // This is equivalent to checking if s[k_a..] is equal to s[k_b..] when considering s as a cyclic string.
                    // This can be done by comparing s+s.
                    // LCP(s+s, k_a, k_b) where LCP is on s+s.
                    // LCP(s[k_a..], s[k_b..]) on the original string s.
                    // If LCP(s[k_a..], s[k_b..]) >= n - max(k_a, k_b), then they match up to the end of s.
                    // Then we need to compare s[0..] with s[0..] for the remaining part.
                    // This is exactly what LCP on s+s does.
                    // LCP(s[k_a..] + s[0..k_a-1], s[k_b..] + s[0..k_b-1])
                    // This is LCP of s_k_a and s_k_b.
                    // If LCP(s_k_a, s_k_b) == n, then s_k_a == s_k_b.

                    // We need to check if there exist k_a, k_b in current_k_group such that s_k_a == s_k_b.
                    // If such a pair exists, Vasya loses for this group.
                    // If all s_k_i are distinct, Vasya wins for this group.

                    bool all_distinct_shifts = true;
                    for (size_t i = 0; i < current_k_group.size(); ++i) {
                        for (size_t j = i + 1; j < current_k_group.size(); ++j) {
                            int k_a = current_k_group[i];
                            int k_b = current_k_group[j];

