#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // If robot cannot move left (f1=0), it cannot reach any point with x < its current x.
            // So, the target X must be >= its current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // If robot cannot move up (f2=0), it cannot reach any point with y > its current y.
            // So, the target Y must be <= its current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
            // If robot cannot move right (f3=0), it cannot reach any point with x > its current x.
            // So, the target X must be <= its current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If robot cannot move down (f4=0), it cannot reach any point with y < its current y.
            // So, the target Y must be >= its current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 with modulo.
    // If b-1 is even, (b-1)/2 * b
    // If b is even, (b)/2 * (b-1)
    long long sum_r;
    if (b == 1) { // If b=1, then b-1=0, so sum_r is 0.
        sum_r = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long inv2 = 500000004; // Modular inverse of 2 mod 10^9+7
        sum_r = (b_minus_1 % MOD * (b % MOD)) % MOD;
        sum_r = (sum_r * inv2) % MOD;
    }

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_{k=1 to a} k = a * (a+1) / 2
    // sum_{k=1 to a} 1 = a
    long long sum_k_val;
    long long inv2 = 500000004; // Modular inverse of 2 mod 10^9+7
    sum_k_val = (a % MOD * ((a + 1) % MOD)) % MOD;
    sum_k_val = (sum_k_val * inv2) % MOD;

    long long sum_k_b_plus_1 = (b % MOD * sum_k_val) % MOD;
    sum_k_b_plus_1 = (sum_k_b_plus_1 + (a % MOD)) % MOD;

    // Total sum = sum_r * sum_k_b_plus_1
    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

