        int n = s.length();

        // Max length of a substring we need to consider for its value
        // 2^17 = 131072, 2^18 = 262144. Max N is 2e5.
        // So, a binary number representing a value up to 2e5 needs at most 18 bits.
        // If a substring starts with '1', its value is at least 2^(len-1).
        // If len-1 >= 18, then 2^(len-1) > 2e5. So len-1 can be at most 17.
        // Thus, len can be at most 18.
        // If a substring starts with '0', its value is smaller.
        // The maximum length of a substring whose value we might need to compute
        // is limited by the maximum possible value (N).
        // log2(2e5) approx 17.6. So max_bits_for_value = 18.
        // We can iterate up to a small constant number of bits, say 20, to be safe.
        // Let's use 20 as a practical upper bound for `k` (length of substring starting with '1')
        // or `k_prime` (length of substring starting with '0' after leading zeros).
        const int MAX_BITS_TO_CHECK = 20; 

        for (int i = 0; i < n; ++i) {
            // Case 1: Substring starts with '1'
            if (s[i] == '1') {
                long long current_val = 0;
                for (int j = i; j < n; ++j) {
                    // If the substring is too long, its value will exceed N
                    // if it starts with '1' and has length > MAX_BITS_TO_CHECK.
                    // Specifically, if current_val * 2 overflows long long, or
                    // if current_val * 2 + 1 exceeds N and j-i+1 > MAX_BITS_TO_CHECK.
                    // We can cap the length of substrings we check for value.
                    // If j - i + 1 > MAX_BITS_TO_CHECK, then 2^(j-i) > 2^MAX_BITS_TO_CHECK.
                    // If MAX_BITS_TO_CHECK is 20, 2^20 is 1M.
                    // If N is 2e5, then 2^(j-i) will quickly exceed N.
                    // So, we only need to check substrings of length up to MAX_BITS_TO_CHECK.
                    if (j - i + 1 > MAX_BITS_TO_CHECK) {
                        break; 
                    }

                    current_val = (current_val << 1) | (s[j] - '0');

                    // Check if current_val exceeds N. If it does, no longer good.
                    // This check is important because current_val can grow large.
                    // If current_val > n, then it cannot be equal to j-i+1 (which is <= n).
                    if (current_val > n) {
                        break;
                    }

                    if (current_val == (j - i + 1)) {
                        good_substrings_count++;
                    }
                }
            }
            // Case 2: Substring starts with '0'
            else { // s[i] == '0'
                // Count consecutive leading zeros
                int zero_count = 0;
                int k = i;
                while (k < n && s[k] == '0') {
                    zero_count++;
                    k++;
                }

                // If we reached end of string, all are zeros.
                // f(0...0) = 0. Length is zero_count.
                // If zero_count == 0, it's a good substring.
                // This only happens if the substring is "0".
                // If zero_count > 0, and f(0...0) = 0, then 0 == zero_count is false unless zero_count is 0.
                // But zero_count is at least 1 here. So no good substrings of all zeros.
                // The only exception is if the substring is "0" and its length is 0, which is impossible.
                // So, f(0) = 0, length = 1. Not good.
                // f(00) = 0, length = 2. Not good.
                // So, a substring of all zeros is never good.

                // Now consider substrings starting with '0' followed by '1'.
                // The actual binary value starts from the first '1'.
                // Let's say the substring is s[i...j].
                // It has `zero_count` leading zeros.
                // The actual binary value is f(s[i+zero_count ... j]).
                // The length is j - i + 1.
                // We need j - i + 1 == f(s[i+zero_count ... j]).

                // The value f(s[i+zero_count ... j]) can be at most N.
                // The length of the non-zero part (s[i+zero_count ... j]) can be at most MAX_BITS_TO_CHECK.
