                long long current_val = 0;
                for (int j = k; j < n; ++j) { // k is the index of the first '1' after leading zeros
                    // If the length of the non-zero part exceeds MAX_BITS_TO_CHECK,
                    // its value will be too large to be equal to j-i+1 (which is <= N).
                    if (j - k + 1 > MAX_BITS_TO_CHECK) {
                        break;
                    }

                    current_val = (current_val << 1) | (s[j] - '0');

                    // The total length of the substring is (j - i + 1).
                    // We need to check if current_val == (j - i + 1).
                    // If current_val exceeds N, it cannot be equal to j-i+1.
                    if (current_val > n) {
                        break;
                    }

                    if (current_val == (j - i + 1)) {
                        good_substrings_count++;
                    }
                }
            }
        }
        std::cout << good_substrings_count << "\n";
    }
    return 0;
}

