// Function to apply one step of median smoothing
// Returns true if the sequence changed, false otherwise
bool apply_median_smoothing(std::vector<int>& a) {
    int n = a.size();
    if (n < 3) { // Sequences of length 0, 1, 2 are always stable by definition
        return false;
    }

    std::vector<int> b = a; // Create a copy for the new sequence
    bool changed = false;

    // b_1 = a_1 and b_n = a_n, so no change for ends

    for (int i = 1; i < n - 1; ++i) { // i from 1 to n-2 (0-indexed)
        // Median of a[i-1], a[i], a[i+1]
        // For 0s and 1s, median is 1 if sum >= 2, else 0
        int sum = a[i - 1] + a[i] + a[i + 1];
        int median_val = (sum >= 2) ? 1 : 0;

        if (b[i] != median_val) {
            b[i] = median_val;
            changed = true;
        }
    }

    a = std::move(b); // Update the original sequence
    return changed;
}

