    // Then x = (1 + a[1]) - a[1 + a[1]], y = a[1] + a[1 + a[1]].
    // This means the first step always involves a[1].
    // The subsequent steps involve a[x] where x > 1.
    // So, we can precompute results for starting positions x_curr > 1.

    // dp_y[k] stores the final y value if the program starts with x=k, y=0, and a[k] is the value used for the first step.
    // dp_x[k] stores the final x value if the program starts with x=k, y=0, and a[k] is the value used for the first step.
    // This is slightly different from the problem's flow.
    // Let's define dp_y[k] as the *additional* y accumulated and dp_x[k] as the *next* x if we are at position k and just performed step 2 (x += a[k], y += a[k]).
    // Then we need to perform step 3 (x -= a[x], y += a[x]).
    // This is a standard dynamic programming approach for paths on a graph.

    // dp_y[k] will store the total y accumulated from position k onwards, assuming we just landed on k.
    // dp_x[k] will store the final x position from k onwards.
    // We need to compute these for k from 2 to n.
    // The values a[k] for k >= 2 are fixed.

    // Let's define dp_y[k] as the total y accumulated and dp_x[k] as the final x,
    // if the program *starts* at x=k, y=0, and the first operation is x += a[k], y += a[k].
    // This is exactly what we need for the second part of the cycle.
    // The values a[k] for k >= 2 are fixed.
    // We can compute these using memoization or iteration from n down to 2.

    for (int k = 2; k <= n; ++k) {
        long long current_a_k = a[k];
        long long x_after_step2 = k + current_a_k;
        long long y_after_step2 = current_a_k;

        if (x_after_step2 <= 0 || x_after_step2 > n) {
            dp_y[k] = y_after_step2;
            dp_x[k] = x_after_step2;
        } else {
            // Now we are at x_after_step2, y_after_step2.
            // We need to perform step 3: x -= a[x], y += a[x].
            // This means we need the result of starting at x_after_step2.
            // This is a recursive definition.
            // Let's use a standard DP approach with memoization.
            // We need to handle cycles.

            // Use a temporary state to detect cycles during computation
            std::vector<int> visited_path;
            int current_pos = k;
            long long current_y_accum = 0;

            while (current_pos >= 1 && current_pos <= n && dp_y[current_pos] == -2) {
                // Mark as currently visiting to detect cycles
                dp_y[current_pos] = -1; // Temporarily mark as potentially infinite
                dp_x[current_pos] = -1; // Temporarily mark as potentially infinite
                visited_path.push_back(current_pos);

                long long val_a_curr = a[current_pos];

                // Step 2: x += a[x], y += a[x]
                long long next_x_step2 = current_pos + val_a_curr;
                long long next_y_step2 = current_y_accum + val_a_curr;

                if (next_x_step2 <= 0 || next_x_step2 > n) {
                    // Terminate after step 2
                    for (int node : visited_path) {
                        dp_y[node] = next_y_step2;
                        dp_x[node] = next_x_step2;
                    }
                    goto next_k_loop; // Break out of inner while and continue outer for loop
                }

                // Step 3: x -= a[x], y += a[x]
                long long val_a_next_step2 = a[next_x_step2];
                long long next_x_step3 = next_x_step2 - val_a_next_step2;
                long long next_y_step3 = next_y_step2 + val_a_next_step2;

                if (next_x_step3 <= 0 || next_x_step3 > n) {
                    // Terminate after step 3
                    for (int node : visited_path) {
                        dp_y[node] = next_y_step3;
                        dp_x[node] = next_x_step3;
                    }
                    goto next_k_loop; // Break out of inner while and continue outer for loop
                }

                // Continue to next iteration with new x and y
                current_pos = next_x_step3;
                current_y_accum = next_y_step3;

                // Check if we hit a node already in the current path (cycle)
                for (size_t i = 0; i < visited_path.size(); ++i) {
                    if (visited_path[i] == current_pos) {
                        // Cycle detected
                        for (int node : visited_path) {
                            dp_y[node] = -1;
                            dp_x[node] = -1;
                        }
                        goto next_k_loop;
                    }
                }
            }

            // If we exited the loop because dp_y[current_pos] was already computed
            if (current_pos <= 0 || current_pos > n) {
                // Terminated outside bounds
                for (int node : visited_path) {
                    dp_y[node] = current_y_accum;
                    dp_x[node] = current_pos;
                }
            } else if (dp_y[current_pos] == -1) {
                // Hit an infinite loop
                for (int node : visited_path) {
                    dp_y[node] = -1;
                    dp_x[node] = -1;
                }
            } else {
                // Hit a previously computed state
                for (int node : visited_path) {
                    dp_y[node] = current_y_accum + dp_y[current_pos];
                    dp_x[node] = dp_x[current_pos];
                }
            }
        }
        next_k_loop:;
    }

    // Now, for each i from 1 to n-1, simulate the program
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a[1] for the current run

        long long current_x = 1;
        long long current_y = 0;

        // Step 2: x += a[x], y += a[x]
        long long val_a_curr = a[current_x];
        current_x += val_a_curr;
        current_y += val_a_curr;

        if (current_x <= 0 || current_x > n) {
            std::cout << current_y << "\n";
            continue;
        }

        // Now we are at current_x, current_y.
        // We need to perform step 3: x -= a[x], y += a[x].
        // This is exactly the state that dp_y[current_x] and dp_x[current_x] represent.
        // The values a[k] for k >= 2 are fixed, so dp_y[current_x] and dp_x[current_x] are valid.
        // If current_x is 1, then a[1] is 'i', which is different from the precomputed a[1] (if any).
        // However, our DP table is only for k >= 2.
        // So, if current_x == 1, we need to re-simulate.
        // But current_x will be 1 + a[1], which is 1 + i. Since i >= 1, current_x will be >= 2.
        // So, current_x will always be >= 2 after the first step 2.
        // Thus, we can always use the precomputed DP values.

        if (dp_y[current_x] == -1) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y + dp_y[current_x] << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <map>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int initial_diff = initial_s - initial_b;

    // Precompute prefix sums for differences (1 -> +1, 2 -> -1)
    // For left side (jars 0 to n-1)
    // For right side (jars n to 2n-1)

    // diff_L[k] = (count of 1s - count of 2s) in jars 0 to k-1
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // diff_R[k] = (count of 1s - count of 2s) in jars 2n-1 down to 2n-k
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Map to store the minimum k_L for a given diff_L value
    std::map<int, int> min_kL_for_diff;
    for (int k_L = 0; k_L <= n; ++k_L) {
        int current_diff_L = diff_L[k_L];
        if (min_kL_for_diff.find(current_diff_L) == min_kL_for_diff.end()) {
            min_kL_for_diff[current_diff_L] = k_L;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible removals

    // Iterate through all possible k_R values
    for (int k_R = 0; k_R <= n; ++k_R) {
        int current_diff_R = diff_R[k_R];
        // The remaining jars have a difference of initial_diff - current_diff_L - current_diff_R
        // We want this to be 0.
        // So, initial_diff - current_diff_L - current_diff_R = 0
        // This means current_diff_L = initial_diff - current_diff_R
        int target_diff_L = initial_diff - current_diff_R;

        if (min_kL_for_diff.count(target_diff_L)) {
            int k_L = min_kL_for_diff[target_diff_L];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n, LLONG_MAX); // Represents a_i + delta_i_at_max_op_time <= m_k
                                                  // So, a_i <= m_k - delta_i_at_max_op_time
                                                  // We want to find the largest possible a_i, so a_i = min(m_k - delta_i_at_max_op_time)
                                                  // Initialize with LLONG_MAX to take minimums.

    std::vector<long long> current_delta(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                initial_a[j] = std::min(initial_a[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // If initial_a[j] is still LLONG_MAX, it means it was never constrained by a type 2 operation.
    // We can set it to 0, as per problem statement |a_i| <= 10^9.
    // Setting it to 0 is a valid choice that satisfies the constraints.
    for (int i = 0; i < n; ++i) {
        if (initial_a[i] == LLONG_MAX) {
            initial_a[i] = 0;
        }
    }

    // Verify the solution
    std::vector<long long> b = initial_a; // b will store the current state of the array
    current_delta.assign(n, 0); // Reset current_delta for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = LLONG_MIN;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

