struct Child {
    long long v, d, p;
    int original_idx;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_idx = i + 1;
        children[i].in_line = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        cured_children_indices.push_back(children[i].original_idx);
        children[i].in_line = false; // Child i goes to the doctor

        long long current_v_cry = children[i].v;
        long long total_d_cry_from_leaving_children = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply accumulated d_cry from previously leaving children
            children[j].p -= total_d_cry_from_leaving_children;

            // Apply v_cry from child i
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry--;
            }

            // Check if child j leaves
            if (children[j].p < 0) {
                children[j].in_line = false;
                total_d_cry_from_leaving_children += children[j].d;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

