// Function to check if a string is a palindrome
bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Case k=1
    // Try all possible single cuts
    for (int i = 1; i < n; ++i) { // i is the length of the first part s1
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string s_prime = s2 + s1;
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Case k=2
    // If k=1 didn't work, we need to check if k=2 is possible.
    // A k=2 solution is always possible unless all characters in s are the same.
    // If all characters are the same (e.g., "qqqq"), then any reordering of substrings
    // will result in the same string, which will also be a palindrome.
    // In this case, s' == s will always be true, so it's impossible.

    // Check if all characters in s are the same
    bool all_same = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same = false;
            break;
        }
    }

    if (all_same) {
        std::cout << "Impossible" << std::endl;
    } else {
        // If not all characters are the same, a k=2 solution is always possible.
        // For example, cut s into s[0], s[1...n-2], s[n-1].
        // Reorder to s[n-1], s[1...n-2], s[0].
        // Since s is a palindrome, s[0] == s[n-1].
        // The new string will be s[0] + s[1...n-2] + s[n-1], which is s itself.
        // This specific reordering doesn't work.

        // However, consider the property that if a string is a palindrome and not all characters are the same,
        // then it must have at least two distinct characters.
        // If N is odd, the middle character is unique.
        // If N is even, the string is like ABBA.
        // If N is 1, it's "a", all same, impossible.
        // If N > 1 and not all same, then there exists at least one character different from s[0].
        // Consider the string s. If we can't find a k=1 solution, it means that for any split s1|s2,
        // s2s1 is either not a palindrome or s2s1 == s.
        //
        // A known result for this problem (or similar ones) is that if a palindrome string `s`
        // has length `N > 1` and is not composed of all identical characters, then it's always possible
        // to form a new palindrome `s'` by reordering its parts with at most 2 cuts.
        // The only case where it's impossible is when all characters are the same.
        // Since we've already handled `k=1` and `all_same`, if we reach here, it means `k=1` failed
        // and `all_same` is false. Thus, `k=2` must be the answer.
        std::cout << 2 << std::endl;
    }

    return 0;
}

