    // This is the standard way to propagate minimums from right to left.

    // First, find all patterns and store their (start_idx, end_idx).
    // For each pattern (x, x+2k), update `min_good_r[x] = min(min_good_r[x], x+2k)`.
    // This means that if we start at `x`, the earliest `r` that makes it good is `x+2k`.

    // Iterate x from 1 to n.
    // For each x, iterate k from 1 up to some limit (e.g., 20).
    // If x + 2k <= n and s[x-1] == s[x+k-1] == s[x+2k-1]:
    //   `min_good_r[x] = min(min_good_r[x], x+2k)`.
    // This is O(N * K_limit). K_limit = 20 is fine.

    for (int x = 1; x <= n; ++x) {
        for (int k = 1; k <= 20; ++k) { // k up to 20 is sufficient for N=300000
            if (x + 2 * k <= n) {
                if (s[x - 1] == s[x + k - 1] && s[x + k - 1] == s[x + 2 * k - 1]) {
                    min_good_r[x] = std::min(min_good_r[x], x + 2 * k);
                }
            } else {
                // No need to check larger k for this x
                break;
            }
        }
    }

    // Now, propagate the minimums from right to left.
    // `min_good_r[l]` should be the minimum `r` such that `s[l-1...r-1]` contains a pattern.
    // This means `min_good_r[l]` is `min(min_good_r[l], min_good_r[l+1])`.
    for (int l = n - 1; l >= 1; --l) {
        min_good_r[l] = std::min(min_good_r[l], min_good_r[l + 1]);
    }

    // Now, `min_good_r[l]` stores the smallest `r` such that `s[l-1...r-1]` is "good".
    // If `min_good_r[l]` is `n+1`, it means no pattern exists starting at or after `l`.
    // For each `l`, the number of "bad" `r` values is `min_good_r[l] - l`.
    // These are `r` values from `l` to `min_good_r[l] - 1`.
    // If `min_good_r[l]` is `n+1`, then all `r` from `l` to `n` are bad.
    // The number of bad `r` values is `n - l + 1`.
    // This is equivalent to `std::min(n + 1, min_good_r[l]) - l`.

    for (int l = 1; l <= n; ++l) {
        // For a fixed l, any r such that l <= r < min_good_r[l] forms a "bad" pair (l, r).
        // The number of such r's is (min_good_r[l] - 1) - l + 1 = min_good_r[l] - l.
        // If min_good_r[l] is n+1, then all r from l to n are bad.
        // Number of bad r's = n - l + 1.
        // This can be written as std::min(n + 1, min_good_r[l]) - l.
        bad_pairs += (long long)std::min(n + 1, min_good_r[l]) - l;
    }

    std::cout << total_pairs - bad_pairs << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <vector>

// Function to calculate parity of a 01-string
int calculate_parity(const std::string& s) {
    int ones_count = 0;
    for (char c : s) {
        if (c == '1') {
            ones_count++;
        }
    }
    return ones_count % 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string a, b;
    std::cin >> a >> b;

    // Calculate initial parity of a
    int parity_a = calculate_parity(a);

    // Calculate parity of b
    int parity_b = calculate_parity(b);

    // The maximum possible length of 'a' that can be formed
    // is its initial length plus its parity.
    // If initial_parity_a is 0, max_len_a_prime = |a|.
    // If initial_parity_a is 1, max_len_a_prime = |a| + 1.
    // This is because if we append parity(a), the new string has parity 0.
    // So, if parity_a is 1, we can append '1' to 'a' to get a string of length |a|+1 with parity 0.
    // If parity_a is 0, we can't append '1' to 'a' to get a string of length |a|+1 with parity 0.
    // We can only append '0' to 'a' to get a string of length |a|+1 with parity 0.
    // The key is that any string 's' that can be formed by appending parity(s)
    // will have parity 0.
    // So, if we want to reach a string 'b' with parity 1, we must be able to form 'b'
    // by only removing characters from an initial 'a' or from 'a' after appending '0'.
    // If we append '1', the string becomes parity 0.
    // The maximum number of '1's we can have in a string derived from 'a'
    // that has parity 0 is `count_ones(a)` if `parity_a == 0`,
    // or `count_ones(a) + 1` if `parity_a == 1`.
    // This is equivalent to `count_ones(a) + parity_a`.

