int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize the state for two test values: 0 and 1023 (all bits set)
    // We need to track how 0 and 1023 transform.
    // Let's use 0 and 1 for simplicity, and then apply to all bits.
    // For each bit position, we need to know what happens to 0 and 1.
    // Initial state:
    // If input bit is 0, output bit is 0.
    // If input bit is 1, output bit is 1.
    // This can be represented by two values:
    // val_0: what 0 becomes after all operations
    // val_1: what 1 becomes after all operations
    // Initially, val_0 = 0, val_1 = 1.
    int val_0 = 0;
    int val_1023 = 1023; // Represents all bits being 1

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            val_0 &= x;
            val_1023 &= x;
        } else if (op_char == '|') {
            val_0 |= x;
            val_1023 |= x;
        } else { // '^'
            val_0 ^= x;
            val_1023 ^= x;
        }
    }

    // Now we have val_0 and val_1023.
    // For each bit position `j` (0 to 9):
    // Let `bit_0_j` be the j-th bit of `val_0`.
    // Let `bit_1_j` be the j-th bit of `val_1023`.
    //
    // If input bit `x_j` is 0, it becomes `bit_0_j`.
    // If input bit `x_j` is 1, it becomes `bit_1_j`.
    //
    // We need to find a sequence of operations that achieves this for all bits.
    //
    // Case 1: `bit_0_j` = 0, `bit_1_j` = 0
    //   Input 0 -> 0, Input 1 -> 0. This means the bit is always 0.
    //   This can be achieved by `& 0` for this bit.
    // Case 2: `bit_0_j` = 0, `bit_1_j` = 1
    //   Input 0 -> 0, Input 1 -> 1. This means the bit is unchanged.
    //   This can be achieved by `& 1`, `| 0`, or `^ 0` for this bit.
    // Case 3: `bit_0_j` = 1, `bit_1_j` = 0
    //   Input 0 -> 1, Input 1 -> 0. This means the bit is flipped.
    //   This can be achieved by `^ 1` for this bit.
    // Case 4: `bit_0_j` = 1, `bit_1_j` = 1
    //   Input 0 -> 1, Input 1 -> 1. This means the bit is always 1.
    //   This can be achieved by `| 1` for this bit.

    // We can combine these bit-wise operations into three constants:
    // `and_const`: bits that should become 0 if input is 0, and 1 if input is 1 (unchanged)
    //              or bits that should become 0 regardless of input (forced to 0)
    // `or_const`: bits that should become 1 regardless of input (forced to 1)
    // `xor_const`: bits that should be flipped
    int final_and_val = 1023; // Initialize to all 1s (no effect on &)
    int final_or_val = 0;     // Initialize to all 0s (no effect on |)
    int final_xor_val = 0;    // Initialize to all 0s (no effect on ^)

    for (int j = 0; j < 10; ++j) { // Iterate through 10 bits (0 to 9)
        int bit_0_j = (val_0 >> j) & 1;
        int bit_1_j = (val_1023 >> j) & 1;

        if (bit_0_j == 0 && bit_1_j == 0) {
            // Case 1: Input 0 -> 0, Input 1 -> 0. Bit always 0.
            // Achieved by `& 0` for this bit.
            final_and_val &= ~(1 << j); // Set j-th bit of final_and_val to 0
        } else if (bit_0_j == 0 && bit_1_j == 1) {
            // Case 2: Input 0 -> 0, Input 1 -> 1. Bit unchanged.
            // Achieved by `& 1`, `| 0`, `^ 0` for this bit.
            // No change needed for final_and_val, final_or_val, final_xor_val for this bit.
        } else if (bit_0_j == 1 && bit_1_j == 0) {
            // Case 3: Input 0 -> 1, Input 1 -> 0. Bit flipped.
            // Achieved by `^ 1` for this bit.
            final_xor_val |= (1 << j); // Set j-th bit of final_xor_val to 1
        } else { // bit_0_j == 1 && bit_1_j == 1
            // Case 4: Input 0 -> 1, Input 1 -> 1. Bit always 1.
            // Achieved by `| 1` for this bit.
            final_or_val |= (1 << j); // Set j-th bit of final_or_val to 1
        }
    }

    // The order of operations matters.
    // A common way to represent any bitwise function f(x) is:
    // (x & A) | B
    // or
    // (x | A) & B
    // or
    // (x ^ A) & B | C
    //
    // The derived `final_and_val`, `final_or_val`, `final_xor_val`
    // can be applied in the order: AND, OR, XOR.
    //
    // Let's verify this order:
    // `y = x & final_and_val`
    // `z = y | final_or_val`
    // `result = z ^ final_xor_val`
    //
    // Consider a bit `j`:
    //
    // Case 1: `bit_0_j` = 0, `bit_1_j` = 0 (always 0)
    //   `final_and_val_j` = 0, `final_or_val_j` = 0, `final_xor_val_j` = 0
    //   `y_j = x_j & 0 = 0`
    //   `z_j = 0 | 0 = 0`
    //   `result_j = 0 ^ 0 = 0` (Correct)
    //
    // Case 2: `bit_0_j` = 0, `bit_1_j` = 1 (unchanged)
    //   `final_and_val_j` = 1, `final_or_val_j` = 0, `final_xor_val_j` = 0
    //   `y_j = x_j & 1 = x_j`
    //   `z_j = x_j | 0 = x_j`
    //   `result_j = x_j ^ 0 = x_j` (Correct)
    //
    // Case 3: `bit_0_j` = 1, `bit_1_j` = 0 (flipped)
    //   `final_and_val_j` = 1, `final_or_val_j` = 0, `final_xor_val_j` = 1
    //   `y_j = x_j & 1 = x_j`
    //   `z_j = x_j | 0 = x_j`
    //   `result_j = x_j ^ 1 = ~x_j` (Correct)
    //
    // Case 4: `bit_0_j` = 1, `bit_1_j` = 1 (always 1)
    //   `final_and_val_j` = 1, `final_or_val_j` = 1, `final_xor_val_j` = 0
    //   `y_j = x_j & 1 = x_j`
    //   `z_j = x_j | 1 = 1`
    //   `result_j = 1 ^ 0 = 1` (Correct)

    std::vector<std::pair<char, int>> program;
    if (final_and_val != 1023) { // If there's any bit forced to 0
        program.push_back({'&', final_and_val});
    }
    if (final_or_val != 0) { // If there's any bit forced to 1
        program.push_back({'|', final_or_val});
    }
    if (final_xor_val != 0) { // If there's any bit flipped
        program.push_back({'^', final_xor_val});
    }

    std::cout << program.size() << "\n";
    for (const auto& op : program) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
