bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    std::vector<long long> head_reach_left(n);
    std::vector<long long> head_reach_right(n);
    for (int i = 0; i < n; ++i) {
        head_reach_left[i] = h[i] - T;
        head_reach_right[i] = h[i] + T;
    }

    int p_idx = 0;
    int h_idx = 0;

    while (p_idx < m) {
        // Find the first head that can reach p[p_idx]
        // This head must have its rightmost reach >= p[p_idx]
        // And its leftmost reach <= p[p_idx]
        while (h_idx < n && head_reach_right[h_idx] < p[p_idx]) {
            h_idx++;
        }

        if (h_idx == n) { // No head can reach p[p_idx]
            return false;
        }

        // Now h_idx is the first head such that head_reach_right[h_idx] >= p[p_idx]
        // We need to check if it can actually cover p[p_idx]
        if (head_reach_left[h_idx] > p[p_idx]) {
            // This head is too far to the right to cover p[p_idx]
            // And any subsequent head will be even further right.
            return false;
        }

        // This head h_idx can cover p[p_idx].
        // It can cover all tracks up to head_reach_right[h_idx].
        long long current_coverage_limit = head_reach_right[h_idx];

        // Advance p_idx past all tracks covered by this head
        while (p_idx < m && p[p_idx] <= current_coverage_limit) {
            p_idx++;
        }

        // Move to the next head for the next iteration, as this head is "used"
        h_idx++;
    }

    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 20000000000LL; // Max possible distance: (10^10 - 1) - (1 - 10^10) approx 2*10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> partition(n);

    // Case 1: All elements in one partition (e.g., partition 1)
    // min_f = a_min + a_second_min
    // max_f = a_max + a_second_max
    // goodness = (a_max + a_second_max) - (a_min + a_second_min)
    long long goodness1 = (elements[n - 1].value + elements[n - 2].value) -
                          (elements[0].value + elements[1].value);

    // Case 2: At least one element in each partition.
    // The minimum possible value of f is min(a_i + a_j, a_k + a_l + h).
    // The maximum possible value of f is max(a_i + a_j, a_k + a_l + h).

    // If we put elements[0] in S1 and elements[1] in S2, then a_min + a_second_min + h is a possible value.
    // If we put elements[0] in S1 and elements[n-1] in S2, then a_min + a_max + h is a possible value.
    // If we put elements[n-1] in S1 and elements[n-2] in S2, then a_max + a_second_max + h is a possible value.

    // Consider the strategy: put elements[0] in S1, and all other elements in S2.
    // min_f:
    //   - If n=2: elements[0] in S1, elements[1] in S2. Only one pair (elements[0], elements[1]).
    //     f = elements[0].value + elements[1].value + h. min_f = max_f = f. goodness = 0.
    //   - If n > 2:
    //     - Pairs within S2: elements[1].value + elements[2].value
    //     - Pairs between S1 and S2: elements[0].value + elements[1].value + h
    //     min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // max_f:
    //   - If n=2: elements[0].value + elements[1].value + h
    //   - If n > 2:
    //     - Pairs within S2: elements[n-1].value + elements[n-2].value
    //     - Pairs between S1 and S2: elements[0].value + elements[n-1].value + h
    //     max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)

    // Let's analyze the specific partition: elements[0] in S1, elements[1...n-1] in S2.
    // This partition is optimal if h is large enough to make it undesirable to have elements in different partitions.
    // The minimum value of f will be min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // The maximum value of f will be max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)

    // The key insight is that the minimum possible value of f is always a_min + a_second_min (if they are in the same partition)
    // or a_min + a_second_min + h (if they are in different partitions).
    // The maximum possible value of f is always a_max + a_second_max (if they are in the same partition)
    // or a_max + a_second_max + h (if they are in different partitions).

    // Consider the partition where elements[0] is in S1, and all other elements are in S2.
    // min_f_val = min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h) (if n > 2)
    //             elements[0].value + elements[1].value + h (if n = 2)
    // max_f_val = max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h) (if n > 2)
    //             elements[0].value + elements[1].value + h (if n = 2)

    // Let's simplify. The minimum possible sum of two elements is elements[0].value + elements[1].value.
    // The maximum possible sum of two elements is elements[n-1].value + elements[n-2].value.

    // Option A: All elements in one group.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // goodness = max_f - min_f

    // Option B: elements[0] in group 1, elements[1...n-1] in group 2.
    // min_f = min(elements[1].value + elements[2].value (if n > 2), elements[0].value + elements[1].value + h)
    // max_f = max(elements[n-1].value + elements[n-2].value (if n > 2), elements[0].value + elements[n-1].value + h)
    // If n=2, min_f = max_f = elements[0].value + elements[1].value + h, goodness = 0.
    // If n > 2:
    //   min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    //   max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
    //   goodness = max_f - min_f;

    // The problem states that the minimum goodness is required.
    // The minimum possible value of f is `elements[0].value + elements[1].value`.
    // The maximum possible value of f is `elements[n-1].value + elements[n-2].value + h`.
    // This is because we can always put elements[0] and elements[1] in the same group to get `elements[0].value + elements[1].value`.
    // And we can always put elements[n-1] and elements[n-2] in different groups (e.g., elements[n-1] in S1, elements[n-2] in S2)
    // to get `elements[n-1].value + elements[n-2].value + h`.
    // So, the overall range of f values is at least `(elements[n-1].value + elements[n-2].value + h) - (elements[0].value + elements[1].value)`.
    // This is the goodness if we have both types of pairs (same group and different groups).

    // Let's consider the two main strategies:
    // 1. All elements in one group.
    //    min_f = elements[0].value + elements[1].value
    //    max_f = elements[n-1].value + elements[n-2].value
    //    goodness = max_f - min_f
    //    This is `goodness1`.

    // 2. Split into two groups.
    //    To minimize goodness, we want to make max_f - min_f as small as possible.
    //    The smallest possible min_f is `elements[0].value + elements[1].value`.
    //    The largest possible max_f is `elements[n-1].value + elements[n-2].value + h`.
    //    If we can achieve a partition where min_f = elements[0].value + elements[1].value
    //    and max_f = elements[n-1].value + elements[0].value + h, this might be good.
    //    Consider the partition: elements[0] in S1, elements[1...n-1] in S2.
    //    min_f_val:
    //      If n=2: elements[0].value + elements[1].value + h
    //      If n > 2: std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    //    max_f_val:
    //      If n=2: elements[0].value + elements[1].value + h
    //      If n > 2: std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //    goodness2 = max_f_val - min_f_val

    long long current_min_goodness = goodness1;
    for (int i = 0; i < n; ++i) {
        partition[elements[i].original_index] = 1;
    }

    // Check the partition where elements[0] is in group 1, and all others are in group 2.
    // This is only relevant if n >= 2.
    // If n=2, elements[0] in S1, elements[1] in S2.
    // Only one pair (elements[0], elements[1]), they are in different groups.
    // f = elements[0].value + elements[1].value + h.
    // min_f = max_f = f. Goodness = 0.
    if (n == 2) {
        if (0 < current_min_goodness) {
            current_min_goodness = 0;
            partition[elements[0].original_index] = 1;
            partition[elements[1].original_index] = 2;
        }
    } else { // n > 2
        long long min_f_val_split, max_f_val_split;

        // Case 2.1: elements[0] in S1, elements[1...n-1] in S2.
        // min_f is either (elements[1]+elements[2]) or (elements[0]+elements[1]+h)
        min_f_val_split = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        // max_f is either (elements[n-1]+elements[n-2]) or (elements[0]+elements[n-1]+h)
        max_f_val_split = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
        long long goodness2_1 = max_f_val_split - min_f_val_split;

        if (goodness2_1 < current_min_goodness) {
            current_min_goodness = goodness2_1;
            partition[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                partition[elements[i].original_index] = 2;
            }
        }

        // Case 2.2: elements[n-1] in S1, elements[0...n-2] in S2.
        // min_f is either (elements[0]+elements[1]) or (elements[n-1]+elements[0]+h)
        min_f_val_split = std::min(elements[0].value + elements[1].value, elements[n-1].value + elements[0].value + h);
        // max_f is either (elements[n-2]+elements[n-3]) or (elements[n-1]+elements[n-2]+h)
        max_f_val_split = std::max(elements[n-2].value + elements[n-3].value, elements[n-1].value + elements[n-2].value + h);
        long long goodness2_2 = max_f_val_split - min_f_val_split;

        if (goodness2_2 < current_min_goodness) {
            current_min_goodness = goodness2_2;
            partition[elements[n-1].original_index] = 1;
            for (int i = 0; i < n - 1; ++i) {
                partition[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << current_min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << partition[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

