        long long diff = std::abs(a - b);
        long long presses = 0;

        // Use as many 5s as possible
        presses += diff / 5;
        diff %= 5;

        // Handle remaining difference (0, 1, 2, 3, 4)
        if (diff == 1 || diff == 2) {
            presses += 1;
        } else if (diff == 3 || diff == 4) {
            presses += 2;
        }
        // If diff is 0, no additional presses needed.

        std::cout << presses << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    if (n == 2) {
        std::cout << p[1] << " " << p[0] << std::endl;
        return;
    }

    // The strategy is to reverse the permutation.
    // Let p' be the reversed permutation of p.
    // p' = [p_n, p_{n-1}, ..., p_2, p_1]
    // The sums of adjacent elements for p are:
    // [p_1+p_2, p_2+p_3, ..., p_{n-1}+p_n]
    // The sums of adjacent elements for p' are:
    // [p_n+p_{n-1}, p_{n-1}+p_{n-2}, ..., p_2+p_1]
    // These two sets of sums are identical, just in reverse order.
    // Therefore, their sorted versions (fingerprints) will be identical.
    // Since n >= 2, if p is a permutation, its reverse p' will be different from p
    // unless p is a palindrome (e.g., [1,2,1] which is not a permutation, or [1,2,3,2,1] not a permutation).
    // For a permutation of distinct elements from 1 to n, p can only be equal to its reverse p'
    // if p_i = p_{n-1-i} for all i.
    // This implies that the sequence must be symmetric.
    // For example, if n=3, p=[1,2,3], p'=[3,2,1]. They are different.
    // If n=4, p=[1,2,3,4], p'=[4,3,2,1]. They are different.
    // The only case where p == p' is if p is a palindrome.
    // A permutation of distinct integers from 1 to n cannot be a palindrome unless n=1 (not allowed)
    // or n=0 (not allowed).
    // For example, if n=3, p=[1,2,3]. Reverse is [3,2,1]. Different.
    // If n=4, p=[1,2,3,4]. Reverse is [4,3,2,1]. Different.
    // A permutation [p_1, ..., p_n] is a palindrome if p_i = p_{n-i+1}.
    // Since all elements are distinct, this can only happen if n=1.
    // For n >= 2, p cannot be a palindrome.
    // Thus, reversing the permutation always yields a different permutation.

    std::reverse(p.begin(), p.end());
    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

