                    first_half_assigned = true;
                } else {
                    p[i] = 1; // Subsequent T/2 goes to black
                    first_half_assigned = false;
                }
            }
        }

        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
