#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then p[i] = max_{j!=i} min(p[i], p[j]) = max_{j!=i, p[j]>p[i]} p[i] = p[i]
        // or max_{j!=i, p[j]<p[i]} p[j].
        // The problem statement guarantees a solution exists.
        // The maximum value in any row (excluding diagonal) will be p[i] itself,
        // unless p[i] is the largest element 'n'.
        // If p[i] is 'n', then min(n, p[j]) = p[j] for all j!=i.
        // So max_{j!=i} min(n, p[j]) = max_{j!=i} p[j] = n-1 (since p is a permutation of 1..n).
        // Thus, if max_val_in_row is n-1, p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
