int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    double h;
    std::cin >> n >> h;

    std::cout << std::fixed << std::setprecision(12);

    for (int i = 1; i < n; ++i) {
        // The area of the top part of the carrot up to the i-th cut
        // (which forms a smaller triangle) must be i times the area of one piece.
        // Area of a triangle with height x and base b_x is (1/2) * b_x * x.
        // By similarity, b_x / x = 1 / h, so b_x = x / h.
        // Thus, Area_x = (1/2) * (x/h) * x = x^2 / (2h).
        // Total area of the carrot is A_total = (1/2) * 1 * h = h / 2.
        // Area of one piece is A_piece = A_total / n = (h / 2) / n = h / (2n).
        // The area up to the i-th cut (at distance x_i from apex) must be i * A_piece.
        // x_i^2 / (2h) = i * (h / (2n))
        // x_i^2 = i * h^2 / n
        // x_i = sqrt(i * h^2 / n)
        // x_i = h * sqrt(i / n)
        double x_i = h * std::sqrt(static_cast<double>(i) / n);
        std::cout << x_i << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

