    int q;
    std::cin >> q;
    while (q--) {
        long long n, m;
        std::cin >> n >> m;

        long long count = n / m; // Number of multiples of m up to n

        if (count == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Calculate the sum of last digits for the first 10 multiples of m
        // This forms one cycle of last digits
        long long cycle_sum = 0;
        for (int i = 1; i <= 10; ++i) {
            cycle_sum += (m * i) % 10;
        }

        // Number of full cycles
        long long num_full_cycles = count / 10;
        long long total_sum = num_full_cycles * cycle_sum;

        // Remaining multiples after full cycles
        long long remaining_multiples = count % 10;
        for (long long i = 1; i <= remaining_multiples; ++i) {
            total_sum += (m * i) % 10;
        }

        std::cout << total_sum << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1]. It's always beautiful.
        // For m > 1, we need to check if the segment containing 1...m
        // has length m.

        // Update current_min_idx and current_max_idx to include m
        // The value 'm' is at pos[m].
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // The length of the segment containing 1...m is current_max_idx - current_min_idx + 1.
        // If this length is equal to m, then 1...m are exactly those elements
        // in p[current_min_idx ... current_max_idx].
        // Since p is a permutation, all elements are distinct.
        // If the length is m, and it contains 1 and m, and all numbers between 1 and m,
        // then it must be a permutation of 1...m.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

