        if (d == 0.0) {
            std::cout << std::fixed << std::setprecision(9) << "Y 0.000000000 0.000000000\n";
            continue;
        }

        double discriminant = d * d - 4.0 * d;

        if (discriminant < 0.0) {
            std::cout << "N\n";
        } else {
            double sqrt_discriminant = std::sqrt(discriminant);
            double a1 = (d + sqrt_discriminant) / 2.0;
            double b1 = (d - sqrt_discriminant) / 2.0;

            // Check if a and b are non-negative.
            // Since d >= 0, and sqrt_discriminant >= 0, a1 will always be >= 0.
            // We need to check b1.
            // b1 = (d - sqrt(d^2 - 4d)) / 2
            // For b1 to be non-negative, d >= sqrt(d^2 - 4d)
            // Squaring both sides (both are non-negative): d^2 >= d^2 - 4d
            // 0 >= -4d
            // 4d >= 0
            // This is true for d >= 0.
            // So, if discriminant >= 0, then both a1 and b1 will be non-negative.

            std::cout << std::fixed << std::setprecision(9) << "Y " << a1 << " " << b1 << "\n";
        }
    }
    return 0;
}

