#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        std::cout << "Yes\n";
        return;
    }

    // Calculate prefix minimums for increasing sequence
    // min_val_prefix[i] stores the minimum possible value for a[i]
    // if a[0]...a[i] is strictly increasing and a[0] = 0.
    // min_val_prefix[i] = i
    // We need a[i] >= i for it to be possible.
    // More accurately, a[i] must be at least i.
    // If a[i] < i for any i, then it's impossible to form 0, 1, ..., i.
    // So, we need to find the first index `i` from the left where `a[i] < i`.
    // All elements before this index `i` (i.e., `a[0]` to `a[i-1]`) satisfy `a[j] >= j`.
    // This `i` is the maximum possible `k` for the increasing part.
    int max_k_from_left = n - 1; // 0-indexed
    for (int i = 0; i < n; ++i) {
        if (a[i] < i) {
            max_k_from_left = i - 1;
            break;
        }
    }

    // Calculate suffix minimums for decreasing sequence
    // min_val_suffix[i] stores the minimum possible value for a[i]
    // if a[i]...a[n-1] is strictly decreasing and a[n-1] = 0.
    // min_val_suffix[i] = (n-1) - i
    // We need a[i] >= (n-1) - i for it to be possible.
    // If a[i] < (n-1) - i for any i, then it's impossible to form ..., 1, 0.
    // So, we need to find the first index `i` from the right where `a[i] < (n-1) - i`.
    // All elements after this index `i` (i.e., `a[i+1]` to `a[n-1]`) satisfy `a[j] >= (n-1) - j`.
    // This `i` is the minimum possible `k` for the decreasing part.
    int min_k_from_right = 0; // 0-indexed
    for (int i = n - 1; i >= 0; --i) {
        if (a[i] < (n - 1) - i) {
            min_k_from_right = i + 1;
            break;
        }
    }

    // If there is any k (0-indexed) such that:
    // 1. a[0]...a[k] can be made strictly increasing (i.e., k <= max_k_from_left)
    // 2. a[k]...a[n-1] can be made strictly decreasing (i.e., k >= min_k_from_right)
    // Then it's possible.
    // This means we need to find if there's an overlap between the valid ranges for k.
    // The valid range for k from the left is [0, max_k_from_left].
    // The valid range for k from the right is [min_k_from_right, n-1].
    // We need to check if these two ranges intersect.
    // Intersection exists if min_k_from_right <= max_k_from_left.
    if (min_k_from_right <= max_k_from_left) {
        std::cout << "Yes\n";
    } else {
        std::cout << "No\n";
    }
}

