#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::sort(a.begin(), a.end());
    int count = 0;
    int j = 0; // Pointer for elements to be placed (the 'B' array elements)
    for (int i = 0; i < n; ++i) { // Pointer for original array elements (the 'A' array elements)
        // We are trying to find an element a[j] from the available elements
        // that is strictly greater than a[i] (the current original element).
        // Since both arrays are sorted, if a[j] > a[i], then a[j+1] will also be >= a[j],
        // so it's always optimal to use the smallest possible a[j] that satisfies the condition
        // to leave larger elements for later, potentially larger a[i] values.
        while (j < n && a[j] <= a[i]) {
            j++;
        }
        if (j < n) { // Found an element a[j] such that a[j] > a[i]
            count++;
            j++; // Move to the next element in the 'B' array for the next match
        } else {
            // No more elements in 'B' array are greater than a[i] (or any subsequent a[k] where k > i)
            // So we can't make any more matches.
            break;
        }
    }
    std::cout << count << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(a_elements.begin(), a_elements.end(), compareElements);

    // Sort B in descending order
    // We need to sort by value, but keep original indices for mapping
    std::sort(b_elements.begin(), b_elements.end(), [](const Element& x, const Element& y) {
        return x.value > y.value;
    });

    // Create the result array A'
    std::vector<long long> result_a_prime(m);

    // Map sorted A values to original B positions
    // The i-th smallest A value should be paired with the i-th largest B value
    for (int i = 0; i < m; ++i) {
        // b_elements[i] is the i-th largest B value.
        // Its original_index tells us where it was in the input B array.
        // This original_index is the target position in the output A' array.
        // a_elements[i] is the i-th smallest A value.
        // This value should go into the target position.
        result_a_prime[b_elements[i].original_index] = a_elements[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) {
        return true; // An empty sequence can be considered a permutation of length 0
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val <= 0 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> max_prefix(n + 1, 0);
    std::vector<bool> seen_prefix(n + 1, false);
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        if (a[i] <= 0 || a[i] > i + 1 || seen_prefix[a[i]]) {
            possible_prefix = false;
        }
        seen_prefix[a[i]] = true;
        max_prefix[i + 1] = std::max(max_prefix[i], a[i]);
        if (max_prefix[i + 1] != i + 1) {
            possible_prefix = false;
        }
        if (!possible_prefix) {
            max_prefix[i + 1] = -1; // Mark as invalid
        }
    }

    std::vector<int> max_suffix(n + 1, 0);
    std::vector<bool> seen_suffix(n + 1, false);
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int len_suffix = n - i;
        if (a[i] <= 0 || a[i] > len_suffix || seen_suffix[a[i]]) {
            possible_suffix = false;
        }
        seen_suffix[a[i]] = true;
        max_suffix[i] = std::max(max_suffix[i + 1], a[i]);
        if (max_suffix[i] != len_suffix) {
            possible_suffix = false;
        }
        if (!possible_suffix) {
            max_suffix[i] = -1; // Mark as invalid
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (max_prefix[l1] == l1 && max_suffix[l1] == l2) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

