    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int countR = 0;
        int countS = 0;
        int countP = 0;

        for (char move : s) {
            if (move == 'R') {
                countR++;
            } else if (move == 'S') {
                countS++;
            } else { // move == 'P'
                countP++;
            }
        }

        char most_frequent_bot_move;
        if (countR >= countS && countR >= countP) {
            most_frequent_bot_move = 'R';
        } else if (countS >= countR && countS >= countP) {
            most_frequent_bot_move = 'S';
        } else {
            most_frequent_bot_move = 'P';
        }

        char our_winning_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << our_winning_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    long long opponent_score = 0;
    bool chanek_turn = true;

    while (n > 0) {
        if (chanek_turn) {
            if (n % 2 != 0) { // N is odd
                chanek_score += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, Chanek takes 1
                    chanek_score += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 > 1) { // N/2 is odd and > 1
                    // Taking N/2 leaves an odd number for opponent, which is good for Chanek
                    chanek_score += n / 2;
                    n /= 2;
                } else { // N/2 is even or N/2 is 1 (which means N=2, handled above)
                    // Taking N/2 leaves an even number for opponent, which might be bad.
                    // Taking 1 leaves an odd number for opponent.
                    // In this case, taking 1 is always better or equal to taking N/2
                    // because it leaves an odd number for the opponent, forcing them to take 1.
                    // If Chanek takes N/2, opponent might take N/4, etc.
                    // The only exception is when N/2 is odd and > 1, where taking N/2 is optimal.
                    // Otherwise, taking 1 is optimal.
                    chanek_score += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 != 0) { // N is odd
                opponent_score += 1;
                n -= 1;
            } else { // N is even
                if (n == 2) { // Special case for N=2, Opponent takes 1
                    opponent_score += 1;
                    n -= 1;
                } else if ((n / 2) % 2 != 0 && n / 2 > 1) { // N/2 is odd and > 1
                    // Opponent wants to maximize their score.
                    // Taking N/2 leaves an odd number for Chanek, which is good for opponent.
                    opponent_score += n / 2;
                    n /= 2;
                } else { // N/2 is even or N/2 is 1 (N=2, handled above)
                    // Taking N/2 leaves an even number for Chanek.
                    // Taking 1 leaves an odd number for Chanek.
                    // Opponent prefers to leave an odd number for Chanek.
                    opponent_score += 1;
                    n -= 1;
                }
            }
        }
        chanek_turn = !chanek_turn;
    }
    return chanek_score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::cout << solve() << "\n";
    }
    return 0;
}

