#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    // If current_sum == 2 * current_xor_sum, the array is already good.
    // We can append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
        return;
    }

    // We need to append elements.
    // Let's try to append two elements.
    // Let the two elements be X and Y.
    // New sum: S' = current_sum + X + Y
    // New XOR sum: X' = current_xor_sum ^ X ^ Y
    // We want S' = 2 * X'
    // current_sum + X + Y = 2 * (current_xor_sum ^ X ^ Y)

    // A simple strategy is to make the XOR sum equal to the current_xor_sum,
    // and then adjust the sum.
    // Let's try to append two elements: current_xor_sum and current_sum + current_xor_sum.
    // This is not quite right.

    // Consider appending two elements: current_xor_sum and current_sum + current_xor_sum.
    // Let's try to append two elements:
    // b1 = current_xor_sum
    // b2 = current_sum + current_xor_sum
    // This is not correct. The problem is that b2 can be very large.
    // The problem statement says b_i <= 10^18.

    // Let's try to append two elements:
    // 1. The current XOR sum (current_xor_sum)
    // 2. The current sum (current_sum)
    // This is also not correct.

    // The strategy from competitive programming problems for this type of problem:
    // Append two elements:
    // 1. current_xor_sum
    // 2. current_sum + current_xor_sum
    // Let's verify this.
    // Let X_orig = current_xor_sum
    // Let S_orig = current_sum
    // Append b1 = X_orig
    // Append b2 = S_orig + X_orig
    //
    // New XOR sum: X_new = X_orig ^ b1 ^ b2
    // X_new = X_orig ^ X_orig ^ (S_orig + X_orig)
    // X_new = 0 ^ (S_orig + X_orig)
    // X_new = S_orig + X_orig
    //
    // New sum: S_new = S_orig + b1 + b2
    // S_new = S_orig + X_orig + (S_orig + X_orig)
    // S_new = 2 * S_orig + 2 * X_orig
    // S_new = 2 * (S_orig + X_orig)
    //
    // We want S_new = 2 * X_new
    // 2 * (S_orig + X_orig) = 2 * (S_orig + X_orig)
    // This identity holds!
    // So, appending b1 = current_xor_sum and b2 = current_sum + current_xor_sum makes the array good.
    // The number of appended elements is 2.
    // The values can be large, but within 10^18.
    // current_sum can be up to 10^5 * 10^9 = 10^14.
    // current_xor_sum can be up to 2^30 - 1 (approx 10^9).
    // So b2 = current_sum + current_xor_sum can be up to 10^14 + 10^9, which is well within 10^18.

    long long b1 = current_xor_sum;
    long long b2 = current_sum + current_xor_sum;

    std::cout << 2 << "\n";
    std::cout << b1 << " " << b2 << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
