#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long l, r, Ql, Qr;
    std::cin >> n >> l >> r >> Ql >> Qr;

    std::vector<long long> w(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> w[i];
    }

    std::vector<long long> prefix_sum(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_sum[i + 1] = prefix_sum[i] + w[i];
    }

    long long min_energy = -1;

    // Iterate through all possible counts of items taken from the left
    // Let i be the number of items taken from the left (0 <= i <= n)
    // Then n - i items must be taken from the right
    for (int i = 0; i <= n; ++i) {
        long long current_energy = 0;

        // Energy for items taken from the left
        // These are w[0]...w[i-1]
        current_energy += (prefix_sum[i] - prefix_sum[0]) * l;

        // Energy for items taken from the right
        // These are w[n-(n-i)]...w[n-1]
        // Which is w[i]...w[n-1] if we consider the original indices
        // But since we are taking from the right, it's the last (n-i) items.
        // The sum of these weights is (prefix_sum[n] - prefix_sum[i])
        current_energy += (prefix_sum[n] - prefix_sum[i]) * r;

        // Add penalty for imbalance
        int num_left = i;
        int num_right = n - i;

        if (num_left > num_right) {
            // More items taken from left. The difference is num_left - num_right.
            // The last (num_left - num_right - 1) items taken from the left
            // would incur Ql penalty if they were taken consecutively after the right items ran out.
            // This is equivalent to (num_left - num_right - 1) * Ql
            current_energy += std::max(0, num_left - num_right - 1) * Ql;
        } else if (num_right > num_left) {
            // More items taken from right. The difference is num_right - num_left.
            // The last (num_right - num_left - 1) items taken from the right
            // would incur Qr penalty if they were taken consecutively after the left items ran out.
            // This is equivalent to (num_right - num_left - 1) * Qr
            current_energy += std::max(0, num_right - num_left - 1) * Qr;
        }

        if (min_energy == -1 || current_energy < min_energy) {
            min_energy = current_energy;
        }
    }

    std::cout << min_energy << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

long long get_max_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    std::vector<long long> prime_factors_q;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    long long max_x = 1;

    for (long long factor_q : prime_factors_q) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= factor_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

