    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p, q;
        std::cin >> p >> q;
        std::cout << get_max_x(p, q) << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string d_str;
    std::cin >> d_str;

    std::vector<int> d(n);
    for (int i = 0; i < n; ++i) {
        d[i] = d_str[i] - '0';
    }

    for (int pivot = 0; pivot <= 9; ++pivot) {
        std::string coloring(n, ' ');
        std::vector<int> s1_digits;
        std::vector<int> s2_digits;
        bool possible_pivot = true;

        // First pass: assign digits strictly less than pivot to S1,
        // strictly greater than pivot to S2.
        // Digits equal to pivot are unassigned for now.
        for (int i = 0; i < n; ++i) {
            if (d[i] < pivot) {
                coloring[i] = '1';
                s1_digits.push_back(d[i]);
            } else if (d[i] > pivot) {
                coloring[i] = '2';
                s2_digits.push_back(d[i]);
            }
        }

        // Check if S1 and S2 are already sorted
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_pivot = false;
                break;
            }
        }
        if (!possible_pivot) continue;

        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_pivot = false;
                break;
            }
        }
        if (!possible_pivot) continue;

        // Second pass: assign digits equal to pivot.
        // The first occurrence of 'pivot' and subsequent 'pivot's can be assigned to S1
        // as long as they maintain S1's non-decreasing property.
        // After a 'pivot' is assigned to S2, all subsequent 'pivot's must be assigned to S2.
        bool assigned_pivot_to_s2 = false;
        for (int i = 0; i < n; ++i) {
            if (d[i] == pivot) {
                if (!assigned_pivot_to_s2) {
                    // Try to assign to S1
                    if (s1_digits.empty() || d[i] >= s1_digits.back()) {
                        coloring[i] = '1';
                        s1_digits.push_back(d[i]);
                    } else {
                        // Cannot assign to S1, must assign to S2
                        coloring[i] = '2';
                        s2_digits.push_back(d[i]);
                        assigned_pivot_to_s2 = true;
                    }
                } else {
                    // Already assigned a pivot to S2, so all subsequent pivots must go to S2
                    coloring[i] = '2';
                    s2_digits.push_back(d[i]);
                }
            }
        }

        // Final check for S1 and S2 non-decreasing property
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                possible_pivot = false;
                break;
            }
        }
        if (!possible_pivot) continue;

        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                possible_pivot = false;
                break;
            }
        }
        if (!possible_pivot) continue;

        // Check the boundary condition: last of S1 <= first of S2
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                possible_pivot = false;
            }
        }

        if (possible_pivot) {
            std::cout << coloring << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;

        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);

        // Ensure abs_n >= abs_m for simpler logic
        if (abs_n < abs_m) {
            std::swap(abs_n, abs_m);
        }

        // Minimum moves required is abs_n (Chebyshev distance)
        // If k < abs_n, it's impossible.
        if (k < abs_n) {
            std::cout << -1 << "\n";
            continue;
        }

        // Calculate the number of diagonal moves needed to cover the smaller coordinate
        // and an equal amount of the larger coordinate.
        long long diag_moves_to_match_min = abs_m;

        // After diag_moves_to_match_min, we are at (abs_n - abs_m, 0) or (0, abs_n - abs_m)
        // and have used abs_m moves.
        // Remaining distance in one coordinate: abs_n - abs_m
        // Remaining moves: k - abs_m

        long long remaining_dist_one_coord = abs_n - abs_m;
        long long remaining_moves = k - abs_m;

        // If remaining_dist_one_coord is 0, we are at (0,0) relative to the current position.
        // We need to make remaining_moves.
        // Each pair of moves (e.g., (1,0) then (-1,0)) can be used to waste 2 moves.
        // If remaining_moves is odd, we must make one more move to an adjacent cell,
        // then we can waste the rest in pairs.
        // If remaining_moves is even, we can waste all moves in pairs.
        // The parity of remaining_moves must match the parity of remaining_dist_one_coord.
        // If remaining_dist_one_coord is 0, remaining_moves must be even.
        // If remaining_dist_one_coord is > 0, remaining_moves must have the same parity.
        // This is equivalent to (remaining_moves - remaining_dist_one_coord) % 2 == 0.
        if ((remaining_moves - remaining_dist_one_coord) % 2 != 0) {
            std::cout << -1 << "\n";
            continue;
        }

        // If we reach here, it's possible.
        // The maximum number of diagonal moves is k, unless we are forced to make straight moves.
        // We have already made diag_moves_to_match_min diagonal moves.
        // We have remaining_moves and remaining_dist_one_coord.
        // We must cover remaining_dist_one_coord using straight moves. This takes remaining_dist_one_coord moves.
        // The rest of the moves (remaining_moves - remaining_dist_one_coord) must be wasted.
        // Each wasted move can be a diagonal move if we move (1,1) then (-1,-1).
        // Or it can be a straight move if we move (1,0) then (-1,0).
        // To maximize diagonal moves, we want to use diagonal moves for wasting.
        // The number of moves to waste is (remaining_moves - remaining_dist_one_coord).
        // These wasted moves can be done as pairs of diagonal moves (e.g., (1,1) then (-1,-1)).
        // So, (remaining_moves - remaining_dist_one_coord) / 2 pairs of diagonal moves.
        // This adds (remaining_moves - remaining_dist_one_coord) diagonal moves.

        long long total_diagonal_moves = diag_moves_to_match_min + (remaining_moves - remaining_dist_one_coord);

        std::cout << total_diagonal_moves << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // We need to handle division by 2 modulo MOD.
    // Since MOD is prime (10^9 + 7), we can use modular inverse.
    // Modular inverse of 2 is (MOD + 1) / 2.
    long long sum_r_term = (b - 1);
    if (sum_r_term < 0) sum_r_term = 0; // If b=1, b-1=0, sum is 0.

    long long sum_r = (sum_r_term % MOD * (b % MOD)) % MOD;
    long long inv2 = (MOD + 1) / 2;
    sum_r = (sum_r * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = sum_{k=1 to a} (k*b) + sum_{k=1 to a} 1
    //                = b * sum_{k=1 to a} k + a
    //                = b * (a * (a+1) / 2) + a
    long long sum_k_term_a = a % MOD;
    long long sum_k_term_a_plus_1 = (a + 1) % MOD;

    long long sum_k = (sum_k_term_a * sum_k_term_a_plus_1) % MOD;
    sum_k = (sum_k * inv2) % MOD;

    long long sum_k_b_plus_1 = ( (b % MOD) * sum_k ) % MOD;
    sum_k_b_plus_1 = (sum_k_b_plus_1 + sum_k_term_a) % MOD;

    // Total sum = (sum_r * sum_k_b_plus_1) % MOD
    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

