#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, std::set<char>> adj;
    std::set<char> used_in_s;

    for (size_t i = 0; i < s.length(); ++i) {
        used_in_s.insert(s[i]);
        if (i > 0) {
            adj[s[i]].insert(s[i-1]);
            adj[s[i-1]].insert(s[i]);
        }
    }

    for (const auto& pair : adj) {
        if (pair.second.size() > 2) {
            std::cout << "NO\n";
            return;
        }
    }

    std::string layout_str = "";
    std::set<char> visited_in_layout;

    // Find starting points for chains (characters with only one neighbor in s)
    // Or if all characters have two neighbors, pick any unvisited character from s.
    char start_char = '\0';
    for (char c : used_in_s) {
        if (adj[c].size() == 1) {
            start_char = c;
            break;
        }
    }

    if (start_char == '\0' && !used_in_s.empty()) { // All characters in s have two neighbors, implies a cycle
        // This case is problematic. If all characters in `s` have two neighbors,
        // it means they form a cycle. A linear keyboard cannot represent a cycle.
        // Example: abcda -> a-b, b-c, c-d, d-a. 'a' needs to be adjacent to 'b' and 'd'.
        // If we place 'b' and 'd' on either side of 'a', then 'b' and 'd' are not adjacent.
        // But 'b' needs to be adjacent to 'c', and 'd' needs to be adjacent to 'c'.
        // This implies 'c' must be adjacent to both 'b' and 'd'.
        // This forms a cycle of length 4: a-b-c-d-a.
        // A linear layout can only represent paths, not cycles.
        // The only exception is if the entire string `s` itself forms a path,
        // and all characters in `s` are distinct.
        // E.g., "abcde". 'a' has 1 neighbor, 'e' has 1 neighbor.
        // If `s` is "abacaba", 'a' has neighbors 'b', 'c'. 'b' has 'a'. 'c' has 'a'.
        // Here 'a' has degree 2, 'b' has degree 1, 'c' has degree 1.
        // The logic for `adj[c].size() > 2` already handles cases like `abcda` where 'a' would have neighbors 'b' and 'd',
        // and 'b' would have 'a' and 'c', 'c' would have 'b' and 'd', 'd' would have 'c' and 'a'.
        // In `abcda`, 'a' has neighbors 'b' and 'd'. 'b' has 'a' and 'c'. 'c' has 'b' and 'd'. 'd' has 'c' and 'a'.
        // All characters in `abcda` have degree 2.
        // This means `start_char` will remain `\0`.
        // This is the "NO" case.
        std::cout << "NO\n";
        return;
    }

    if (start_char == '\0' && used_in_s.empty()) { // Empty password or password with single character
        // If s is "a", used_in_s = {'a'}, adj is empty. start_char remains '\0'.
        // This is fine, we just append all chars.
        // If s is "ab", start_char will be 'a' or 'b'.
        // If s is "a", used_in_s has 'a'. adj is empty. start_char is '\0'.
        // We need to handle this. If used_in_s is not empty, but start_char is '\0',
        // it means all characters in used_in_s have degree 2. This implies a cycle.
        // This is an impossible case for a linear keyboard.
        // The only exception is if used_in_s has only one character, e.g., s="a".
        // In this case, adj is empty, start_char is '\0'.
        // We should just pick that character as the start.
        if (!used_in_s.empty()) {
            start_char = *used_in_s.begin();
        }
    }

    if (start_char != '\0') {
        char current = start_char;
        char prev = '\0'; // Sentinel for the first character

        while (visited_in_layout.find(current) == visited_in_layout.end()) {
            layout_str += current;
            visited_in_layout.insert(current);

            char next_char = '\0';
            for (char neighbor : adj[current]) {
                if (neighbor != prev) {
                    next_char = neighbor;
                    break;
                }
            }
            prev = current;
            current = next_char;
            if (current == '\0' && visited_in_layout.size() < used_in_s.size()) {
                // This means we reached the end of a chain, but not all characters from s are in the layout.
                // This implies there are multiple disjoint chains or cycles.
                // Example: s = "ab" + "cd". 'a' has 'b', 'b' has 'a'. 'c' has 'd', 'd' has 'c'.
                // If we start with 'a', we get "ab". Then current becomes '\0'.
                // But 'c' and 'd' are still in used_in_s but not in visited_in_layout.
                // This is an impossible case for a single linear layout.
                std::cout << "NO\n";
                return;
            }
        }
        // If we exited the loop because current is already visited, it means we formed a cycle.
        // This is only allowed if the cycle includes ALL characters from used_in_s,
        // AND the cycle is of length 2 (e.g., "ababa").
        // But if it's a cycle of length > 2, it's impossible.
        // Example: "abcda". 'a' -> 'b' -> 'c' -> 'd' -> 'a'.
        // If we start with 'a', we get "abcd". Then 'd' has 'c' and 'a'. 'c' is prev. So next is 'a'.
        // 'a' is already visited. This means we formed a cycle.
        // A linear keyboard cannot represent a cycle of length > 2.
        // If current is '\0', it means we reached the end of a path.
        // If current is not '\0' and visited_in_layout.find(current) != visited_in_layout.end(),
        // it means we found a cycle.
        // This check is implicitly handled by the `if (visited_in_layout.size() < used_in_s.size())`
        // if `current` becomes `\0` and we haven't visited all.
        // If `current` is not `\0` and is visited, it means we completed a cycle.
        // This is only valid if the cycle is of length 2 (e.g., "ab").
        // But if it's a cycle of length > 2, it's impossible.
        // The `adj[c].size() > 2` check already handles the most common cycle issues.
        // The remaining cycle issue is when all characters in `s` have degree 2, forming a single cycle.
        // E.g., `abcda`. `adj['a'] = {'b', 'd'}`. `adj['b'] = {'a', 'c'}`. `adj['c'] = {'b', 'd'}`. `adj['d'] = {'c', 'a'}`.
        // All degrees are 2. `start_char` will be `\0`. This is handled by `std::cout << "NO\n"; return;`
        // So, if we reach here, it means we successfully built a path.
    }

    if (visited_in_layout.size() != used_in_s.size()) {
        // This means there are characters in `s` that were not part of the constructed path.
        // This implies multiple disjoint components in the graph formed by `s`.
        // A single linear keyboard cannot represent disjoint components.
        std::cout << "NO\n";
        return;
    }

    // Append remaining unused characters
    for (char c = 'a'; c <= 'z'; ++c) {
        if (visited_in_layout.find(c) == visited_in_layout.end()) {
            layout_str += c;
        }
    }

    std::cout << "YES\n";
    std::cout << layout_str << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

