        //   x_j must become NOT x_j. (0->1, 1->0)
        //   Simplest: final_xor_mask_j = 1.
        //   final_and_mask_j = 1, final_or_mask_j = 0, final_xor_mask_j = 1.
        else if (b0_j == 1 && b1_j == 0) {
            final_and_mask |= (1 << j); // Set j-th bit of AND mask to 1
            final_or_mask &= ~(1 << j); // Set j-th bit of OR mask to 0
            final_xor_mask |= (1 << j); // Set j-th bit of XOR mask to 1
        }
        // If b0_j = 1, b1_j = 1:
        //   x_j must become 1 regardless of its initial value.
        //   Simplest: final_or_mask_j = 1.
        //   final_and_mask_j = 1, final_or_mask_j = 1, final_xor_mask_j = 0.
        else if (b0_j == 1 && b1_j == 1) {
            final_and_mask |= (1 << j); // Set j-th bit of AND mask to 1
            final_or_mask |= (1 << j);  // Set j-th bit of OR mask to 1
            final_xor_mask &= ~(1 << j); // Set j-th bit of XOR mask to 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_or_mask != 0) {
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_and_mask != 1023) { // 1023 is all 1s for 10 bits
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_xor_mask != 0) {
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s) - (count of 2s) among jars n, n-1, ..., n-k+1
    // This is equivalent to (count of 1s) - (count of 2s) for a[n-k]...a[n-1]
    // We want to store diff for prefix of length k from the right end of the left half.
    // So, diff_L[k] is for jars a[n-k]...a[n-1]
    std::map<int, int> diff_L_map; // Stores diff -> min_k
    diff_L_map[0] = 0; // 0 jars removed from left, diff is 0
    int current_diff_L = 0;
    for (int k = 1; k <= n; ++k) {
        int jar_idx = n - k; // Jars are 0-indexed, so a[n-k] is the k-th jar from the right of the left half
        if (a[jar_idx] == 1) {
            current_diff_L++;
        } else {
            current_diff_L--;
        }
        if (diff_L_map.find(current_diff_L) == diff_L_map.end()) {
            diff_L_map[current_diff_L] = k;
        }
    }

    // Calculate prefix sums for the right side (jars n+1 to 2n)
    // diff_R[k] = (count of 1s) - (count of 2s) among jars n+1, n+2, ..., n+k
    // We want to store diff for prefix of length k from the left end of the right half.
    // So, diff_R[k] is for jars a[n]...a[n+k-1]
    std::map<int, int> diff_R_map; // Stores diff -> min_k
    diff_R_map[0] = 0; // 0 jars removed from right, diff is 0
    int current_diff_R = 0;
    for (int k = 1; k <= n; ++k) {
        int jar_idx = n + k - 1; // Jars are 0-indexed, so a[n+k-1] is the k-th jar from the left of the right half
        if (a[jar_idx] == 1) {
            current_diff_R++;
        } else {
            current_diff_R--;
        }
        if (diff_R_map.find(current_diff_R) == diff_R_map.end()) {
            diff_R_map[current_diff_R] = k;
        }
    }

    int min_removed_jars = 2 * n; // Initialize with max possible

    // Iterate through all possible diff_L values
    for (auto const& [diff_L_val, k_L] : diff_L_map) {
        // We need diff_L_val + diff_R_val = 0, so diff_R_val = -diff_L_val
        int target_diff_R_val = -diff_L_val;
        if (diff_R_map.count(target_diff_R_val)) {
            int k_R = diff_R_map[target_diff_R_val];
            min_removed_jars = std::min(min_removed_jars, k_L + k_R);
        }
    }

    std::cout << min_removed_jars << std::endl;
}

