        long long max_x = 1000000000LL;  // Effectively positive infinity
        long long min_y = -1000000000LL; // Effectively negative infinity
        long long max_y = 1000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // If f1 (move left) is 0, robot cannot move left.
            // So, its final X coordinate must be >= its current X coordinate.
            // It can only move right or stay.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // If f3 (move right) is 0, robot cannot move right.
            // So, its final X coordinate must be <= its current X coordinate.
            // It can only move left or stay.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If f4 (move down) is 0, robot cannot move down.
            // So, its final Y coordinate must be >= its current Y coordinate.
            // It can only move up or stay.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // If f2 (move up) is 0, robot cannot move up.
            // So, its final Y coordinate must be <= its current Y coordinate.
            // It can only move down or stay.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            // The problem guarantees that if a solution exists, one with coordinates
            // not exceeding 10^5 by absolute value exists.
            // We can pick any point within the valid range.
            // For example, (min_x, min_y) is a valid point.
            // We need to clamp it to the guaranteed range if it falls outside
            // the -10^5 to 10^5 range, though the problem statement implies
            // min_x/max_x/min_y/max_y will naturally be within this range
            // if a solution exists.
            // The initial coordinates are up to 10^5, so min_x/max_x/min_y/max_y
            // will be within this range.
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
