#include <iostream>
#include <vector>
#include <numeric>

// Using long long for x and y to prevent overflow, as a_i can be up to 10^9
// and y can accumulate many such values. x can also become large.
// The problem statement implies x is an index, so it should not exceed n.
// However, intermediate x values can go beyond n or below 1 before termination.
// The values a_i are positive integers.

// Memoization table for results
// dp[i] stores a pair: {final_x, final_y} if it terminates, or a special value if it loops.
// We need to store the *change* in x and y from the point where x was i.
// Let's define dp[i] as {delta_x, delta_y} if starting at x=i, y=0, it terminates.
// If it terminates, the final x will be x_initial + delta_x, final y will be y_initial + delta_y.
// If it loops, we need a way to mark it.
// A value like {0, -1} could indicate a loop, but -1 is a valid y output.
// Let's use a special large value for delta_x to indicate a loop, e.g., LLONG_MAX.
// Or, more simply, use a visited array during DFS.

std::vector<long long> a_values; // Stores a_2, ..., a_n. a_values[0] corresponds to a_2.
int N;

// dp_x[i] stores the final x value if starting with x=i, y=0.
// dp_y[i] stores the final y value if starting with x=i, y=0.
// These are the *absolute* final values, not deltas.
std::vector<long long> dp_x;
std::vector<long long> dp_y;

// visited[i] = 0: not visited
// visited[i] = 1: currently in recursion stack (detects cycle)
// visited[i] = 2: finished processing (result stored in dp_x, dp_y)
std::vector<int> visited;

// Function to solve for a given starting x_val (1-indexed)
// Returns true if it terminates, false if it loops.
bool solve(int current_x_idx) {
    // If current_x_idx is out of bounds, it terminates.
    // The problem states x <= 0 or x > n terminates.
    // Here, current_x_idx is 1-indexed.
    if (current_x_idx <= 0 || current_x_idx > N) {
        dp_x[current_x_idx] = current_x_idx; // Store the terminating x
        dp_y[current_x_idx] = 0;             // No additional y accumulated from this point
        return true;
    }

    // If already visited and processed, return stored result.
    if (visited[current_x_idx] == 2) {
        return dp_x[current_x_idx] != -1; // -1 indicates a loop
    }

    // If currently in recursion stack, it's a cycle.
    if (visited[current_x_idx] == 1) {
        dp_x[current_x_idx] = -1; // Mark as loop
        dp_y[current_x_idx] = -1; // Mark as loop
        return false;
    }

    visited[current_x_idx] = 1; // Mark as currently visiting

    long long val_a_x = (current_x_idx == 1) ? 0 : a_values[current_x_idx - 2]; // a_1 is special, a_2 is a_values[0]

    // Simulate one step:
    // Step 1: x = x + a_x, y = y + a_x
    long long next_x1 = current_x_idx + val_a_x;
    long long current_y_accumulated = val_a_x;

    // Check termination after step 1
    if (next_x1 <= 0 || next_x1 > N) {
        dp_x[current_x_idx] = next_x1;
        dp_y[current_x_idx] = current_y_accumulated;
        visited[current_x_idx] = 2;
        return true;
    }

    // Step 2: x = x - a_x, y = y + a_x
    long long next_x2 = next_x1 - val_a_x;
    current_y_accumulated += val_a_x;

    // Recursively solve for next_x2
    bool terminates_from_next_x2 = solve(next_x2);

    if (terminates_from_next_x2) {
        // If it terminates, add the accumulated y from this step and the y from the recursive call
        dp_x[current_x_idx] = dp_x[next_x2];
        dp_y[current_x_idx] = current_y_accumulated + dp_y[next_x2];
    } else {
        // If it loops, this path also loops
        dp_x[current_x_idx] = -1;
        dp_y[current_x_idx] = -1;
    }

    visited[current_x_idx] = 2; // Mark as finished processing
    return terminates_from_next_x2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    a_values.resize(N - 1);
    for (int i = 0; i < N - 1; ++i) {
        std::cin >> a_values[i];
    }

    // dp_x and dp_y need to store results for indices 0 to N+1
    // Index 0 for x=0, Index N+1 for x=N+1. These are termination states.
    // Actual values for x are 1 to N.
    dp_x.resize(N + 2);
    dp_y.resize(N + 2);
    visited.resize(N + 2, 0);

    // Pre-fill termination states
    dp_x[0] = 0; dp_y[0] = 0; visited[0] = 2;
    dp_x[N+1] = N+1; dp_y[N+1] = 0; visited[N+1] = 2;

    for (int i = 1; i < N; ++i) { // i represents the value of a_1
        // Reset visited for each run if not using memoization across runs.
        // But here, we are using memoization for the *subproblems* (solve(x))
        // which are independent of the initial a_1.
        // The only thing that changes is the value of a_1 itself.
        // The `solve` function takes `current_x_idx` as an argument.
        // When `current_x_idx == 1`, it uses `i` as `a_1`.
        // For `current_x_idx > 1`, it uses `a_values[current_x_idx - 2]`.
        // So, we need to pass `i` into the `solve` function or make `a_1` a global variable.
        // Let's modify `solve` to take `a_1_val` as an argument.

        // The problem states: "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This means a_1 is set to `i` for each run.
        // The `solve` function needs to know the current `a_1` value.
        // The `a_values` vector stores a_2 to a_n.
        // When `current_x_idx == 1`, `val_a_x` should be `i`.
        // When `current_x_idx > 1`, `val_a_x` should be `a_values[current_x_idx - 2]`.

        // To handle this, we can temporarily set a_values[-1] or a global variable.
        // A cleaner way is to pass a lambda or a function pointer for `get_a_x`.
        // Or, since `a_1` is only used when `current_x_idx == 1`, we can make `solve`
        // a wrapper that calls a helper function.

        // Let's re-think the DP state. The DP state `dp_x[k]` and `dp_y[k]` should represent
        // the outcome if the program *reaches* state `x=k`.
        // The value of `a_1` only affects the very first step.
        // So, for each `i` (value of `a_1`), we perform the first step manually,
        // then call `solve` for the subsequent state.

        long long current_a1_val = i; // This is the value of a_1 for the current run

        // Initial state for this run: x=1, y=0
        long long x_curr = 1;
        long long y_curr = 0;

        // First operation: x = x + a_x, y = y + a_x
        // Here a_x is a_1, which is current_a1_val
        x_curr += current_a1_val;
        y_curr += current_a1_val;

        // Check termination after first operation
        if (x_curr <= 0 || x_curr > N) {
            std::cout << y_curr << "\n";
            continue; // Move to the next 'i'
        }

        // Second operation: x = x - a_x, y = y + a_x
        // Here a_x is a_1, which is current_a1_val
        x_curr -= current_a1_val;
        y_curr += current_a1_val;

        // Now, the program continues from (x_curr, y_curr) using the standard a_values.
        // We need to call `solve` for `x_curr`.
        // The `solve` function needs to be able to distinguish between `a_1` and `a_k` for `k > 1`.
        // The current `solve` function assumes `a_1` is 0 if `current_x_idx == 1`.
        // This is incorrect for the general case.

        // Let's modify `solve` to take `a_val_at_x` as an argument, or use a global `a_1_override`.
        // A simpler approach: The `solve` function should compute the outcome for `x=k` assuming `a_k` is used.
        // The special `a_1` value is only for the *initial* `x=1`.
        // After the first two steps, `x` is no longer `1`. So `a_x` will always be from `a_values`.

        // Let's re-implement `solve` to use `a_values` directly for `current_x_idx > 1`.
        // The `solve` function as written is correct for `current_x_idx > 1`.
        // For `current_x_idx == 1`, it uses `val_a_x = 0`, which is wrong.
        // The `solve` function should be called only for `x > 1` or `x <= 0` or `x > N`.
        // The initial `x=1` case is handled manually.

        // The `solve` function should be called for `x_curr`.
        // If `x_curr` is 1, it means we are back to `x=1`. This is a loop.
        // But the problem states `a_1` is `i` for *each run*.
        // So if `x_curr` becomes 1 again, `a_1` would be `i` again.
        // This means the `solve` function should be able to handle `a_1` being `i`.

        // This implies the DP state needs to be `dp[x][a_1_value]` which is too large.
        // The problem statement: "Suppose for each i (1 <= i <= n - 1) we run the program on the sequence i, a_2, a_3, ..., a_n."
        // This means `a_1` is `i` for the *entire duration* of that specific run.
        // So, `a_x` is `i` if `x=1`, and `a_values[x-2]` if `x > 1`.

        // Let's modify `solve` to take `a1_override` as an argument.
        // This `a1_override` will be used when `current_x_idx == 1`.

        // Redefine solve:
        // `solve(current_x_idx, a1_override)`
        // This will be called for each `i`.
        // The `dp` table and `visited` array must be reset for each `i`.
        // This makes it O(N^2) which is too slow (N=2e5).

        // The key insight must be that the `a_1` value only matters when `x=1`.
        // If `x` becomes `k > 1`, the subsequent steps are independent of `a_1`.
        // So, we can precompute `dp_x[k]` and `dp_y[k]` for `k > 1`.
        // And then for each `i`, we simulate the first step, then use the precomputed values.

        // Let's re-initialize `dp_x`, `dp_y`, `visited` for each `i`.
        // This is the O(N^2) approach.
        // N=2e5, N^2 = 4e10, too slow.

        // The problem must be solvable in O(N log N) or O(N).
        // The `solve` function as written is a DFS with memoization.
        // If `a_x` is fixed for `x > 1`, then `solve(k)` for `k > 1` can be computed once.
        // Let's compute `dp_x[k]` and `dp_y[k]` for `k = 2, ..., N`.
        // These values represent the final `x` and `y` if the program *starts* at `x=k` (with `y=0`).
        // And `a_k` is `a_values[k-2]`.

        // Reset visited for each run.
        std::fill(visited.begin(), visited.end(), 0);
        std::fill(dp_x.begin(), dp_x.end(), 0);
        std::fill(dp_y.begin(), dp_y.end(), 0);

        // Pre-fill termination states
        dp_x[0] = 0; dp_y[0] = 0; visited[0] = 2;
        dp_x[N+1] = N+1; dp_y[N+1] = 0; visited[N+1] = 2;

        // For each `i` (value of a_1):
        // Simulate the first two operations manually.
        // x_start = 1, y_start = 0
        // a_x = i
        // x_after_op1 = 1 + i
        // y_after_op1 = 0 + i
        // If x_after_op1 terminates, output y_after_op1.
        // x_after_op2 = x_after_op1 - i
        // y_after_op2 = y_after_op1 + i
        // If x_after_op2 terminates, output y_after_op2.
        // Else, call solve(x_after_op2, i)
        // The `solve` function needs to know `i` when `x=1`.

        // Let's make `get_a_val(idx, a1_override)` helper.
        auto get_a_val = [&](int idx, long long a1_override) {
            if (idx == 1) return a1_override;
            return a_values[idx - 2];
        };

        // The `solve` function needs to be able to use `get_a_val`.
        // This means `solve` needs `a1_override` as an argument.
        // If `solve` takes `a1_override`, then `dp_x` and `dp_y` would need to be 2D.
        // This is the core problem.

        // The only way to make it O(N) or O(N log N) is if the `solve` function
        // does not depend on `a1_override` for its memoization.
        // This means `solve(k)` must return the same result regardless of `a1_override`.
        // This is true if `k != 1`.
        // So, we can compute `dp_x[k]` and `dp_y[k]` for `k = 2, ..., N` once.
        // And then for each `i`, we simulate the first two steps.
        // If `x` becomes `1` again, it's a loop.
        // If `x` becomes `k > 1`, we use `dp_x[k]` and `dp_y[k]`.

        // Let's define `solve_for_k_gt_1(current_x_idx)`
        // This function computes `dp_x[current_x_idx]` and `dp_y[current_x_idx]` for `current_x_idx > 1`.
        // It uses `a_values[current_x_idx - 2]` for `a_x`.
        // It will be called for `k = 2, ..., N`.

        // `dp_x` and `dp_y` will store results for `x > 1`.
        // `visited` will also be for `x > 1`.
        // Indices 0 and N+1 are termination states.
        // Indices 2 to N are states where `a_x` is from `a_values`.

        // Function to solve for x > 1
        // Returns true if it terminates, false if it loops.
        // `current_x_idx` is 1-indexed.
        std::function<bool(int)> solve_for_k_gt_1 =
            [&](int current_x_idx) -> bool {
            if (current_x_idx <= 0 || current_x_idx > N) {
                dp_x[current_x_idx] = current_x_idx;
                dp_y[current_x_idx] = 0;
                return true;
            }

            if (visited[current_x_idx] == 2) {
                return dp_x[current_x_idx] != -1;
            }

            if (visited[current_x_idx] == 1) {
                dp_x[current_x_idx] = -1;
                dp_y[current_x_idx] = -1;
                return false;
            }

            visited[current_x_idx] = 1;

            long long val_a_x = a_values[current_x_idx - 2]; // For x > 1, a_x is from a_values

            // Step 1: x = x + a_x, y = y + a_x
            long long next_x1 = current_x_idx + val_a_x;
            long long current_y_accumulated = val_a_x;

            if (next_x1 <= 0 || next_x1 > N) {
                dp_x[current_x_idx] = next_x1;
                dp_y[current_x_idx] = current_y_accumulated;
                visited[current_x_idx] = 2;
                return true;
            }

            // Step 2: x = x - a_x, y = y + a_x
            long long next_x2 = next_x1 - val_a_x;
            current_y_accumulated += val_a_x;

            bool terminates_from_next_x2 = solve_for_k_gt_1(next_x2);

            if (terminates_from_next_x2) {
                dp_x[current_x_idx] = dp_x[next_x2];
                dp_y[current_x_idx] = current_y_accumulated + dp_y[next_x2];
            } else {
                dp_x[current_x_idx] = -1;
                dp_y[current_x_idx] = -1;
            }

            visited[current_x_idx] = 2;
            return terminates_from_next_x2;
        };

    // Precompute results for x = 2 to N
    for (int k = 2; k <= N; ++k) {
        if (visited[k] == 0) { // Only compute if not already visited
            solve_for_k_gt_1(k);
        }
    }

    // Now, for each i (value of a_1), simulate the first two steps and then use DP.
    for (int i = 1; i < N; ++i) {
        long long current_a1_val = i;

        long long x_curr = 1;
        long long y_curr = 0;

        // First operation: x = x + a_x, y = y + a_x
        // Here a_x is a_1, which is current_a1_val
