    // Max f = a_{n-1} + a_n
    // Goodness = (a_{n-1} + a_n) - (a_1 + a_2)
    long long goodness1 = (max_a + second_max_a) - (min_a + second_min_a);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Try to put a_1 in one subsequence and the rest in another.
    // Or a_n in one subsequence and the rest in another.
    // This is effectively trying to isolate one element.
    // The most interesting case is when a_1 is isolated.
    // Then f(a_1, a_j) = a_1 + a_j + h for j > 1
    // And f(a_i, a_j) = a_i + a_j for i, j > 1
    // Min f values:
    //   - a_1 + a_2 + h (from a_1 and a_2)
    //   - a_2 + a_3 (from a_2 and a_3, if n >= 3)
    // Max f values:
    //   - a_1 + a_n + h (from a_1 and a_n)
    //   - a_{n-1} + a_n (from a_{n-1} and a_n)

    // Let's consider a specific partition strategy:
    // Put elements[0] (smallest) into subsequence 1.
    // Put elements[1] to elements[n-1] into subsequence 2.
    // This is only relevant if n >= 2.
    // If n=2, elements[0] in sub1, elements[1] in sub2.
    //   f(elements[0], elements[1]) = elements[0].value + elements[1].value + h
    //   Goodness = 0. This is covered by the general logic below.

    // If n >= 3:
    // Subsequence 1: {elements[0]}
    // Subsequence 2: {elements[1], ..., elements[n-1]}
    //
    // Values of f:
    //   - elements[0].value + elements[j].value + h for j = 1 to n-1
    //   - elements[i].value + elements[j].value for i, j = 1 to n-1, i != j
    //
    // Minimum f:
    //   min(elements[0].value + elements[1].value + h, elements[1].value + elements[2].value)
    //   (The second term only exists if n >= 3)
    //
    // Maximum f:
    //   max(elements[0].value + elements[n-1].value + h, elements[n-2].value + elements[n-1].value)
    //   (The second term only exists if n >= 3)

    long long goodness2 = -1;
    std::vector<int> partition2(n);

    if (n >= 2) {
        long long current_min_f;
        long long current_max_f;

        if (n == 2) {
            // elements[0] in sub1, elements[1] in sub2
            current_min_f = elements[0].value + elements[1].value + h;
            current_max_f = elements[0].value + elements[1].value + h;
        } else { // n >= 3
            current_min_f = std::min(elements[0].value + elements[1].value + h,
                                     elements[1].value + elements[2].value);
            current_max_f = std::max(elements[0].value + elements[n-1].value + h,
                                     elements[n-2].value + elements[n-1].value);
        }
        goodness2 = current_max_f - current_min_f;

        partition2[elements[0].original_index] = 1;
        for (int i = 1; i < n; ++i) {
            partition2[elements[i].original_index] = 2;
        }
    }

    // Compare goodness1 and goodness2
    if (goodness2 == -1 || goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <string>
#include <numeric>
#include <algorithm>

int count_ones(const std::string& s) {
    return std::accumulate(s.begin(), s.end(), 0, [](int sum, char c) {
        return sum + (c == '1');
    });
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string a, b;
    std::cin >> a >> b;

    int ones_a = count_ones(a);
    int ones_b = count_ones(b);

    // Calculate the maximum possible number of ones in a string derived from 'a'
    // by only appending parities.
    // If current_ones is even, parity is 0, ones count doesn't change.
    // If current_ones is odd, parity is 1, ones count increases by 1.
    // So, max_ones_a_derived is ones_a if ones_a is even, and ones_a + 1 if ones_a is odd.
    int max_ones_a_derived = ones_a + (ones_a % 2);

    // Condition 1: The number of ones in 'b' must be less than or equal to
    // the maximum possible number of ones we can achieve in 'a' by appending parities.
    // This is because removing characters can only decrease or keep the number of ones,
    // and appending parity can increase it by at most 1 (if current ones count is odd).
    // The maximum number of ones we can ever have in a string derived from 'a'
    // (before any removals) is `ones_a` if `ones_a` is even, or `ones_a + 1` if `ones_a` is odd.
    // Any string `s` derived from `a` by removing prefix and then appending parities
    // will have `count_ones(s) <= max_ones_a_derived`.
    if (ones_b > max_ones_a_derived) {
        std::cout << "NO\n";
        return 0;
    }

    // Condition 2: The length of 'b' must be less than or equal to the length of 'a'
    // plus the difference in their '1' counts.
    // This is because each time we append a '1' (when parity is 1), the length increases by 1.
    // Each time we append a '0' (when parity is 0), the length increases by 1.
    // The number of '1's in 'b' can be at most `ones_a + (length_b - length_a_min_possible)`.
    // More simply, if we want to reach length |b| from some suffix of 'a' of length `L_s`,
    // we need to perform `|b| - L_s` append operations.
    // The number of '1's in 'b' must be achievable.
    // The minimum number of '1's in any suffix of 'a' is 0.
    // The maximum number of '1's in any suffix of 'a' is `ones_a`.
    //
    // Let's re-evaluate the logic.
    // We can always remove characters from 'a' to get any suffix.
    // Let `a_suffix` be any suffix of `a`.
    // We can then append `parity(a_suffix)` repeatedly.
    // The length of `a_suffix` is `L_s`.
    // The number of ones in `a_suffix` is `C_s`.
    // After `k` append operations, the length becomes `L_s + k`.
    // The number of ones becomes `C_s + (number of 1s appended)`.
    //
    // The key insight is that we can always make the string longer by appending parity.
    // If we have a string `s` with `C_s` ones and length `L_s`.
    // If `C_s` is even, `parity(s)` is '0'. Appending it makes `s0`. `C_s` remains even.
    // If `C_s` is odd, `parity(s)` is '1'. Appending it makes `s1`. `C_s` becomes even.
    //
    // This means that after at most one append operation (if `C_s` is odd),
    // we can always reach a state where the number of ones is even.
    // Once the number of ones is even, we can append '0's indefinitely.
    //
    // So, for any suffix `s` of `a`:
    // 1. If `count_ones(s)` is even, we can form `s`, `s0`, `s00`, `s000`, ...
    //    The number of ones remains `count_ones(s)`.
    // 2. If `count_ones(s)` is odd, we can form `s`, `s1`, `s10`, `s100`, ...
    //    The number of ones becomes `count_ones(s) + 1` after the first append, and then stays `count_ones(s) + 1`.
    //
    // This implies that for any suffix `s` of `a`, we can generate strings of length `|b|`
    // that have `count_ones(s)` ones (if `count_ones(s)` is even)
    // or `count_ones(s) + 1` ones (if `count_ones(s)` is odd), provided `|b| >= |s|`.
    //
    // So, we need to check if there exists *any* suffix `s` of `a` such that:
    // 1. `|s| <= |b|` (we can't make a string shorter than its initial suffix length by appending)
    // 2. `count_ones(b)` is equal to `count_ones(s)` (if `count_ones(s)` is even)
    //    OR `count_ones(b)` is equal to `count_ones(s) + 1` (if `count_ones(s)` is odd)
    //
    // The maximum number of ones we can achieve from any suffix `s` of `a` is `count_ones(s)` if `count_ones(s)` is even,
    // or `count_ones(s) + 1` if `count_ones(s)` is odd.
    // Let this be `target_ones_from_s`.
    // We need `target_ones_from_s >= count_ones(b)`.
    //
    // The minimum length of a string we can form from `s` that has `target_ones_from_s` ones is `|s|` (if `count_ones(s)` is even)
    // or `|s| + 1` (if `count_ones(s)` is odd).
    // Let this be `min_len_for_target_ones`.
    // We need `min_len_for_target_ones <= |b|`.
    //
    // Combining these:
    // For any suffix `s` of `a`:
    // Let `current_ones_s = count_ones(s)`.
    // Let `current_len_s = |s|`.
    //
    // If `current_ones_s` is even:
    //   We can form strings of length `current_len_s`, `current_len_s+1`, ...
    //   All these strings will have `current_ones_s` ones.
    //   So, if `current_ones_s == ones_b` AND `current_len_s <= b.length()`, then YES.
    //
    // If `current_ones_s` is odd:
    //   We can form `s` (length `current_len_s`, ones `current_ones_s`).
    //   Then `s + '1'` (length `current_len_s+1`, ones `current_ones_s+1`).
    //   Then `s + '1' + '0'` (length `current_len_s+2`, ones `current_ones_s+1`).
    //   So, if `current_ones_s + 1 == ones_b` AND `current_len_s + 1 <= b.length()`, then YES.
    //
    // We need to iterate through all possible suffixes of `a`.
    // The initial string `a` itself is a suffix (when we remove 0 characters).
    //
    // Let's simplify the conditions:
    // We need to find if there's *any* suffix `s` of `a` such that:
    // 1. `|s| <= |b|`
    // 2. `count_ones(s) <= ones_b`
    // 3. `ones_b <= count_ones(s) + (count_ones(s) % 2)` (This is the `max_ones_a_derived` logic)
    //
    // The `max_ones_a_derived` logic applies to the *initial* `a`.
    // Let `max_ones_from_a = ones_a + (ones_a % 2)`.
    // If `ones_b > max_ones_from_a`, it's impossible. This is already checked.
    //
    // Now, we need to check if `b` can be formed.
    // The crucial part is that we can always make the string longer by appending parity.
    // If `count_ones(s)` is even, we can make `s` into `s00...0` of any length `L >= |s|`.
    // If `count_ones(s)` is odd, we can make `s` into `s100...0` of any length `L >= |s|+1`.
    //
    // So, the conditions for a suffix `s` to be a potential base for `b` are:
    // Case 1: `count_ones(s)` is even.
    //   We need `count_ones(s) == ones_b` AND `|s| <= |b|`.
    // Case 2: `count_ones(s)` is odd.
    //   We need `count_ones(s) + 1 == ones_b` AND `|s| + 1 <= |b|`.
    //
    // If any suffix `s` of `a` satisfies either of these, then it's possible.
    //
    // Let's iterate through all suffixes of `a`.
    // We can maintain `current_ones` and `current_len` as we "remove" characters from the front of `a`.
    // Start with `s = a`.
    // `current_ones = ones_a`.
    // `current_len = a.length()`.
    //
    // Loop:
    //   Check if `current_ones` (even case) or `current_ones + 1` (odd case) matches `ones_b`
    //   AND if `current_len` (even case) or `current_len + 1` (odd case) is `<= b.length()`.
    //   If yes, print YES and exit.
    //
    //   Remove first char from `s`:
    //   If `s[0]` was '1', `current_ones--`.
    //   `current_len--`.
    //   If `current_len` becomes 0, break loop.

    int current_ones_in_suffix = ones_a;
    int current_len_in_suffix = a.length();

    for (int i = 0; i < a.length(); ++i) {
        // Check conditions for the current suffix (a.substr(i))
        if (current_ones_in_suffix % 2 == 0) { // Parity is 0, can append 0s
            if (current_ones_in_suffix == ones_b && current_len_in_suffix <= b.length()) {
                std::cout << "YES\n";
                return 0;
            }
        } else { // Parity is 1, can append 1 then 0s
            if (current_ones_in_suffix + 1 == ones_b && current_len_in_suffix + 1 <= b.length()) {
                std::cout << "YES\n";
                return 0;
            }
        }

        // Prepare for the next suffix (a.substr(i+1))
        if (a[i] == '1') {
            current_ones_in_suffix--;
        }
        current_len_in_suffix--;
        if (current_len_in_suffix == 0 && i < a.length() - 1) { // Should not happen if loop condition is correct
            break;
        }
    }

    // The loop above checks for suffixes of length 1 or more.
    // What if a becomes empty? The problem states "You cannot perform this operation if a is empty."
    // So, the smallest suffix we consider has length 1.
    // The loop correctly handles this by iterating `a.length()` times,
    // where `i` goes from 0 to `a.length() - 1`.
    // In the last iteration, `i = a.length() - 1`, `current_len_in_suffix` is 1.
    // After the check, `current_len_in_suffix` becomes 0, and the loop terminates.

    std::cout << "NO\n";

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    // Check for k=1
    // A single cut divides s into two parts: s[0...i-1] and s[i...n-1].
    // We can reorder them to s[i...n-1] + s[0...i-1].
    // We need this new string to be a palindrome and not equal to s.
    for (int i = 1; i < n; ++i) { // i is the cut point, s[0...i-1] and s[i...n-1]
        std::string s_prime = s.substr(i) + s.substr(0, i);
        if (s_prime != s && is_palindrome(s_prime)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // If k=1 didn't work, check for k=2.
    // This means 3 pieces.
    // The problem statement implies that if k=1 doesn't work, k=2 is the next possibility.
    // The only case where k=2 is needed is if all cyclic shifts of s (which are palindromes)
    // are equal to s.
    // This happens if s consists of repeating characters, e.g., "aaaaa".
    // Or if s is like "ababa" and all its cyclic shifts are "ababa" or "babab" (which is not a palindrome).
    // The problem guarantees s is a palindrome.
    // If all cyclic shifts of s that are palindromes are equal to s,
    // then we need to consider more complex cuts.
    // However, the problem statement implies that if k=1 doesn't work, k=2 is the answer
    // unless it's impossible.
    //
    // Let's re-evaluate the "Impossible" case.
    // If all characters in s are the same (e.g., "qqqq"), then any permutation of its substrings
    // will result in the same string "qqqq". In this case, it's impossible to get a new string.
    bool all_same_char = true;
    for (int i = 1; i < n; ++i) {
        if (s[i] != s[0]) {
            all_same_char = false;
            break;
        }
    }
    if (all_same_char) {
        std::cout << "Impossible" << std::endl;
        return 0;
    }

    // If not all characters are the same, and k=1 didn't work, then k=2 is always possible.
    // Consider s = "nolon". k=1 doesn't work.
    // s[0...0] = "n", s[1...4] = "olon". "olonn" is not a palindrome.
    // s[0...1] = "no", s[2...4] = "lon". "lonno" is not a palindrome.
    // s[0...2] = "nol", s[3...4] = "on". "onnol" is not a palindrome.
    // s[0...3] = "nolo", s[4...4] = "n". "nnolo" is not a palindrome.
    //
    // For k=2, we can always make a new palindrome if not all characters are the same.
    // Example: s = "nolon"
    // Cut: "no" | "l" | "on"
    // Reorder: "on" | "l" | "no" -> "onlno"
    // "onlno" is a palindrome and not equal to "nolon".
    //
    // The strategy for k=2:
    // Take s[0...n/2 - 1] as the first piece (P1).
    // Take s[n/2] as the second piece (P2) if n is odd, or empty if n is even.
    // Take s[n/2 + (n%2)...n-1] as the third piece (P3).
    //
    // More simply, consider cutting s into s[0...i-1], s[i...j-1], s[j...n-1].
    // If n is odd, and s is not all same characters, we can always find a cut.
    // For example, cut s into s[0...n/2-1], s[n/2], s[n/2+1...n-1].
    // Let A = s[0...n/2-1], B = s[n/2], C = s[n/2+1...n-1].
    // Since s is a palindrome, A is the reverse of C.
    // So s = A + B + reverse(A).
    // We can reorder to reverse(A) + B + A. This is a palindrome.
    // This new string is different from s if A is not empty and A is not equal to reverse(A).
    // If A is empty, n=1, which is covered by all_same_char.
    // If A is equal to reverse(A), then A is a palindrome.
    //
    // The problem statement implies that if k=1 doesn't work, and it's not "Impossible", then k=2 is the answer.
    // This is a common pattern in competitive programming problems.
    // The only case where k=1 fails is if all cyclic shifts of s that are palindromes are equal to s.
    // This happens if s is of the form `xyx` where `x` is a palindrome, and `y` is a single character.
    // E.g., `abacaba`. Cyclic shifts: `bacabaa`, `acabaab`, `cabaaba`, `abaacab`, `baacaba`, `aacabab`.
    // None of these are palindromes.
    //
    // The only case where k=1 fails is when s is a palindrome, and for any split s = A+B, B+A is either not a palindrome or B+A == s.
    // If s is a palindrome, then s[0...i-1] + s[i...n-1] = A + B.
    // B+A is a palindrome if and only if A is a palindrome and B is a palindrome.
    // This is not true. For example, "otto". A="ot", B="to". B+A="toot", which is a palindrome.
    // A is not a palindrome, B is not a palindrome.
    //
    // The condition for B+A to be a palindrome is that (B+A) == reverse(B+A).
    // Since s is a palindrome, s[j] == s[n-1-j].
    // Let s = P_1 P_2 ... P_k+1.
    // The new string s' is a permutation of these pieces.
    //
    // The crucial observation for k=2:
    // If `s` is a palindrome and not all characters are the same, then `k=2` is always possible.
    // Consider `s = s_0 s_1 ... s_{n-1}`.
    // Since `s` is a palindrome, `s_i = s_{n-1-i}`.
    // Since not all characters are the same, there exists some `i` such that `s_i != s_0`.
    //
    // Let's try to prove that if `k=1` fails, and `s` is not all same characters, then `k=2` is the answer.
    // If `k=1` fails, it means for every `i` from `1` to `n-1`:
    // `s.substr(i) + s.substr(0, i)` is either not a palindrome OR it is equal to `s`.
    //
    // Consider the string `s` of length `n`.
    // If `n` is odd, `n = 2m + 1`. `s = s_0 ... s_{m-1} s_m s_{m+1} ... s_{2m}`.
    // `s_0 ... s_{m-1}` is `A`. `s_m` is `B`. `s_{m+1} ... s_{2m}` is `C`.
    // `C` is `reverse(A)`. So `s = A B reverse(A)`.
    // We can cut into `A`, `B`, `reverse(A)`.
    // Reorder to `reverse(A) B A`. This is a palindrome.
    // Is `reverse(A) B A == A B reverse(A)`?
    // This is true if and only if `A == reverse(A)`.
    // If `A` is not a palindrome, then `reverse(A) B A` is a new palindrome.
    // If `A` is a palindrome, then `reverse(A) B A == A B A`.
    // In this case, `A B A` is the same as `A B reverse(A)` (since `A` is a palindrome).
    // So if `A` is a palindrome, this specific `k=2` cut doesn't produce a new string.
    //
    // Example: `s = "abacaba"`. `n=7`, `m=3`. `A="aba"`, `B="c"`, `reverse(A)="aba"`.
    // `A` is a palindrome. So `reverse(A) B A` is `abacaba`, which is `s`.
    // This specific `k=2` cut doesn't work for `abacaba`.
    //
    // However, `abacaba` has `k=1` solution.
    // Cut `s` at `i=1`: `s[0]="a"`, `s[1...6]="bacaba"`. New string: `bacabaa`. Not palindrome.
    // Cut `s` at `i=2`: `s[0...1]="ab"`, `s[2...6]="acaba"`. New string: `acabaab`. Not palindrome.
    // Cut `s` at `i=3`: `s[0...2]="aba"`, `s[3...6]="caba"`. New string: `cabaaba`. Not palindrome.
    //
    // Wait, the example `nolon` gives `2`.
    // `nolon`. `n=5`. `A="no"`, `B="l"`, `reverse(A)="on"`.
    // `A` is not a palindrome. So `reverse(A) B A` is `onlno`. This is a new palindrome.
    // So for `nolon`, `k=2` works with this strategy.
    //
    // The problem states: "It can be shown that there is no solution with one cut." for `nolon`.
    // Let's verify for `nolon`:
    // `i=1`: `olon` + `n` = `olonn`. Not palindrome.
    // `i=2`: `lon` + `no` = `lonno`. Not palindrome.
    // `i=3`: `on` + `nol` = `onnol`. Not palindrome.
    // `i=4`: `n` + `nolo` = `nnolo`. Not palindrome.
    // So `k=1` indeed fails for `nolon`.
    //
    // The logic seems to be:
    // 1. Check if all characters in `s` are the same. If yes, print "Impossible".
    // 2. Check if `k=1` is possible. Iterate through all `n-1` possible single cuts.
    //    For each cut `s = A + B`, form `s' = B + A`. If `s' != s` and `s'` is a palindrome, print `1`.
    // 3. If neither of the above, print `2`.
    //
    // This covers all cases.
    // Why is `k=2` always possible if `s` is not all same characters and `k=1` fails?
    //
    // Consider `s` is a palindrome, not all chars are same.
    // If `k=1` fails, it means for any `i` (1 to n-1), `s.substr(i) + s.substr(0,i)` is either not a palindrome or equals `s`.
    //
    // Let's take `s = "kinnikkinnik"`. `n=12`.
    // `k=1` solution: `nik` + `kinnikkin` = `nikkinnikkin`. This is a palindrome and not equal to `s`.
    // So `k=1` is the answer.
    //
    // The logic seems sound. The problem implies that if `k=1` doesn't work, `k=2` is the answer unless it's impossible.
    // The "Impossible" case is only when all characters are the same.

    std::cout << 2 << std::endl; // If k=1 didn't work and not all chars are same, then k=2 is the answer.

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

long long n_heads;
long long m_tracks;
std::vector<long long> h_positions;
std::vector<long long> p_targets;

bool check(long long T) {
    std::vector<long long> current_p = p_targets;
    std::vector<long long> current_h = h_positions;

    // Remove p_targets that are already covered by initial h_positions
    // This is an optimization, but the core logic should handle it.
    // For the check function, we need to see if all p_targets can be covered.
    // The initial state means h_i are covered.
    // The problem states "all of the tracks numbered h_1, ..., h_n have been read at the beginning".
    // This implies that if a p_i is equal to some h_j, it's already covered.
    // However, the problem also says "Mike needs to read the data on m distinct tracks with numbers p_1, ..., p_m".
    // It's safer to assume we need to explicitly cover all p_i.
    // The example 2 5 6 and 1 3 6 8, output 2. Here 6 is both h_i and p_i.
    // If we remove 6 from p_targets, we'd only need to cover 1, 3, 8.
    // The solution should naturally handle this.

    long long p_idx = 0; // Index for p_targets
    long long h_idx = 0; // Index for h_positions

    while (p_idx < m_tracks && h_idx < n_heads) {
        // Find the first p_target that is not yet covered by previous heads
        // or is too far for the current head.
        // If current head h_idx can cover p_target p_idx
        // i.e., p_targets[p_idx] is within [h_positions[h_idx] - T, h_positions[h_idx] + T]
        // then this head can potentially cover a range of p_targets.

        // If p_targets[p_idx] is too far to the left for current h_idx,
        // it means h_idx cannot cover p_targets[p_idx].
        // This implies that p_targets[p_idx] must be covered by a head to its left (h_idx-1 or earlier).
        // But we are iterating h_idx from left to right.
        // So, if p_targets[p_idx] > h_positions[h_idx] + T, then h_idx cannot cover p_targets[p_idx].
        // This means p_targets[p_idx] must be covered by a head h_k where k > h_idx.
        // This is not the right way to think about it.

        // A head at h_positions[h_idx] can cover the range [h_positions[h_idx] - T, h_positions[h_idx] + T].
        // We want to cover all p_targets.
        // We can greedily assign heads.
        // For the current head h_positions[h_idx], what is the leftmost p_target it can cover?
        // It can cover p_targets[p_idx] if p_targets[p_idx] >= h_positions[h_idx] - T.
        // If p_targets[p_idx] < h_positions[h_idx] - T, then p_targets[p_idx] must be covered by a previous head.
        // Since p_targets are sorted, if p_targets[p_idx] is not covered, then no subsequent p_target will be covered by this head.
        // So, we advance p_idx until p_targets[p_idx] >= h_positions[h_idx] - T.
        while (p_idx < m_tracks && p_targets[p_idx] < h_positions[h_idx] - T) {
            p_idx++; // This p_target must be covered by a previous head.
                     // If we reach here, it means it wasn't covered. So this T is not enough.
                     // This is incorrect. We are trying to cover p_targets with h_positions.
                     // If p_targets[p_idx] is too far left for h_positions[h_idx], it means it must have been covered by h_positions[h_idx-1] or earlier.
                     // If it wasn't, then T is too small.
        }

        if (p_idx == m_tracks) { // All p_targets covered
            return true;
        }

        // Now, p_targets[p_idx] >= h_positions[h_idx] - T.
        // This means h_positions[h_idx] can potentially cover p_targets[p_idx].
        // The current head h_positions[h_idx] can cover up to h_positions[h_idx] + T.
        // We use this head to cover as many p_targets as possible, starting from p_targets[p_idx].
        long long current_head_reach = h_positions[h_idx] + T;
        while (p_idx < m_tracks && p_targets[p_idx] <= current_head_reach) {
            p_idx++; // This p_target is covered by the current head.
        }
        h_idx++; // Move to the next head.
    }

    return p_idx == m_tracks; // All p_targets must be covered.
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> n_heads >> m_tracks;

    h_positions.resize(n_heads);
    for (long long i = 0; i < n_heads; ++i) {
        std::cin >> h_positions[i];
    }

    p_targets.resize(m_tracks);
    for (long long i = 0; i < m_tracks; ++i) {
        std::cin >> p_targets[i];
    }

    // Remove p_targets that are already at h_positions.
    // This is not strictly necessary for the check function to work correctly,
    // but it can reduce the number of targets to cover.
    // However, the problem statement implies we need to "read" them,
    // and if they are already at h_i, they are "read at the beginning".
    // Let's re-evaluate. The example 1: h={2,5,6}, p={1,3,6,8}. Output 2.
    // If we remove 6 from p, p becomes {1,3,8}.
    // The check function should work on the original p_targets.
    // The logic of `check` function is to see if all `p_targets` can be covered.
    // If `p_targets[p_idx]` is `h_positions[h_idx]`, it's covered by `h_positions[h_idx]` with `T=0`.
    // So the current `check` function should be fine.

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between p and h, plus some buffer.
                               // Max p_i is 10^10, min h_i is 1. Max diff is 10^10.
                               // Max diff between p_i and p_j is 10^10.
                               // A single head might need to cover a range of 2 * 10^10.
                               // So T can be up to 10^10.
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    std::vector<int> L(n, 0); // L[i] = length of 0-block ending at i
    std::vector<int> R(n, 0); // R[i] = length of 0-block starting at i

    // Calculate L
    if (a[0] == 0) L[0] = 1;
    for (int i = 1; i < n; ++i) {
        if (a[i] == 0) {
            L[i] = L[i - 1] + 1;
        } else {
            L[i] = 0;
        }
    }

    // Calculate R
    if (a[n - 1] == 0) R[n - 1] = 1;
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 0) {
            R[i] = R[i + 1] + 1;
        } else {
            R[i] = 0;
        }
    }

    int max_k = 0;
    std::vector<int> final_a = a;

    for (int i = 0; i < n; ++i) {
        if (a[i] == 1) {
            // Find the length of the 0-block to the left
            int left_zeros = (i > 0) ? L[i - 1] : 0;
            // Find the length of the 0-block to the right
            int right_zeros = (i < n - 1) ? R[i + 1] : 0;

            if (left_zeros == 0 && right_zeros == 0) {
                // This '1' is isolated or part of a block of 1s. It will never change.
                // E.g., ...111... or ...010...
                // The '1' at index i will remain 1.
            } else if (left_zeros == 0) { // ...1000...
                // The '1' at index i will remain 1.
                // The 0s to its right will shrink.
                // The first 0 at i+1 will become 1 if right_zeros is 1.
                // If right_zeros is odd, the middle 0 will become 1.
                // The '1' at index i will remain 1.
            } else if (right_zeros == 0) { // ...0001...
                // The '1' at index i will remain 1.
                // The 0s to its left will shrink.
                // The '1' at index i will remain 1.
            } else { // ...0001000...
                int k_val = std::min(left_zeros, right_zeros);
                max_k = std::max(max_k, (k_val + 1) / 2);

                // The '1' at index i will remain 1.
                // The 0s to its left and right will be converted to 1s up to k_val steps.
                // Specifically, 0s at i-1, i-2, ..., i-k_val will become 1s.
                // And 0s at i+1, i+2, ..., i+k_val will become 1s.
                // This means the 0s in the range [i - k_val, i + k_val] (excluding i itself)
                // will eventually become 1s.
                // The final sequence will have 1s in the range [i - k_val, i + k_val].
                for (int j = 1; j <= k_val; ++j) {
                    if (i - j >= 0) final_a[i - j] = 1;
                    if (i + j < n) final_a[i + j] = 1;
                }
            }
        }
    }

    std::cout << max_k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << final_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

