    long long good_pairs_count = 0;
    for (int r = 0; r < n; ++r) {
        good_pairs_count += min_l_for_bad_substring[r];
    }

    bad_pairs = total_pairs - good_pairs_count;

    std::cout << bad_pairs << std::endl;

